@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  html { font-family: 'Inter', system-ui, sans-serif; }
  body { @apply bg-gray-50 text-gray-900; }
}

@layer components {
  .btn-primary { @apply bg-rose-600 hover:bg-rose-700 text-white font-semibold py-2 px-4 rounded-lg transition-colors duration-200 disabled:opacity-50 disabled:cursor-not-allowed; }
  .btn-secondary { @apply bg-white hover:bg-gray-50 text-gray-700 font-semibold py-2 px-4 rounded-lg border border-gray-300 transition-colors duration-200; }
  .btn-danger { @apply bg-red-600 hover:bg-red-700 text-white font-semibold py-2 px-4 rounded-lg transition-colors duration-200; }
  .btn-success { @apply bg-emerald-600 hover:bg-emerald-700 text-white font-semibold py-2 px-4 rounded-lg transition-colors duration-200; }
  .card { @apply bg-white rounded-2xl shadow-sm border border-gray-100 p-6; }
  .input { @apply w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-rose-500 focus:border-transparent; }
  .label { @apply block text-sm font-medium text-gray-700 mb-1; }
  .badge { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium; }
}

@tailwind base;
@tailwind components;
@tailwind utilities;

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap');

@layer base {
  html {
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
    -webkit-font-smoothing: antialiased;
  }
  body {
    @apply bg-stone-50 text-stone-900;
  }
  * {
    @apply box-border;
  }
}

@layer components {
  /* ── Buttons ── */
  .btn-primary {
    @apply inline-flex items-center justify-center gap-2 bg-rose-600 hover:bg-rose-700 active:bg-rose-800
           text-white font-semibold py-2.5 px-5 rounded-xl transition-all duration-150
           disabled:opacity-50 disabled:cursor-not-allowed shadow-sm hover:shadow-rose-200/60 hover:shadow-md;
  }
  .btn-secondary {
    @apply inline-flex items-center justify-center gap-2 bg-white hover:bg-stone-50 active:bg-stone-100
           text-stone-700 font-medium py-2.5 px-5 rounded-xl border border-stone-200
           transition-all duration-150 shadow-sm;
  }
  .btn-ghost {
    @apply inline-flex items-center justify-center gap-2 hover:bg-stone-100 active:bg-stone-200
           text-stone-600 font-medium py-2 px-3 rounded-lg transition-all duration-150;
  }
  .btn-danger {
    @apply inline-flex items-center justify-center gap-2 bg-red-600 hover:bg-red-700
           text-white font-semibold py-2.5 px-5 rounded-xl transition-all duration-150 shadow-sm;
  }
  .btn-success {
    @apply inline-flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700
           text-white font-semibold py-2.5 px-5 rounded-xl transition-all duration-150 shadow-sm;
  }

  /* ── Cards ── */
  .card {
    @apply bg-white rounded-2xl border border-stone-100 p-6 shadow-sm;
  }
  .card-hover {
    @apply card cursor-pointer hover:shadow-md hover:border-stone-200 transition-all duration-200;
  }
  .card-glass {
    @apply bg-white/80 backdrop-blur-sm rounded-2xl border border-white/60 p-6 shadow-md;
  }

  /* ── Forms ── */
  .input {
    @apply w-full rounded-xl border border-stone-200 bg-white px-4 py-2.5 text-sm text-stone-900
           placeholder:text-stone-400 focus:outline-none focus:ring-2 focus:ring-rose-500/20
           focus:border-rose-400 transition-all duration-150;
  }
  .label {
    @apply block text-sm font-medium text-stone-600 mb-1.5;
  }

  /* ── Badges ── */
  .badge {
    @apply inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-semibold;
  }

  /* ── Status dots ── */
  .status-dot {
    @apply inline-block w-2 h-2 rounded-full;
  }

  /* ── Section headers ── */
  .section-title {
    @apply text-lg font-bold text-stone-900;
  }
  .section-subtitle {
    @apply text-sm text-stone-500 mt-0.5;
  }

  /* ── Timeline ── */
  .timeline-line {
    @apply absolute left-6 top-0 bottom-0 w-px bg-gradient-to-b from-rose-200 via-rose-100 to-transparent;
  }
  .timeline-dot {
    @apply w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-sm flex-none;
  }

  /* ── Allergen badges ── */
  .badge-allergen {
    @apply inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-semibold border;
  }
}

@layer utilities {
  .scrollbar-thin {
    scrollbar-width: thin;
    scrollbar-color: #d1cdc7 transparent;
  }
  .scrollbar-thin::-webkit-scrollbar {
    width: 4px;
  }
  .scrollbar-thin::-webkit-scrollbar-track {
    background: transparent;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb {
    background: #d1cdc7;
    border-radius: 4px;
  }
  .text-gradient {
    @apply bg-gradient-to-r from-rose-600 to-pink-600 bg-clip-text text-transparent;
  }
}

import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import PrivateRoute from './components/PrivateRoute';

import Login from './pages/Login';
import Dashboard from './pages/admin/Dashboard';
import EventList from './pages/admin/EventList';
import CreateEvent from './pages/admin/CreateEvent';
import EventDetail from './pages/admin/EventDetail';
import KitchenView from './pages/admin/KitchenView';
import DjView from './pages/admin/DjView';
import FloorView from './pages/admin/FloorView';
import UserManagement from './pages/admin/UserManagement';
import JobPositions from './pages/admin/JobPositions';
import CalendarView from './pages/admin/CalendarView';
import AutomationSettings from './pages/admin/AutomationSettings';
import ClientPortal from './pages/client/ClientPortal';

function HomeRedirect() {
  const { user, hasAnyPermission } = useAuth();
  if (!user) return <Navigate to="/login" replace />;
  if (user.role === 'CLIENT')  return <Navigate to="/mi-evento" replace />;
  if (user.role === 'OFFICE')  return <Navigate to="/admin/dashboard" replace />;
  if (user.role === 'KITCHEN') return <Navigate to="/admin/cocina" replace />;
  if (user.role === 'DJ')      return <Navigate to="/admin/dj" replace />;
  if (user.role === 'FLOOR')   return <Navigate to="/admin/sala" replace />;
  // Roles personalizados: redirigir según permisos
  if (hasAnyPermission('DASHBOARD_VIEW')) return <Navigate to="/admin/dashboard" replace />;
  if (hasAnyPermission('PROTOCOL_VIEW'))  return <Navigate to="/admin/dj" replace />;
  if (hasAnyPermission('TABLES_VIEW'))    return <Navigate to="/admin/sala" replace />;
  if (hasAnyPermission('ALLERGENS_VIEW', 'MENUS_VIEW')) return <Navigate to="/admin/cocina" replace />;
  return <Navigate to="/no-autorizado" replace />;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Toaster position="top-right" toastOptions={{
          duration: 3000,
          style: { borderRadius: '12px', fontSize: '14px', fontWeight: 500 }
        }} />
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/" element={<HomeRedirect />} />

          {/* Rutas de administración — solo OFFICE */}
          <Route path="/admin/dashboard" element={
            <PrivateRoute roles={['OFFICE']}><Dashboard /></PrivateRoute>
          } />
          <Route path="/admin/eventos" element={
            <PrivateRoute roles={['OFFICE']}><EventList /></PrivateRoute>
          } />
          <Route path="/admin/eventos/nuevo" element={
            <PrivateRoute roles={['OFFICE']}><CreateEvent /></PrivateRoute>
          } />
          <Route path="/admin/eventos/:id" element={
            <PrivateRoute roles={['OFFICE']}><EventDetail /></PrivateRoute>
          } />
          <Route path="/admin/usuarios" element={
            <PrivateRoute roles={['OFFICE']}><UserManagement /></PrivateRoute>
          } />
          <Route path="/admin/puestos" element={
            <PrivateRoute roles={['OFFICE']}><JobPositions /></PrivateRoute>
          } />
          <Route path="/admin/calendario" element={
            <PrivateRoute roles={['OFFICE']}><CalendarView /></PrivateRoute>
          } />
          <Route path="/admin/automatizaciones" element={
            <PrivateRoute roles={['OFFICE']}><AutomationSettings /></PrivateRoute>
          } />

          {/* Vistas de staff — rol fijo O permiso equivalente */}
          <Route path="/admin/cocina" element={
            <PrivateRoute roles={['OFFICE','KITCHEN']} anyPermission={['ALLERGENS_VIEW','MENUS_VIEW']}>
              <KitchenView />
            </PrivateRoute>
          } />
          <Route path="/admin/dj" element={
            <PrivateRoute roles={['OFFICE','DJ']} anyPermission={['PROTOCOL_VIEW']}>
              <DjView />
            </PrivateRoute>
          } />
          <Route path="/admin/sala" element={
            <PrivateRoute roles={['OFFICE','FLOOR']} anyPermission={['TABLES_VIEW','GUESTS_VIEW']}>
              <FloorView />
            </PrivateRoute>
          } />

          {/* Portal del cliente */}
          <Route path="/mi-evento" element={
            <PrivateRoute roles={['CLIENT']}><ClientPortal /></PrivateRoute>
          } />

          <Route path="/no-autorizado" element={
            <div className="min-h-screen flex items-center justify-center bg-stone-50">
              <div className="text-center card p-12">
                <p className="text-5xl mb-4"></p>
                <h1 className="text-2xl font-bold text-stone-900 mb-2">Acceso no autorizado</h1>
                <p className="text-stone-500 mb-6">No tienes permiso para ver esta página.</p>
                <a href="/login" className="btn-primary">Volver al inicio</a>
              </div>
            </div>
          } />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import PrivateRoute from './components/PrivateRoute';

import Login from './pages/Login';
import Dashboard from './pages/admin/Dashboard';
import EventList from './pages/admin/EventList';
import CreateEvent from './pages/admin/CreateEvent';
import EventDetail from './pages/admin/EventDetail';
import KitchenView from './pages/admin/KitchenView';
import DjView from './pages/admin/DjView';
import FloorView from './pages/admin/FloorView';
import UserManagement from './pages/admin/UserManagement';
import JobPositions from './pages/admin/JobPositions';
import CalendarView from './pages/admin/CalendarView';
import AutomationSettings from './pages/admin/AutomationSettings';
import ClientPortal from './pages/client/ClientPortal';

/**
 * Redirige al usuario a la primera sección que tiene permitida.
 * Orden de prioridad: Dashboard → Sala → Protocolo → Cocina → no-autorizado
 */
function HomeRedirect() {
  const { user, hasPermission, hasAnyPermission } = useAuth();
  if (!user) return <Navigate to="/login" replace />;

  // Roles con destino fijo
  if (user.role === 'CLIENT')  return <Navigate to="/mi-evento"        replace />;
  if (user.role === 'OFFICE')  return <Navigate to="/admin/dashboard"  replace />;

  // Todos los demás: navegar a la primera sección habilitada por permisos
  if (hasPermission('DASHBOARD_VIEW'))                              return <Navigate to="/admin/dashboard" replace />;
  if (hasPermission('TABLES_VIEW'))                                 return <Navigate to="/admin/sala"      replace />;
  if (hasPermission('PROTOCOL_VIEW'))                               return <Navigate to="/admin/dj"        replace />;
  if (hasAnyPermission('ALLERGENS_VIEW', 'MENUS_VIEW'))            return <Navigate to="/admin/cocina"    replace />;

  return <Navigate to="/no-autorizado" replace />;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Toaster position="top-right" toastOptions={{
          duration: 3000,
          style: { borderRadius: '12px', fontSize: '14px', fontWeight: 500 }
        }} />
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/" element={<HomeRedirect />} />

          {/* ── Dashboard
              Accesible para OFFICE (siempre) O cualquier usuario con DASHBOARD_VIEW */}
          <Route path="/admin/dashboard" element={
            <PrivateRoute roles={['OFFICE']} anyPermission={['DASHBOARD_VIEW']}>
              <Dashboard />
            </PrivateRoute>
          } />

          {/* ── Rutas exclusivas de OFFICE ─────────────────────────────────── */}
          <Route path="/admin/eventos" element={
            <PrivateRoute roles={['OFFICE']}><EventList /></PrivateRoute>
          } />
          <Route path="/admin/eventos/nuevo" element={
            <PrivateRoute roles={['OFFICE']}><CreateEvent /></PrivateRoute>
          } />
          <Route path="/admin/eventos/:id" element={
            <PrivateRoute roles={['OFFICE']}><EventDetail /></PrivateRoute>
          } />
          <Route path="/admin/usuarios" element={
            <PrivateRoute roles={['OFFICE']}><UserManagement /></PrivateRoute>
          } />
          <Route path="/admin/puestos" element={
            <PrivateRoute roles={['OFFICE']}><JobPositions /></PrivateRoute>
          } />
          <Route path="/admin/calendario" element={
            <PrivateRoute roles={['OFFICE']}><CalendarView /></PrivateRoute>
          } />
          <Route path="/admin/automatizaciones" element={
            <PrivateRoute roles={['OFFICE']}><AutomationSettings /></PrivateRoute>
          } />

          {/* ── Vistas de staff — acceso por ROL o por PERMISO ─────────────────
              anyPermission permite que cualquier usuario con el permiso adecuado
              acceda aunque su rol no sea el "nativo" de la vista.
              Los roles legacy (KITCHEN, DJ, FLOOR) siguen funcionando como antes. */}

          {/* Vista Cocina: requiere ver menús O ver alérgenos */}
          <Route path="/admin/cocina" element={
            <PrivateRoute roles={['OFFICE', 'KITCHEN']} anyPermission={['ALLERGENS_VIEW', 'MENUS_VIEW']}>
              <KitchenView />
            </PrivateRoute>
          } />

          {/* Vista DJ / Protocolo: requiere ver protocolo */}
          <Route path="/admin/dj" element={
            <PrivateRoute roles={['OFFICE', 'DJ']} anyPermission={['PROTOCOL_VIEW']}>
              <DjView />
            </PrivateRoute>
          } />

          {/* Vista Sala / Mesas: requiere ver mesas
              (TABLES_VIEW incluye acceso a la vista completa; FloorView
               gestiona internamente qué pestañas mostrar por permiso) */}
          <Route path="/admin/sala" element={
            <PrivateRoute roles={['OFFICE', 'FLOOR']} anyPermission={['TABLES_VIEW']}>
              <FloorView />
            </PrivateRoute>
          } />

          {/* Portal del cliente */}
          <Route path="/mi-evento" element={
            <PrivateRoute roles={['CLIENT']}><ClientPortal /></PrivateRoute>
          } />

          <Route path="/no-autorizado" element={
            <div className="min-h-screen flex items-center justify-center bg-stone-50">
              <div className="text-center card p-12">
                <p className="text-5xl mb-4"></p>
                <h1 className="text-2xl font-bold text-stone-900 mb-2">Acceso no autorizado</h1>
                <p className="text-stone-500 mb-6">No tienes permiso para ver esta página.</p>
                <a href="/login" className="btn-primary">Volver al inicio</a>
              </div>
            </div>
          } />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

import { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  LayoutDashboard, Calendar, Users, Music2, ChefHat, Layers,
  LogOut, Menu, X, ChevronRight, Sparkles, CalendarDays, Bell, Briefcase
} from 'lucide-react';

const navByRole = {
  OFFICE: [
    { to: '/admin/dashboard',       label: 'Dashboard',       icon: LayoutDashboard },
    { to: '/admin/eventos',         label: 'Eventos',         icon: Calendar },
    { to: '/admin/calendario',      label: 'Calendario',      icon: CalendarDays },
    { to: '/admin/usuarios',        label: 'Personal',        icon: Users },
    { to: '/admin/puestos',         label: 'Puestos',         icon: Briefcase },
    { to: '/admin/automatizaciones',label: 'Automatizaciones',icon: Bell },
  ],
  KITCHEN: [{ to: '/admin/cocina', label: 'Mi Evento', icon: ChefHat }],
  DJ:      [{ to: '/admin/dj',     label: 'Mi Evento', icon: Music2 }],
  FLOOR:   [{ to: '/admin/sala',   label: 'Mi Evento', icon: Layers }],
  CLIENT:  [{ to: '/mi-evento',    label: 'Mi Evento', icon: Calendar }],
};

const roleConfig = {
  OFFICE:  { label: 'Administración', color: 'bg-violet-100 text-violet-700', dot: 'bg-violet-500' },
  KITCHEN: { label: 'Cocina',         color: 'bg-orange-100 text-orange-700', dot: 'bg-orange-500' },
  DJ:      { label: 'DJ',             color: 'bg-blue-100 text-blue-700',     dot: 'bg-blue-500'   },
  FLOOR:   { label: 'Sala / Metres',  color: 'bg-emerald-100 text-emerald-700', dot: 'bg-emerald-500' },
  CLIENT:  { label: 'Cliente',        color: 'bg-rose-100 text-rose-700',     dot: 'bg-rose-500'   },
};

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  const links = navByRole[user?.role] || [];
  const rc = roleConfig[user?.role] || {};

  const handleLogout = () => { logout(); navigate('/login'); };

  const NavLinks = () => (
    <nav className="flex-1 px-3 py-4 space-y-1">
      {links.map(link => {
        const Icon = link.icon;
        const active = location.pathname.startsWith(link.to);
        return (
          <Link key={link.to} to={link.to}
            onClick={() => setMobileOpen(false)}
            className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-150 group ${
              active
                ? 'bg-rose-50 text-rose-700 shadow-sm'
                : 'text-stone-600 hover:bg-stone-100 hover:text-stone-900'
            }`}>
            <Icon size={18} className={active ? 'text-rose-600' : 'text-stone-400 group-hover:text-stone-600'} />
            {link.label}
            {active && <ChevronRight size={14} className="ml-auto text-rose-400" />}
          </Link>
        );
      })}
    </nav>
  );

  const SidebarContent = () => (
    <div className="flex flex-col h-full">
      {/* Logo */}
      <div className="px-4 py-5 border-b border-stone-100">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-gradient-to-br from-rose-500 to-pink-600 rounded-xl flex items-center justify-center shadow-sm">
            <Sparkles size={18} className="text-white" />
          </div>
          <div>
            <p className="font-bold text-stone-900 text-sm leading-none">Agora Celebraciones</p>
            <p className="text-xs text-stone-400 mt-0.5">Gestión Premium</p>
          </div>
        </div>
      </div>

      <NavLinks />

      {/* User footer */}
      <div className="px-3 pb-4 border-t border-stone-100 pt-3">
        <div className="flex items-center gap-3 px-3 py-2.5 rounded-xl bg-stone-50">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-stone-200 to-stone-300 flex items-center justify-center flex-none">
            <span className="text-xs font-bold text-stone-600">
              {(user?.nombre || user?.username || '?')[0].toUpperCase()}
            </span>
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-stone-900 truncate">{user?.nombre || user?.username}</p>
            <span className={`badge ${rc.color} text-[10px] mt-0.5`}>{rc.label}</span>
          </div>
          <button onClick={handleLogout} className="text-stone-400 hover:text-rose-600 transition-colors p-1 rounded-lg hover:bg-rose-50" title="Cerrar sesión">
            <LogOut size={15} />
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <>
      {/* Desktop sidebar */}
      <aside className="hidden lg:flex flex-col fixed inset-y-0 left-0 w-60 bg-white border-r border-stone-100 z-30 shadow-sm">
        <SidebarContent />
      </aside>

      {/* Mobile top bar */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-40 bg-white border-b border-stone-100 h-14 flex items-center px-4 gap-3 shadow-sm">
        <button onClick={() => setMobileOpen(true)} className="p-2 rounded-lg hover:bg-stone-100 transition-colors">
          <Menu size={20} className="text-stone-600" />
        </button>
        <div className="flex items-center gap-2 flex-1">
          <div className="w-7 h-7 bg-gradient-to-br from-rose-500 to-pink-600 rounded-lg flex items-center justify-center">
            <Sparkles size={14} className="text-white" />
          </div>
          <span className="font-bold text-stone-900 text-sm">Salon Eventos</span>
        </div>
        <span className={`badge ${rc.color} text-[10px]`}>{rc.label}</span>
      </div>

      {/* Mobile drawer */}
      {mobileOpen && (
        <div className="lg:hidden fixed inset-0 z-50 flex">
          <div className="absolute inset-0 bg-black/40" onClick={() => setMobileOpen(false)} />
          <aside className="relative w-72 bg-white h-full flex flex-col shadow-2xl">
            <div className="flex items-center justify-between px-4 py-4 border-b border-stone-100">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-gradient-to-br from-rose-500 to-pink-600 rounded-xl flex items-center justify-center">
                  <Sparkles size={16} className="text-white" />
                </div>
                <span className="font-bold text-stone-900">Salon Eventos</span>
              </div>
              <button onClick={() => setMobileOpen(false)} className="p-2 rounded-lg hover:bg-stone-100">
                <X size={18} className="text-stone-500" />
              </button>
            </div>
            <SidebarContent />
          </aside>
        </div>
      )}
    </>
  );
}

import { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  LayoutDashboard, Calendar, Users, Music2, ChefHat, Layers,
  LogOut, Menu, X, ChevronRight, Sparkles, CalendarDays, Bell, Briefcase,
} from 'lucide-react';
import logoApp from '../assets/logoApp.png';

// ── Menú fijo para OFFICE ────────────────────────────────────────────────────
const OFFICE_NAV = [
  { to: '/admin/dashboard',        label: 'Dashboard',        icon: LayoutDashboard },
  { to: '/admin/eventos',          label: 'Eventos',          icon: Calendar        },
  { to: '/admin/calendario',       label: 'Calendario',       icon: CalendarDays    },
  { to: '/admin/usuarios',         label: 'Personal',         icon: Users           },
  { to: '/admin/puestos',          label: 'Puestos',          icon: Briefcase       },
  { to: '/admin/automatizaciones', label: 'Automatizaciones', icon: Bell            },
];

/**
 * Genera los enlaces de navegación de forma DINÁMICA según los permisos activos.
 *
 * Regla: permiso activo → sección visible en el menú.
 *        permiso inactivo → sección desaparece completamente.
 */
function buildDynamicNav(hasPermission) {
  const items = [];

  // Dashboard
  if (hasPermission('DASHBOARD_VIEW')) {
    items.push({ to: '/admin/dashboard', label: 'Dashboard', icon: LayoutDashboard });
  }

  // Sala / Mesas
  // TABLES_VIEW es la señal de acceso principal a la vista de sala.
  // FloorView gestiona internamente las pestañas Timing, Mesas, Alérgenos y Planos
  // según los permisos de cada usuario (con sus propias comprobaciones internas).
  const hasSalaAccess = hasPermission('TABLES_VIEW');
  if (hasSalaAccess) {
    items.push({ to: '/admin/sala', label: 'Sala / Mesas', icon: Layers });
  }

  // Protocolo
  // Solo aparece como enlace independiente si tiene PROTOCOL_VIEW pero NO sala.
  // Si ya tiene TABLES_VIEW → el protocolo está disponible como pestaña "Timing"
  // dentro de FloorView, evitando duplicados en el menú.
  if (hasPermission('PROTOCOL_VIEW') && !hasSalaAccess) {
    items.push({ to: '/admin/dj', label: 'Protocolo', icon: Music2 });
  }

  // Cocina: menús y/o alérgenos
  if (hasPermission('MENUS_VIEW') || hasPermission('ALLERGENS_VIEW')) {
    items.push({ to: '/admin/cocina', label: 'Cocina', icon: ChefHat });
  }

  return items;
}

// ── Config visual de roles (con fallback para roles personalizados) ──────────
const ROLE_CONFIG = {
  OFFICE:  { label: 'Administración',  color: 'bg-violet-100 text-violet-700',  dot: 'bg-violet-500'  },
  KITCHEN: { label: 'Cocina',          color: 'bg-orange-100 text-orange-700',  dot: 'bg-orange-500'  },
  DJ:      { label: 'DJ',              color: 'bg-blue-100 text-blue-700',      dot: 'bg-blue-500'    },
  FLOOR:   { label: 'Sala / Metres',   color: 'bg-emerald-100 text-emerald-700',dot: 'bg-emerald-500' },
  CLIENT:  { label: 'Cliente',         color: 'bg-rose-100 text-rose-700',      dot: 'bg-rose-500'    },
};

export default function Sidebar() {
  const { user, logout, hasPermission } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  // ── Construir lista de links según rol/permisos ──────────────────────────
  let links = [];
  if (user) {
    if (user.role === 'OFFICE') {
      links = OFFICE_NAV;
    } else if (user.role === 'CLIENT') {
      links = [{ to: '/mi-evento', label: 'Mi Evento', icon: Calendar }];
    } else {
      // KITCHEN, DJ, FLOOR y cualquier rol personalizado:
      // el menú se construye DINÁMICAMENTE a partir de los permisos activos.
      links = buildDynamicNav(hasPermission);
    }
  }

  // Config visual con fallback para roles custom no registrados
  const rc = ROLE_CONFIG[user?.role] ?? {
    label: user?.role ?? '—',
    color: 'bg-stone-100 text-stone-700',
    dot:   'bg-stone-400',
  };

  const handleLogout = () => { logout(); navigate('/login'); };

  const NavLinks = () => (
    <nav className="flex-1 px-3 py-4 space-y-1 overflow-y-auto">
      {links.length === 0 ? (
        <p className="text-xs text-stone-400 text-center px-2 py-8 leading-relaxed">
          Sin secciones habilitadas.<br />
          <span className="text-[11px]">Contacta con el administrador.</span>
        </p>
      ) : (
        links.map(link => {
          const Icon = link.icon;
          const active = location.pathname === link.to ||
            (link.to !== '/' && location.pathname.startsWith(link.to + '/'));
          return (
            <Link
              key={link.to}
              to={link.to}
              onClick={() => setMobileOpen(false)}
              className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-150 group ${
                active
                  ? 'bg-rose-50 text-rose-700 shadow-sm'
                  : 'text-stone-600 hover:bg-stone-100 hover:text-stone-900'
              }`}
            >
              <Icon
                size={18}
                className={active ? 'text-rose-600' : 'text-stone-400 group-hover:text-stone-600'}
              />
              {link.label}
              {active && <ChevronRight size={14} className="ml-auto text-rose-400" />}
            </Link>
          );
        })
      )}
    </nav>
  );

  const SidebarContent = () => (
    <div className="flex flex-col h-full">
      {/* Logo */}
      <div className="px-4 py-5 border-b border-stone-100 flex-none">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl overflow-hidden shadow-sm flex-none">
            <img src={logoApp} alt="Logo" className="w-full h-full object-cover scale-150" />
          </div>
          <div>
            <p className="font-bold text-stone-900 text-sm leading-none">Agora Celebraciones</p>
            <p className="text-xs text-stone-400 mt-0.5">Gestión Premium</p>
          </div>
        </div>
      </div>

      <NavLinks />

      {/* User footer */}
      <div className="px-3 pb-4 border-t border-stone-100 pt-3 flex-none">
        <div className="flex items-center gap-3 px-3 py-2.5 rounded-xl bg-stone-50">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-stone-200 to-stone-300 flex items-center justify-center flex-none">
            <span className="text-xs font-bold text-stone-600">
              {(user?.nombre || user?.username || '?')[0].toUpperCase()}
            </span>
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-stone-900 truncate">
              {user?.nombre || user?.username}
            </p>
            <span className={`badge ${rc.color} text-[10px] mt-0.5`}>{rc.label}</span>
          </div>
          <button
            onClick={handleLogout}
            className="text-stone-400 hover:text-rose-600 transition-colors p-1 rounded-lg hover:bg-rose-50"
            title="Cerrar sesión"
          >
            <LogOut size={15} />
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <>
      {/* Desktop sidebar */}
      <aside className="hidden lg:flex flex-col fixed inset-y-0 left-0 w-60 bg-white border-r border-stone-100 z-30 shadow-sm">
        <SidebarContent />
      </aside>

      {/* Mobile top bar */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-40 bg-white border-b border-stone-100 h-14 flex items-center px-4 gap-3 shadow-sm">
        <button
          onClick={() => setMobileOpen(true)}
          className="p-2 rounded-lg hover:bg-stone-100 transition-colors"
        >
          <Menu size={20} className="text-stone-600" />
        </button>
        <div className="flex items-center gap-2 flex-1">
          <div className="w-7 h-7 bg-gradient-to-br from-rose-500 to-pink-600 rounded-lg flex items-center justify-center">
            <Sparkles size={14} className="text-white" />
          </div>
          <span className="font-bold text-stone-900 text-sm">Salon Eventos</span>
        </div>
        <span className={`badge ${rc.color} text-[10px]`}>{rc.label}</span>
      </div>

      {/* Mobile drawer */}
      {mobileOpen && (
        <div className="lg:hidden fixed inset-0 z-50 flex">
          <div className="absolute inset-0 bg-black/40" onClick={() => setMobileOpen(false)} />
          <aside className="relative w-72 bg-white h-full flex flex-col shadow-2xl">
            <div className="flex items-center justify-between px-4 py-4 border-b border-stone-100 flex-none">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-gradient-to-br from-rose-500 to-pink-600 rounded-xl flex items-center justify-center">
                  <Sparkles size={16} className="text-white" />
                </div>
                <span className="font-bold text-stone-900">Salon Eventos</span>
              </div>
              <button onClick={() => setMobileOpen(false)} className="p-2 rounded-lg hover:bg-stone-100">
                <X size={18} className="text-stone-500" />
              </button>
            </div>
            <SidebarContent />
          </aside>
        </div>
      )}
    </>
  );
}

import React from 'react';
import { Document, Page, View, Text } from '@react-pdf/renderer';
import { styles, COLORS, formatDate } from './pdfStyles';
import { PdfHeader, PdfFooter } from './PdfPageBase';

const ALLERGEN_LABELS = {
  GLUTEN:'Gluten/Celíaco', LACTEOS:'Lácteos', HUEVOS:'Huevos',
  FRUTOS_SECOS:'Frutos secos', CACAHUETES:'Cacahuetes', SOJA:'Soja',
  MARISCO:'Marisco', PESCADO:'Pescado', MOSTAZA:'Mostaza', APIO:'Apio',
  SESAMO:'Sésamo', SULFITOS:'Sulfitos', MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuces',
};
const DIET_LABELS = {
  VEGETARIANO:'Vegetariano', VEGANO:'Vegano', HALAL:'Halal',
  KOSHER:'Kosher', SIN_SAL:'Sin sal', DIABETICO:'Diabético',
};

const SECTION = 'Dossier Operativo · Sala / Metre';

function SectionBlock({ title, emoji, color = COLORS.primary, bgColor = COLORS.primaryLight }) {
  return (
    <View style={{
      flexDirection: 'row', alignItems: 'center', backgroundColor: bgColor,
      borderLeft: `4pt solid ${color}`, borderRadius: 4,
      paddingHorizontal: 12, paddingVertical: 8, marginTop: 18, marginBottom: 12,
    }}>
      <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 12, color, flex: 1 }}>{emoji}  {title}</Text>
    </View>
  );
}

/**
 * PDF Operativo completo para Metre / Jefe de Sala
 * data = { event, protocol, tables, allergens, menus }
 */
export default function MetreOperativePdfDoc({ data }) {
  const { event, protocol = [], tables = [], allergens = [], menus = [] } = data;

  const totalGuests         = tables.reduce((s, t) => s + (t.guestCount || 0), 0);
  const tablesWithAllergens = tables.filter(t => t.allergiesCount > 0);
  const selectedMenu        = menus.find(m => m.selected);

  const allergensByTable = allergens.reduce((acc, a) => {
    const k = a.tableNumber || 'Sin mesa';
    (acc[k] = acc[k] || []).push(a);
    return acc;
  }, {});

  return (
    <Document
      title={`Dossier Operativo - ${event?.clientName}`}
      author="Sistema de Eventos"
      subject="Dossier operativo para Metre / Jefe de Sala"
    >
      {/* ════════════════════════════════════════════════════════════
          PÁGINA 1 — RESUMEN DEL EVENTO + PROTOCOLO / TIMING
      ════════════════════════════════════════════════════════════ */}
      <Page size="A4" style={styles.page}>
        <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
        <View style={styles.body}>

          <SectionBlock title="Resumen del evento" emoji="" />

          {/* Stats */}
          <View style={styles.statsRow}>
            <View style={styles.statBox}>
              <Text style={styles.statValue}>{totalGuests || event?.estimatedGuests || '—'}</Text>
              <Text style={styles.statLabel}>Invitados</Text>
            </View>
            <View style={[styles.statBox, { backgroundColor: '#f0fdf4', borderColor: '#bbf7d0' }]}>
              <Text style={[styles.statValue, { color: COLORS.green }]}>{tables.length}</Text>
              <Text style={styles.statLabel}>Mesas</Text>
            </View>
            <View style={[styles.statBox, { backgroundColor: COLORS.amberBg, borderColor: '#fcd34d' }]}>
              <Text style={[styles.statValue, { color: tablesWithAllergens.length > 0 ? COLORS.amber : COLORS.green }]}>
                {tablesWithAllergens.length}
              </Text>
              <Text style={styles.statLabel}>Mesas con alergias</Text>
            </View>
          </View>

          {/* info del evento */}
          <View style={styles.card}>
            {[
              ['Nombre del evento',   event?.clientName],
              ['Tipo de celebración', event?.typeLabel],
              ['Fecha',               event?.eventDate ? formatDate(event.eventDate) : ''],
              ['Invitados estimados', event?.estimatedGuests ? `${event.estimatedGuests} personas` : null],
              ['Salón / Lugar',       event?.venue],
              ['Menú confirmado',     selectedMenu?.name || 'Pendiente de confirmar'],
            ].filter(([, v]) => v).map(([label, value]) => (
              <View key={label} style={styles.infoRow}>
                <Text style={styles.infoLabel}>{label}</Text>
                <Text style={styles.infoValue}>{value}</Text>
              </View>
            ))}
            {event?.notes ? (
              <View style={[styles.infoRow, { marginTop: 6, paddingTop: 6, borderTop: `1pt solid ${COLORS.border}` }]}>
                <Text style={[styles.infoLabel, { color: COLORS.primary }]}>Notas internas</Text>
                <Text style={[styles.infoValue, { fontStyle: 'italic', color: COLORS.medium }]}>{event.notes}</Text>
              </View>
            ) : null}
          </View>

          {/* Protocolo / Timing */}
          <SectionBlock title="Protocolo del evento · Timing" emoji="" color="#1d4ed8" bgColor="#eff6ff" />

          {protocol.length === 0 ? (
            <View style={[styles.card, { alignItems: 'center', paddingVertical: 16 }]}>
              <Text style={{ fontSize: 9, color: COLORS.light }}>Sin protocolo definido</Text>
            </View>
          ) : (
            protocol.map((item, i) => (
              <View key={item.id || i} style={{ flexDirection: 'row', marginBottom: 8, alignItems: 'flex-start' }} wrap={false}>
                <View style={{
                  minWidth: 44, paddingHorizontal: 4, paddingVertical: 5,
                  backgroundColor: item.eventTime ? '#1d4ed8' : COLORS.border,
                  borderRadius: 6, alignItems: 'center', flexShrink: 0, marginRight: 10, marginTop: 1,
                }}>
                  <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 8.5, color: item.eventTime ? '#ffffff' : COLORS.medium }}>
                    {item.eventTime || `#${i + 1}`}
                  </Text>
                </View>
                <View style={{
                  flex: 1,
                  backgroundColor: item.youtubeLink ? '#eff6ff' : COLORS.bg,
                  border: `1pt solid ${item.youtubeLink ? '#bfdbfe' : COLORS.border}`,
                  borderRadius: 5, padding: 8,
                }}>
                  <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 10, color: COLORS.dark, marginBottom: 2 }}>
                    {item.description}
                  </Text>
                  {item.involvedPerson ? (
                    <Text style={{ fontSize: 8.5, color: COLORS.medium }}> {item.involvedPerson}</Text>
                  ) : null}
                  {item.youtubeLink ? (
                    <Text style={{ fontSize: 8.5, color: '#2563eb', marginTop: 2 }}> {item.youtubeLink}</Text>
                  ) : null}
                  {item.observations ? (
                    <Text style={{ fontSize: 8.5, color: COLORS.light, fontStyle: 'italic', marginTop: 2 }}>{item.observations}</Text>
                  ) : null}
                </View>
              </View>
            ))
          )}
        </View>
        <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
      </Page>

      {/* ════════════════════════════════════════════════════════════
          PÁGINA 2 — MESAS E INVITADOS
      ════════════════════════════════════════════════════════════ */}
      <Page size="A4" style={styles.page}>
        <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
        <View style={styles.body}>
          <SectionBlock title="Distribución de mesas e invitados" emoji="" color="#166534" bgColor="#f0fdf4" />

          {/* Índice rápido de mesas */}
          <View style={[styles.card, { marginBottom: 14 }]}>
            <Text style={[styles.cardTitle, { marginBottom: 8 }]}>Índice de mesas</Text>
            <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 6 }}>
              {tables.map(t => (
                <View key={t.id} style={{
                  paddingHorizontal: 8, paddingVertical: 4, borderRadius: 6,
                  backgroundColor: t.allergiesCount > 0 ? COLORS.amberBg : '#f0fdf4',
                  border: `1pt solid ${t.allergiesCount > 0 ? '#fcd34d' : '#bbf7d0'}`,
                }}>
                  <Text style={{ fontSize: 8, fontFamily: 'Helvetica-Bold', color: t.allergiesCount > 0 ? COLORS.amber : COLORS.green }}>
                    {t.name} ({t.guestCount || 0}){t.allergiesCount > 0 ? ' ⚠' : ''}
                  </Text>
                </View>
              ))}
            </View>
          </View>

          {tables.length === 0 ? (
            <View style={[styles.card, { alignItems: 'center', paddingVertical: 20 }]}>
              <Text style={{ fontSize: 9, color: COLORS.light }}>Sin mesas configuradas</Text>
            </View>
          ) : (
            tables.map(table => (
              <View key={table.id}
                style={[styles.card, { borderColor: table.allergiesCount > 0 ? '#fcd34d' : COLORS.border, marginBottom: 10 }]}
                wrap={false}
              >
                {/* Cabecera mesa */}
                <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: 8, paddingBottom: 6, borderBottom: `1.5pt solid ${table.allergiesCount > 0 ? '#fcd34d' : COLORS.border}` }}>
                  <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 11, color: COLORS.dark, flex: 1 }}>{table.name}</Text>
                  <Text style={{ fontSize: 8.5, color: COLORS.medium }}>
                    {table.guestCount || 0}{table.capacity ? `/${table.capacity}` : ''} inv.
                  </Text>
                  {table.allergiesCount > 0 && (
                    <View style={[styles.badge, { backgroundColor: COLORS.amberBg, marginLeft: 6 }]}>
                      <Text style={[styles.badgeText, { color: COLORS.amber }]}>⚠ {table.allergiesCount}</Text>
                    </View>
                  )}
                </View>
                {table.notes ? (
                  <Text style={[styles.cardText, { fontStyle: 'italic', marginBottom: 6, color: COLORS.medium }]}> {table.notes}</Text>
                ) : null}

                {/* Invitados */}
                {(table.guests || []).length === 0 ? (
                  <Text style={[styles.tableCell, { color: COLORS.light, fontStyle: 'italic' }]}>Sin invitados asignados</Text>
                ) : (
                  (table.guests || []).map((g, gi) => {
                    const hasR = g.diet || (g.allergies && g.allergies.trim());
                    return (
                      <View key={g.id || gi} style={{
                        flexDirection: 'row', alignItems: 'flex-start', paddingVertical: 5,
                        backgroundColor: hasR ? '#fffbeb' : 'transparent', borderRadius: hasR ? 4 : 0,
                        marginBottom: hasR ? 3 : 0, paddingHorizontal: hasR ? 6 : 0,
                        borderBottom: !hasR && gi < (table.guests || []).length - 1 ? `1pt solid ${COLORS.border}` : 'none',
                      }}>
                        <Text style={{ fontSize: 9, fontFamily: 'Helvetica-Bold', color: hasR ? '#92400e' : COLORS.dark, flex: 1 }}>
                          {hasR ? '⚠ ' : '· '}{g.guestName}
                        </Text>
                        <View style={{ flex: 2, flexDirection: 'row', flexWrap: 'wrap', gap: 2 }}>
                          {g.diet ? (
                            <View style={[styles.badge, { backgroundColor: '#f3e8ff' }]}>
                              <Text style={[styles.badgeText, { color: '#6b21a8' }]}>{DIET_LABELS[g.diet] || g.diet}</Text>
                            </View>
                          ) : null}
                          {g.allergies ? g.allergies.split(',').filter(Boolean).map(a => (
                            <View key={a} style={[styles.badge, { backgroundColor: COLORS.amberBg }]}>
                              <Text style={[styles.badgeText, { color: COLORS.amber }]}>{ALLERGEN_LABELS[a] || a}</Text>
                            </View>
                          )) : null}
                        </View>
                        {g.observations ? (
                          <Text style={{ fontSize: 7.5, color: COLORS.light, fontStyle: 'italic', flex: 1 }}>{g.observations}</Text>
                        ) : null}
                      </View>
                    );
                  })
                )}
              </View>
            ))
          )}
        </View>
        <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
      </Page>

      {/* ════════════════════════════════════════════════════════════
          PÁGINA 3 — ALERGIAS · VISTA OPERATIVA DE SERVICIO
      ════════════════════════════════════════════════════════════ */}
      <Page size="A4" style={styles.page}>
        <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
        <View style={styles.body}>
          <SectionBlock title="Necesidades especiales · Vista rápida de servicio" emoji="⚠️" color={COLORS.amber} bgColor={COLORS.amberBg} />

          <View style={styles.alertBox}>
            <Text style={styles.alertIcon}>⚠</Text>
            <Text style={styles.alertText}>
              ATENCIÓN: Verifica estas restricciones con cocina antes del servicio.
              Esta lista es de uso operativo para el día del evento.
            </Text>
          </View>

          {allergens.length === 0 ? (
            <View style={[styles.card, { alignItems: 'center', paddingVertical: 28, backgroundColor: '#f0fdf4', borderColor: '#bbf7d0' }]}>
              <Text style={{ fontSize: 11, fontFamily: 'Helvetica-Bold', color: COLORS.green, marginBottom: 4 }}>✅ Sin restricciones registradas</Text>
              <Text style={{ fontSize: 9, color: COLORS.medium }}>No hay alérgenos ni dietas especiales para este evento.</Text>
            </View>
          ) : (
            Object.entries(allergensByTable).sort(([a], [b]) => a.localeCompare(b)).map(([tableName, entries]) => (
              <View key={tableName} style={{ backgroundColor: '#fffbeb', border: `1.5pt solid #fcd34d`, borderRadius: 6, padding: 10, marginBottom: 8 }} wrap={false}>
                <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 10, color: '#92400e', marginBottom: 6, paddingBottom: 4, borderBottom: `1pt solid #fcd34d` }}>
                   {tableName}  ·  {entries.length} persona{entries.length !== 1 ? 's' : ''}
                </Text>
                {entries.map((e, ei) => (
                  <View key={e.id || ei} style={{ paddingVertical: 5, borderBottom: ei < entries.length - 1 ? `1pt solid #fde68a` : 'none' }}>
                    <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 10, color: COLORS.dark, marginBottom: 4 }}>⚠  {e.guestName}</Text>
                    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 3 }}>
                      {e.diet ? (
                        <View style={[styles.badge, { backgroundColor: '#f3e8ff', paddingHorizontal: 7, paddingVertical: 3 }]}>
                          <Text style={[styles.badgeText, { color: '#6b21a8', fontSize: 9 }]}> {DIET_LABELS[e.diet] || e.diet}</Text>
                        </View>
                      ) : null}
                      {e.allergies ? e.allergies.split(',').filter(Boolean).map(a => (
                        <View key={a} style={[styles.badge, { backgroundColor: '#fef3c7', paddingHorizontal: 7, paddingVertical: 3 }]}>
                          <Text style={[styles.badgeText, { color: '#92400e', fontSize: 9 }]}>⚠ {ALLERGEN_LABELS[a] || a}</Text>
                        </View>
                      )) : null}
                    </View>
                    {e.observations ? (
                      <Text style={{ fontSize: 8, color: COLORS.medium, fontStyle: 'italic', marginTop: 3 }}> {e.observations}</Text>
                    ) : null}
                  </View>
                ))}
              </View>
            ))
          )}
        </View>
        <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
      </Page>
    </Document>
  );
}

import React from 'react';
import { Document, Page, View, Text, Image } from '@react-pdf/renderer';
import { styles, COLORS, formatDate } from './pdfStyles';
import { PdfHeader, PdfFooter } from './PdfPageBase';

const ALLERGEN_LABELS = {
  GLUTEN:'Gluten/Celíaco', LACTEOS:'Lácteos', HUEVOS:'Huevos',
  FRUTOS_SECOS:'Frutos secos', CACAHUETES:'Cacahuetes', SOJA:'Soja',
  MARISCO:'Marisco', PESCADO:'Pescado', MOSTAZA:'Mostaza', APIO:'Apio',
  SESAMO:'Sésamo', SULFITOS:'Sulfitos', MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuces',
};
const DIET_LABELS = {
  VEGETARIANO:'Vegetariano', VEGANO:'Vegano', HALAL:'Halal',
  KOSHER:'Kosher', SIN_SAL:'Sin sal', DIABETICO:'Diabético',
};

const SECTION = 'Dossier Operativo · Sala / Metre';

function SectionBlock({ title, emoji, color = COLORS.primary, bgColor = COLORS.primaryLight }) {
  return (
    <View style={{
      flexDirection: 'row', alignItems: 'center', backgroundColor: bgColor,
      borderLeft: `4pt solid ${color}`, borderRadius: 4,
      paddingHorizontal: 12, paddingVertical: 8, marginTop: 18, marginBottom: 12,
    }}>
      <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 12, color, flex: 1 }}>{emoji}  {title}</Text>
    </View>
  );
}

/**
 * PDF Operativo completo para Metre / Jefe de Sala
 * data = { event, protocol, tables, allergens, menus, floorPlanBase64?, floorPlanIsImage?, floorPlanFilename? }
 */
export default function MetreOperativePdfDoc({ data }) {
  const { event, protocol = [], tables = [], allergens = [], menus = [],
          floorPlanBase64 = null, floorPlanIsImage = false, floorPlanFilename = null } = data;

  const totalGuests         = tables.reduce((s, t) => s + (t.guestCount || 0), 0);
  const tablesWithAllergens = tables.filter(t => t.allergiesCount > 0);
  const selectedMenu        = menus.find(m => m.selected);

  const allergensByTable = allergens.reduce((acc, a) => {
    const k = a.tableNumber || 'Sin mesa';
    (acc[k] = acc[k] || []).push(a);
    return acc;
  }, {});

  return (
    <Document
      title={`Dossier Operativo - ${event?.clientName}`}
      author="Sistema de Eventos"
      subject="Dossier operativo para Metre / Jefe de Sala"
    >
      {/* ════════════════════════════════════════════════════════════
          PÁGINA 1 — RESUMEN DEL EVENTO + PROTOCOLO / TIMING
      ════════════════════════════════════════════════════════════ */}
      <Page size="A4" style={styles.page}>
        <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
        <View style={styles.body}>

          <SectionBlock title="Resumen del evento" emoji="" />

          {/* Stats */}
          <View style={styles.statsRow}>
            <View style={styles.statBox}>
              <Text style={styles.statValue}>{totalGuests || event?.estimatedGuests || '—'}</Text>
              <Text style={styles.statLabel}>Invitados</Text>
            </View>
            <View style={[styles.statBox, { backgroundColor: '#f0fdf4', borderColor: '#bbf7d0' }]}>
              <Text style={[styles.statValue, { color: COLORS.green }]}>{tables.length}</Text>
              <Text style={styles.statLabel}>Mesas</Text>
            </View>
            <View style={[styles.statBox, { backgroundColor: COLORS.amberBg, borderColor: '#fcd34d' }]}>
              <Text style={[styles.statValue, { color: tablesWithAllergens.length > 0 ? COLORS.amber : COLORS.green }]}>
                {tablesWithAllergens.length}
              </Text>
              <Text style={styles.statLabel}>Mesas con alergias</Text>
            </View>
          </View>

          {/* info del evento */}
          <View style={styles.card}>
            {[
              ['Nombre del evento',   event?.clientName],
              ['Tipo de celebración', event?.typeLabel],
              ['Fecha',               event?.eventDate ? formatDate(event.eventDate) : ''],
              ['Invitados estimados', event?.estimatedGuests ? `${event.estimatedGuests} personas` : null],
              ['Salón / Lugar',       event?.venue],
              ['Menú confirmado',     selectedMenu?.name || 'Pendiente de confirmar'],
            ].filter(([, v]) => v).map(([label, value]) => (
              <View key={label} style={styles.infoRow}>
                <Text style={styles.infoLabel}>{label}</Text>
                <Text style={styles.infoValue}>{value}</Text>
              </View>
            ))}
            {event?.notes ? (
              <View style={[styles.infoRow, { marginTop: 6, paddingTop: 6, borderTop: `1pt solid ${COLORS.border}` }]}>
                <Text style={[styles.infoLabel, { color: COLORS.primary }]}>Notas internas</Text>
                <Text style={[styles.infoValue, { fontStyle: 'italic', color: COLORS.medium }]}>{event.notes}</Text>
              </View>
            ) : null}
          </View>

          {/* Protocolo / Timing */}
          <SectionBlock title="Protocolo del evento · Timing" emoji="" color="#1d4ed8" bgColor="#eff6ff" />

          {protocol.length === 0 ? (
            <View style={[styles.card, { alignItems: 'center', paddingVertical: 16 }]}>
              <Text style={{ fontSize: 9, color: COLORS.light }}>Sin protocolo definido</Text>
            </View>
          ) : (
            protocol.map((item, i) => (
              <View key={item.id || i} style={{ flexDirection: 'row', marginBottom: 8, alignItems: 'flex-start' }} wrap={false}>
                <View style={{
                  minWidth: 44, paddingHorizontal: 4, paddingVertical: 5,
                  backgroundColor: item.eventTime ? '#1d4ed8' : COLORS.border,
                  borderRadius: 6, alignItems: 'center', flexShrink: 0, marginRight: 10, marginTop: 1,
                }}>
                  <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 8.5, color: item.eventTime ? '#ffffff' : COLORS.medium }}>
                    {item.eventTime || `#${i + 1}`}
                  </Text>
                </View>
                <View style={{
                  flex: 1,
                  backgroundColor: item.youtubeLink ? '#eff6ff' : COLORS.bg,
                  border: `1pt solid ${item.youtubeLink ? '#bfdbfe' : COLORS.border}`,
                  borderRadius: 5, padding: 8,
                }}>
                  <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 10, color: COLORS.dark, marginBottom: 2 }}>
                    {item.description}
                  </Text>
                  {item.involvedPerson ? (
                    <Text style={{ fontSize: 8.5, color: COLORS.medium }}> {item.involvedPerson}</Text>
                  ) : null}
                  {item.youtubeLink ? (
                    <Text style={{ fontSize: 8.5, color: '#2563eb', marginTop: 2 }}> {item.youtubeLink}</Text>
                  ) : null}
                  {item.observations ? (
                    <Text style={{ fontSize: 8.5, color: COLORS.light, fontStyle: 'italic', marginTop: 2 }}>{item.observations}</Text>
                  ) : null}
                </View>
              </View>
            ))
          )}
        </View>
        <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
      </Page>

      {/* ════════════════════════════════════════════════════════════
          PÁGINA 2 — MESAS E INVITADOS
      ════════════════════════════════════════════════════════════ */}
      <Page size="A4" style={styles.page}>
        <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
        <View style={styles.body}>
          <SectionBlock title="Distribución de mesas e invitados" emoji="" color="#166534" bgColor="#f0fdf4" />

          {/* Índice rápido de mesas */}
          <View style={[styles.card, { marginBottom: 14 }]}>
            <Text style={[styles.cardTitle, { marginBottom: 8 }]}>Índice de mesas</Text>
            <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 6 }}>
              {tables.map(t => (
                <View key={t.id} style={{
                  paddingHorizontal: 8, paddingVertical: 4, borderRadius: 6,
                  backgroundColor: t.allergiesCount > 0 ? COLORS.amberBg : '#f0fdf4',
                  border: `1pt solid ${t.allergiesCount > 0 ? '#fcd34d' : '#bbf7d0'}`,
                }}>
                  <Text style={{ fontSize: 8, fontFamily: 'Helvetica-Bold', color: t.allergiesCount > 0 ? COLORS.amber : COLORS.green }}>
                    {t.name} ({t.guestCount || 0}){t.allergiesCount > 0 ? ' ⚠' : ''}
                  </Text>
                </View>
              ))}
            </View>
          </View>

          {tables.length === 0 ? (
            <View style={[styles.card, { alignItems: 'center', paddingVertical: 20 }]}>
              <Text style={{ fontSize: 9, color: COLORS.light }}>Sin mesas configuradas</Text>
            </View>
          ) : (
            tables.map(table => (
              <View key={table.id}
                style={[styles.card, { borderColor: table.allergiesCount > 0 ? '#fcd34d' : COLORS.border, marginBottom: 10 }]}
                wrap={false}
              >
                {/* Cabecera mesa */}
                <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: 8, paddingBottom: 6, borderBottom: `1.5pt solid ${table.allergiesCount > 0 ? '#fcd34d' : COLORS.border}` }}>
                  <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 11, color: COLORS.dark, flex: 1 }}>{table.name}</Text>
                  <Text style={{ fontSize: 8.5, color: COLORS.medium }}>
                    {table.guestCount || 0}{table.capacity ? `/${table.capacity}` : ''} inv.
                  </Text>
                  {table.allergiesCount > 0 && (
                    <View style={[styles.badge, { backgroundColor: COLORS.amberBg, marginLeft: 6 }]}>
                      <Text style={[styles.badgeText, { color: COLORS.amber }]}>⚠ {table.allergiesCount}</Text>
                    </View>
                  )}
                </View>
                {table.notes ? (
                  <Text style={[styles.cardText, { fontStyle: 'italic', marginBottom: 6, color: COLORS.medium }]}> {table.notes}</Text>
                ) : null}

                {/* Invitados */}
                {(table.guests || []).length === 0 ? (
                  <Text style={[styles.tableCell, { color: COLORS.light, fontStyle: 'italic' }]}>Sin invitados asignados</Text>
                ) : (
                  (table.guests || []).map((g, gi) => {
                    const hasR = g.diet || (g.allergies && g.allergies.trim());
                    return (
                      <View key={g.id || gi} style={{
                        flexDirection: 'row', alignItems: 'flex-start', paddingVertical: 5,
                        backgroundColor: hasR ? '#fffbeb' : 'transparent', borderRadius: hasR ? 4 : 0,
                        marginBottom: hasR ? 3 : 0, paddingHorizontal: hasR ? 6 : 0,
                        borderBottom: !hasR && gi < (table.guests || []).length - 1 ? `1pt solid ${COLORS.border}` : 'none',
                      }}>
                        <Text style={{ fontSize: 9, fontFamily: 'Helvetica-Bold', color: hasR ? '#92400e' : COLORS.dark, flex: 1 }}>
                          {hasR ? '⚠ ' : '· '}{g.guestName}
                        </Text>
                        <View style={{ flex: 2, flexDirection: 'row', flexWrap: 'wrap', gap: 2 }}>
                          {g.diet ? (
                            <View style={[styles.badge, { backgroundColor: '#f3e8ff' }]}>
                              <Text style={[styles.badgeText, { color: '#6b21a8' }]}>{DIET_LABELS[g.diet] || g.diet}</Text>
                            </View>
                          ) : null}
                          {g.allergies ? g.allergies.split(',').filter(Boolean).map(a => (
                            <View key={a} style={[styles.badge, { backgroundColor: COLORS.amberBg }]}>
                              <Text style={[styles.badgeText, { color: COLORS.amber }]}>{ALLERGEN_LABELS[a] || a}</Text>
                            </View>
                          )) : null}
                        </View>
                        {g.observations ? (
                          <Text style={{ fontSize: 7.5, color: COLORS.light, fontStyle: 'italic', flex: 1 }}>{g.observations}</Text>
                        ) : null}
                      </View>
                    );
                  })
                )}
              </View>
            ))
          )}
        </View>
        <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
      </Page>

      {/* ════════════════════════════════════════════════════════════
          PÁGINA 3 — ALERGIAS · VISTA OPERATIVA DE SERVICIO
      ════════════════════════════════════════════════════════════ */}
      <Page size="A4" style={styles.page}>
        <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
        <View style={styles.body}>
          <SectionBlock title="Necesidades especiales · Vista rápida de servicio" emoji="⚠️" color={COLORS.amber} bgColor={COLORS.amberBg} />

          <View style={styles.alertBox}>
            <Text style={styles.alertIcon}>⚠</Text>
            <Text style={styles.alertText}>
              ATENCIÓN: Verifica estas restricciones con cocina antes del servicio.
              Esta lista es de uso operativo para el día del evento.
            </Text>
          </View>

          {allergens.length === 0 ? (
            <View style={[styles.card, { alignItems: 'center', paddingVertical: 28, backgroundColor: '#f0fdf4', borderColor: '#bbf7d0' }]}>
              <Text style={{ fontSize: 11, fontFamily: 'Helvetica-Bold', color: COLORS.green, marginBottom: 4 }}>✅ Sin restricciones registradas</Text>
              <Text style={{ fontSize: 9, color: COLORS.medium }}>No hay alérgenos ni dietas especiales para este evento.</Text>
            </View>
          ) : (
            Object.entries(allergensByTable).sort(([a], [b]) => a.localeCompare(b)).map(([tableName, entries]) => (
              <View key={tableName} style={{ backgroundColor: '#fffbeb', border: `1.5pt solid #fcd34d`, borderRadius: 6, padding: 10, marginBottom: 8 }} wrap={false}>
                <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 10, color: '#92400e', marginBottom: 6, paddingBottom: 4, borderBottom: `1pt solid #fcd34d` }}>
                   {tableName}  ·  {entries.length} persona{entries.length !== 1 ? 's' : ''}
                </Text>
                {entries.map((e, ei) => (
                  <View key={e.id || ei} style={{ paddingVertical: 5, borderBottom: ei < entries.length - 1 ? `1pt solid #fde68a` : 'none' }}>
                    <Text style={{ fontFamily: 'Helvetica-Bold', fontSize: 10, color: COLORS.dark, marginBottom: 4 }}>⚠  {e.guestName}</Text>
                    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 3 }}>
                      {e.diet ? (
                        <View style={[styles.badge, { backgroundColor: '#f3e8ff', paddingHorizontal: 7, paddingVertical: 3 }]}>
                          <Text style={[styles.badgeText, { color: '#6b21a8', fontSize: 9 }]}> {DIET_LABELS[e.diet] || e.diet}</Text>
                        </View>
                      ) : null}
                      {e.allergies ? e.allergies.split(',').filter(Boolean).map(a => (
                        <View key={a} style={[styles.badge, { backgroundColor: '#fef3c7', paddingHorizontal: 7, paddingVertical: 3 }]}>
                          <Text style={[styles.badgeText, { color: '#92400e', fontSize: 9 }]}>⚠ {ALLERGEN_LABELS[a] || a}</Text>
                        </View>
                      )) : null}
                    </View>
                    {e.observations ? (
                      <Text style={{ fontSize: 8, color: COLORS.medium, fontStyle: 'italic', marginTop: 3 }}> {e.observations}</Text>
                    ) : null}
                  </View>
                ))}
              </View>
            ))
          )}
        </View>
        <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
      </Page>

      {/* ════════════════════════════════════════════════════════════
          PÁGINA 4 (opcional) — PLANO DEL SALÓN
      ════════════════════════════════════════════════════════════ */}
      {floorPlanBase64 && floorPlanIsImage && (
        <Page size="A4" style={styles.page}>
          <PdfHeader event={event} sectionLabel={SECTION} sectionIcon="" />
          <View style={styles.body}>
            <SectionBlock title="Plano del salón" emoji="️" color="#166534" bgColor="#f0fdf4" />
            {floorPlanFilename && (
              <Text style={{ fontSize: 8, color: COLORS.light, marginBottom: 8 }}>{floorPlanFilename}</Text>
            )}
            <Image
              src={floorPlanBase64}
              style={{ maxWidth: '100%', borderRadius: 6, objectFit: 'contain' }}
            />
          </View>
          <PdfFooter eventName={event?.clientName || ''} sectionLabel={SECTION} />
        </Page>
      )}
    </Document>
  );
}

import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import api from '../api/axios';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(() => {
    try { return JSON.parse(localStorage.getItem('user')); } catch { return null; }
  });

  const _applyData = (data) => {
    localStorage.setItem('token', data.token);
    localStorage.setItem('user', JSON.stringify(data));
    setUser(data);
  };

  const login = useCallback(async (username, password) => {
    const res = await api.post('/auth/login', { username, password });
    _applyData(res.data);
    return res.data;
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
  }, []);

  /**
   * Refresca el token y los permisos desde la BD sin necesidad de re-login.
   * Útil después de que un admin cambie los permisos de un puesto.
   * Devuelve los datos actualizados o null si falla silenciosamente.
   */
  const refreshPermissions = useCallback(async () => {
    try {
      const res = await api.get('/auth/refresh');
      _applyData(res.data);
      return res.data;
    } catch {
      // Si falla (token expirado, etc.) no hacemos nada
      return null;
    }
  }, []);

  // Al arrancar la app, si hay sesión activa, refrescamos permisos en segundo plano
  // para asegurar que los cambios de rol/permisos hechos por el admin se aplican.
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      refreshPermissions();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const isRole = useCallback((...roles) => {
    return user && roles.includes(user.role);
  }, [user]);

  /** Comprueba si el usuario tiene un permiso específico */
  const hasPermission = useCallback((code) => {
    if (!user) return false;
    // OFFICE siempre tiene todo (failsafe)
    if (user.role === 'OFFICE') return true;
    return Array.isArray(user.permissions) && user.permissions.includes(code);
  }, [user]);

  /** Comprueba varios permisos (AND: todos deben cumplirse) */
  const hasAllPermissions = useCallback((...codes) => {
    return codes.every(c => hasPermission(c));
  }, [hasPermission]);

  /** Comprueba varios permisos (OR: al menos uno) */
  const hasAnyPermission = useCallback((...codes) => {
    return codes.some(c => hasPermission(c));
  }, [hasPermission]);

  return (
    <AuthContext.Provider value={{ user, login, logout, isRole, hasPermission, hasAllPermissions, hasAnyPermission, refreshPermissions }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}

import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import api from '../api/axios';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(() => {
    try { return JSON.parse(localStorage.getItem('user')); } catch { return null; }
  });

  const _applyData = (data) => {
    localStorage.setItem('token', data.token);
    localStorage.setItem('user', JSON.stringify(data));
    setUser(data);
  };

  const login = useCallback(async (username, password) => {
    const res = await api.post('/auth/login', { username, password });
    _applyData(res.data);
    return res.data;
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
  }, []);

  /**
   * Refresca el token y los permisos desde la BD sin necesidad de re-login.
   * Útil después de que un admin cambie los permisos de un puesto.
   * Devuelve los datos actualizados o null si falla silenciosamente.
   */
  const refreshPermissions = useCallback(async () => {
    try {
      const res = await api.get('/auth/refresh');
      _applyData(res.data);
      return res.data;
    } catch {
      // Si falla (token expirado, etc.) no hacemos nada
      return null;
    }
  }, []);

  // Al arrancar la app, si hay sesión activa, refrescamos permisos en segundo plano
  // para asegurar que los cambios de rol/permisos hechos por el admin se aplican.
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      refreshPermissions();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Escucha notificaciones BroadcastChannel de cambios de permisos desde otra pestaña.
  // Así, si el admin guarda permisos en una pestaña, las demás pestañas abiertas
  // (incluyendo sesiones de otros roles en el mismo navegador) refrescan automáticamente.
  useEffect(() => {
    let bc;
    try {
      bc = new BroadcastChannel('perms_updated');
      bc.onmessage = () => {
        const token = localStorage.getItem('token');
        if (token) refreshPermissions();
      };
    } catch { /* BroadcastChannel no disponible */ }
    return () => { try { bc?.close(); } catch {} };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const isRole = useCallback((...roles) => {
    return user && roles.includes(user.role);
  }, [user]);

  /** Comprueba si el usuario tiene un permiso específico */
  const hasPermission = useCallback((code) => {
    if (!user) return false;
    // OFFICE siempre tiene todo (failsafe)
    if (user.role === 'OFFICE') return true;
    return Array.isArray(user.permissions) && user.permissions.includes(code);
  }, [user]);

  /** Comprueba varios permisos (AND: todos deben cumplirse) */
  const hasAllPermissions = useCallback((...codes) => {
    return codes.every(c => hasPermission(c));
  }, [hasPermission]);

  /** Comprueba varios permisos (OR: al menos uno) */
  const hasAnyPermission = useCallback((...codes) => {
    return codes.some(c => hasPermission(c));
  }, [hasPermission]);

  return (
    <AuthContext.Provider value={{ user, login, logout, isRole, hasPermission, hasAllPermissions, hasAnyPermission, refreshPermissions }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Sparkles, Lock, User, Eye, EyeOff } from 'lucide-react';
import toast from 'react-hot-toast';

export default function Login() {
  const [form, setForm] = useState({ username: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(form.username, form.password);
      toast.success(`Bienvenido, ${user.nombre || user.username} ✨`);
      if (user.role === 'CLIENT') navigate('/mi-evento');
      else if (user.role === 'KITCHEN') navigate('/admin/cocina');
      else if (user.role === 'DJ') navigate('/admin/dj');
      else if (user.role === 'FLOOR') navigate('/admin/sala');
      else navigate('/admin/dashboard');
    } catch {
      toast.error('Usuario o contraseña incorrectos');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-stone-100 via-rose-50/40 to-pink-50/60 flex items-center justify-center p-4">
      {/* Background decoration */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-rose-200/30 rounded-full blur-3xl" />
        <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-pink-200/30 rounded-full blur-3xl" />
      </div>

      <div className="w-full max-w-sm relative">
        {/* Logo + heading */}
        <div className="text-center mb-8">
          <div className="inline-flex w-16 h-16 bg-gradient-to-br from-rose-500 to-pink-600 rounded-2xl items-center justify-center shadow-lg shadow-rose-200 mb-4">
            <Sparkles size={28} className="text-white" />
          </div>
          <h1 className="text-2xl font-bold text-stone-900">Salón de celebraciones</h1>
          <p className="text-stone-500 text-sm mt-1">Accede a tu plataforma de gestión para tu evento</p>
        </div>

        {/* Card */}
        <div className="bg-white rounded-3xl shadow-xl shadow-stone-200/60 border border-stone-100 p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Username */}
            <div>
              <label className="label">Usuario</label>
              <div className="relative">
                <User size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  className="input pl-10"
                  type="text"
                  placeholder="Tu usuario"
                  value={form.username}
                  onChange={e => setForm(f => ({ ...f, username: e.target.value }))}
                  required autoFocus
                />
              </div>
            </div>

            {/* Password */}
            <div>
              <label className="label">Contraseña</label>
              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  className="input pl-10 pr-10"
                  type={showPass ? 'text' : 'password'}
                  placeholder="••••••••"
                  value={form.password}
                  onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPass(p => !p)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-400 hover:text-stone-600"
                >
                  {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button
              type="submit"
              className="btn-primary w-full py-3 text-base"
              disabled={loading}
            >
              {loading ? (
                <span className="flex items-center gap-2">
                  <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  Accediendo...
                </span>
              ) : 'Acceder →'}
            </button>
          </form>
        </div>

        <p className="text-center text-xs text-stone-400 mt-6">
          Sistema privado · Acceso solo con invitación
        </p>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Lock, User, Eye, EyeOff } from 'lucide-react';
import toast from 'react-hot-toast';
import logoApp from '../assets/logoApp.png';

export default function Login() {
  const [form, setForm] = useState({ username: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(form.username, form.password);
      toast.success(`Bienvenido, ${user.nombre || user.username} ✨`);
      if (user.role === 'CLIENT') navigate('/mi-evento');
      else if (user.role === 'KITCHEN') navigate('/admin/cocina');
      else if (user.role === 'DJ') navigate('/admin/dj');
      else if (user.role === 'FLOOR') navigate('/admin/sala');
      else navigate('/admin/dashboard');
    } catch {
      toast.error('Usuario o contraseña incorrectos');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-stone-100 via-rose-50/40 to-pink-50/60 flex items-center justify-center p-4">
      {/* Background decoration */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-rose-200/30 rounded-full blur-3xl" />
        <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-pink-200/30 rounded-full blur-3xl" />
      </div>

      <div className="w-full max-w-sm relative">
        {/* Logo + heading */}
        <div className="text-center mb-8">
          <div className="inline-flex w-24 h-24 rounded-3xl shadow-lg shadow-rose-200 overflow-hidden mb-4">
            <img src={logoApp} alt="Logo" className="w-full h-full object-cover scale-150" />
          </div>
          <h1 className="text-2xl font-bold text-stone-900">Salón de celebraciones</h1>
          <p className="text-stone-500 text-sm mt-1">Accede a tu plataforma de gestión para tu evento</p>
        </div>

        {/* Card */}
        <div className="bg-white rounded-3xl shadow-xl shadow-stone-200/60 border border-stone-100 p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Username */}
            <div>
              <label className="label">Usuario</label>
              <div className="relative">
                <User size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  className="input pl-10"
                  type="text"
                  placeholder="Tu usuario"
                  value={form.username}
                  onChange={e => setForm(f => ({ ...f, username: e.target.value }))}
                  required autoFocus
                />
              </div>
            </div>

            {/* Password */}
            <div>
              <label className="label">Contraseña</label>
              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  className="input pl-10 pr-10"
                  type={showPass ? 'text' : 'password'}
                  placeholder="••••••••"
                  value={form.password}
                  onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPass(p => !p)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-400 hover:text-stone-600"
                >
                  {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button
              type="submit"
              className="btn-primary w-full py-3 text-base"
              disabled={loading}
            >
              {loading ? (
                <span className="flex items-center gap-2">
                  <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  Accediendo...
                </span>
              ) : 'Acceder →'}
            </button>
          </form>
        </div>

        <p className="text-center text-xs text-stone-400 mt-6">
          Sistema privado · Acceso solo con invitación
        </p>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Music2, Calendar, Users, Clock, MapPin,
  Maximize2, Minimize2, Play, UserRound, Lock } from 'lucide-react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import PdfDownloadButton from '../../components/PdfDownloadButton';
import ProtocolPdfDoc from '../../components/pdf/ProtocolPdfDoc';

export default function DjView() {
  const { hasPermission } = useAuth();
  const [events, setEvents]     = useState([]);
  const [selected, setSelected] = useState(null);
  const [protocol, setProtocol] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [fullscreen, setFullscreen] = useState(false);
  const [noPermission, setNoPermission] = useState(false);

  useEffect(() => {
    api.get('/events/mis-eventos')
      .then(r => {
        const active = r.data.filter(e => !['COMPLETADO', 'CANCELADO'].includes(e.status));
        setEvents(active);
        if (active.length > 0) loadEvent(active[0].id);
        else setLoading(false);
      })
      .catch(err => {
        if (err.response?.status === 403) setNoPermission(true);
        else toast.error('Error cargando eventos');
        setLoading(false);
      });
  }, []);

  const loadEvent = async (id) => {
    setSelected(id);
    setProtocol([]);
    setLoading(true);
    try {
      const r = await api.get(`/events/${id}/protocol`);
      setProtocol(r.data);
    } catch (err) {
      if (err.response?.status === 403) {
        setProtocol([]);
        // No mostramos error toast — simplemente no hay acceso al protocolo
      }
    } finally {
      setLoading(false);
    }
  };

  const selectedEvent = events.find(e => e.id === selected);
  const canViewProtocol = hasPermission('PROTOCOL_VIEW');

  if (loading && events.length === 0) return (
    <Layout>
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-2 border-blue-200 border-t-blue-600 rounded-full animate-spin" />
      </div>
    </Layout>
  );

  if (noPermission) return (
    <Layout>
      <div className="card text-center py-20">
        <Lock size={48} className="text-stone-300 mx-auto mb-4" />
        <h2 className="text-xl font-bold text-stone-800 mb-2">Sin acceso</h2>
        <p className="text-stone-500">Tu puesto no tiene permisos para acceder a esta sección.</p>
      </div>
    </Layout>
  );

  if (events.length === 0) return (
    <Layout>
      <div className="card text-center py-20">
        <Music2 size={48} className="text-stone-300 mx-auto mb-4" />
        <h2 className="text-xl font-bold text-stone-800 mb-2">Sin eventos asignados</h2>
        <p className="text-stone-500">Cuando te asignen a un evento, aparecerá aquí.</p>
      </div>
    </Layout>
  );

  const TimelineView = () => (
    <div className={fullscreen ? 'fixed inset-0 z-50 bg-gray-950 overflow-y-auto p-4 sm:p-8' : ''}>
      {fullscreen && (
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center">
              <Music2 size={20} className="text-white" />
            </div>
            <div>
              <h1 className="text-white font-bold text-lg">{selectedEvent?.clientName}</h1>
              <p className="text-gray-400 text-sm">{selectedEvent?.typeLabel}</p>
            </div>
          </div>
          <button onClick={() => setFullscreen(false)}
            className="flex items-center gap-2 px-4 py-2 bg-gray-800 text-gray-300 rounded-xl hover:bg-gray-700 text-sm">
            <Minimize2 size={16} /> Salir pantalla completa
          </button>
        </div>
      )}

      {/* Sin permiso de protocolo */}
      {!canViewProtocol && (
        <div className={`${fullscreen ? 'bg-gray-800 rounded-2xl' : 'card'} text-center py-16`}>
          <Lock size={40} className={`${fullscreen ? 'text-gray-600' : 'text-stone-300'} mx-auto mb-4`} />
          <p className={`font-medium ${fullscreen ? 'text-gray-400' : 'text-stone-500'}`}>
            Tu puesto no tiene permiso para ver el protocolo.
          </p>
        </div>
      )}

      {canViewProtocol && protocol.length === 0 && (
        <div className={`${fullscreen ? 'bg-gray-800 rounded-2xl' : 'card'} text-center py-16`}>
          <Music2 size={40} className={`${fullscreen ? 'text-gray-600' : 'text-stone-300'} mx-auto mb-4`} />
          <p className={`font-medium ${fullscreen ? 'text-gray-400' : 'text-stone-500'}`}>
            El protocolo aún no está definido para este evento.
          </p>
        </div>
      )}

      {canViewProtocol && protocol.length > 0 && (
        <div className="space-y-3">
          {protocol.map((item, i) => (
            <motion.div key={item.id}
              initial={{ opacity: 0, x: -16 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: i * 0.04 }}
              className="relative flex gap-4"
            >
              {i < protocol.length - 1 && (
                <div className={`absolute left-6 top-14 bottom-0 w-px ${fullscreen ? 'bg-gray-700' : 'bg-stone-100'}`}
                  style={{ height: 'calc(100% - 3.5rem)' }} />
              )}
              <div className="flex-none w-12 flex flex-col items-center pt-1">
                {item.eventTime ? (
                  <div className={`text-center px-1 py-1.5 rounded-xl min-w-full ${fullscreen ? 'bg-blue-900/50 border border-blue-700' : 'bg-blue-50 border border-blue-100'}`}>
                    <span className={`text-xs font-bold leading-none ${fullscreen ? 'text-blue-300' : 'text-blue-700'}`}>{item.eventTime}</span>
                  </div>
                ) : (
                  <div className={`w-3 h-3 rounded-full border-2 mt-3 ${fullscreen ? 'border-gray-600 bg-gray-800' : 'border-stone-200 bg-white'}`} />
                )}
              </div>
              <div className={`flex-1 rounded-2xl p-4 mb-3 border transition-all ${
                item.youtubeLink
                  ? fullscreen ? 'bg-blue-900/30 border-blue-700/50' : 'bg-blue-50/80 border-blue-100'
                  : fullscreen ? 'bg-gray-800/80 border-gray-700' : 'bg-white border-stone-100 shadow-sm'
              }`}>
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1">
                    <p className={`font-bold text-base leading-snug ${fullscreen ? 'text-white' : 'text-stone-900'}`}>{item.description}</p>
                    {item.involvedPerson && (
                      <div className={`flex items-center gap-1.5 mt-1.5 text-sm ${fullscreen ? 'text-gray-400' : 'text-stone-500'}`}>
                        <UserRound size={13} />{item.involvedPerson}
                      </div>
                    )}
                    {item.observations && (
                      <p className={`text-sm mt-2 italic ${fullscreen ? 'text-gray-500' : 'text-stone-400'}`}>{item.observations}</p>
                    )}
                  </div>
                  <span className={`text-xs font-semibold px-2 py-1 rounded-lg flex-none ${fullscreen ? 'bg-gray-700 text-gray-400' : 'bg-stone-100 text-stone-500'}`}>#{i + 1}</span>
                </div>
                {item.youtubeLink && (
                  <a href={item.youtubeLink} target="_blank" rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 mt-3 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-xl text-sm font-semibold transition-colors shadow-sm">
                    <Play size={14} className="fill-current" /> Abrir en YouTube
                  </a>
                )}
              </div>
            </motion.div>
          ))}
        </div>
      )}
    </div>
  );

  return (
    <Layout>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl flex items-center justify-center shadow-sm">
              <Music2 size={22} className="text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-stone-900">Vista DJ</h1>
              <p className="text-stone-500 text-sm">Protocolo y canciones del evento</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {selectedEvent && canViewProtocol && (
              <PdfDownloadButton
                permissionCode="PROTOCOL_VIEW"
                label="Descargar protocolo PDF"
                variant="primary"
                fileName={`protocolo-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                fetchData={async () => {
                  const r = await api.get(`/events/${selected}/protocol`);
                  return { event: selectedEvent, protocol: r.data };
                }}
                DocumentComponent={ProtocolPdfDoc}
              />
            )}
            {canViewProtocol && protocol.length > 0 && (
              <button onClick={() => setFullscreen(true)} className="btn-secondary text-sm">
                <Maximize2 size={15} /> Pantalla completa
              </button>
            )}
          </div>
        </div>

        {events.length > 1 && (
          <div className="flex gap-2 flex-wrap">
            {events.map(e => (
              <button key={e.id} onClick={() => loadEvent(e.id)}
                className={`px-4 py-2 rounded-xl text-sm font-medium border transition-all ${
                  selected === e.id ? 'bg-blue-600 text-white border-blue-600 shadow-sm' : 'bg-white text-stone-600 border-stone-200 hover:border-blue-200'
                }`}>
                {e.clientName}
                <span className="ml-1.5 opacity-70 text-xs">{new Date(e.eventDate).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}</span>
              </button>
            ))}
          </div>
        )}

        {selectedEvent && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
            className="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-5 text-white shadow-lg shadow-blue-200">
            <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3">
              <div>
                <p className="text-blue-200 text-xs font-semibold uppercase tracking-wide mb-1">{selectedEvent.typeLabel}</p>
                <h2 className="text-xl font-bold">{selectedEvent.clientName}</h2>
              </div>
              {selectedEvent.daysUntilEvent >= 0 && selectedEvent.daysUntilEvent <= 7 && (
                <div className="bg-white/20 rounded-xl px-3 py-1.5 text-center flex-none">
                  <p className="text-xs text-blue-200">Faltan</p>
                  <p className="text-2xl font-black">{selectedEvent.daysUntilEvent}</p>
                  <p className="text-xs text-blue-200">días</p>
                </div>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 mt-3 text-sm text-blue-100">
              <span className="flex items-center gap-1.5"><Calendar size={14} />{new Date(selectedEvent.eventDate).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}</span>
              {selectedEvent.venue && <span className="flex items-center gap-1.5"><MapPin size={14} />{selectedEvent.venue}</span>}
              {selectedEvent.estimatedGuests && <span className="flex items-center gap-1.5"><Users size={14} />{selectedEvent.estimatedGuests} invitados</span>}
            </div>
          </motion.div>
        )}

        {canViewProtocol && protocol.length > 0 && (
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Clock size={16} className="text-stone-400" />
              <span className="text-sm font-medium text-stone-600">{protocol.length} momentos en el protocolo</span>
            </div>
            <PdfDownloadButton
              permissionCode="PROTOCOL_VIEW"
              label="Descargar protocolo PDF"
              fileName={`protocolo-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
              fetchData={async () => {
                const r = await api.get(`/events/${selected}/protocol`);
                return { event: selectedEvent, protocol: r.data };
              }}
              DocumentComponent={ProtocolPdfDoc}
            />
          </div>
        )}

        <TimelineView />
      </div>
    </Layout>
  );
}

