                {item.youtubeLink && (
                  <a href={item.youtubeLink} target="_blank" rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 mt-3 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-xl text-sm font-semibold transition-colors shadow-sm">
                    <Play size={14} className="fill-current" /> Abrir en YouTube
                  </a>
                )}
              </div>
            </motion.div>
          ))}
        </div>
      )}
    </div>
  );

  return (
    <Layout>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl flex items-center justify-center shadow-sm">
              <Music2 size={22} className="text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-stone-900">Vista DJ</h1>
              <p className="text-stone-500 text-sm">Protocolo y canciones del evento</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {selectedEvent && canViewProtocol && (
              <PdfDownloadButton
                permissionCode="PDF_PROTOCOL"
                label="Descargar protocolo PDF"
                variant="primary"
                fileName={`protocolo-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                fetchData={async () => {
                  const r = await api.get(`/events/${selected}/protocol`);
                  return { event: selectedEvent, protocol: r.data };
                }}
                DocumentComponent={ProtocolPdfDoc}
              />
            )}
            {canViewProtocol && protocol.length > 0 && (
              <button onClick={() => setFullscreen(true)} className="btn-secondary text-sm">
                <Maximize2 size={15} /> Pantalla completa
              </button>
            )}
          </div>
        </div>

        {events.length > 1 && (
          <div className="flex gap-2 flex-wrap">
            {events.map(e => (
              <button key={e.id} onClick={() => loadEvent(e.id)}
                className={`px-4 py-2 rounded-xl text-sm font-medium border transition-all ${
                  selected === e.id ? 'bg-blue-600 text-white border-blue-600 shadow-sm' : 'bg-white text-stone-600 border-stone-200 hover:border-blue-200'
                }`}>
                {e.clientName}
                <span className="ml-1.5 opacity-70 text-xs">{new Date(e.eventDate).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}</span>
              </button>
            ))}
          </div>
        )}

        {selectedEvent && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
            className="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-5 text-white shadow-lg shadow-blue-200">
            <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3">
              <div>
                <p className="text-blue-200 text-xs font-semibold uppercase tracking-wide mb-1">{selectedEvent.typeLabel}</p>
                <h2 className="text-xl font-bold">{selectedEvent.clientName}</h2>
              </div>
              {selectedEvent.daysUntilEvent >= 0 && selectedEvent.daysUntilEvent <= 7 && (
                <div className="bg-white/20 rounded-xl px-3 py-1.5 text-center flex-none">
                  <p className="text-xs text-blue-200">Faltan</p>
                  <p className="text-2xl font-black">{selectedEvent.daysUntilEvent}</p>
                  <p className="text-xs text-blue-200">días</p>
                </div>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 mt-3 text-sm text-blue-100">
              <span className="flex items-center gap-1.5"><Calendar size={14} />{new Date(selectedEvent.eventDate).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}</span>
              {selectedEvent.venue && <span className="flex items-center gap-1.5"><MapPin size={14} />{selectedEvent.venue}</span>}
              {selectedEvent.estimatedGuests && <span className="flex items-center gap-1.5"><Users size={14} />{selectedEvent.estimatedGuests} invitados</span>}
            </div>
          </motion.div>
        )}

        {canViewProtocol && protocol.length > 0 && (
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Clock size={16} className="text-stone-400" />
              <span className="text-sm font-medium text-stone-600">{protocol.length} momentos en el protocolo</span>
            </div>
            <PdfDownloadButton
              permissionCode="PDF_PROTOCOL"
              label="Descargar protocolo PDF"
              fileName={`protocolo-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
              fetchData={async () => {
                const r = await api.get(`/events/${selected}/protocol`);
                return { event: selectedEvent, protocol: r.data };
              }}
              DocumentComponent={ProtocolPdfDoc}
            />
          </div>
        )}

        <TimelineView />
      </div>
    </Layout>
  );
}

import { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { ArrowLeft, Music2, Layers, ChefHat, UserPlus, Trash2, Edit2, X, AlertTriangle, Table2, Map, ZoomIn, ZoomOut, Upload, RotateCcw } from 'lucide-react';
import PdfDownloadButton from '../../components/PdfDownloadButton';
import ProtocolPdfDoc  from '../../components/pdf/ProtocolPdfDoc';
import TablesPdfDoc    from '../../components/pdf/TablesPdfDoc';
import AllergensPdfDoc from '../../components/pdf/AllergensPdfDoc';
import MenusPdfDoc     from '../../components/pdf/MenusPdfDoc';
import InvoicePdfDoc   from '../../components/pdf/InvoicePdfDoc';

const TABS = [
  { id: 'info',         label: 'Información' },
  { id: 'asignaciones', label: 'Personal'     },
  { id: 'menus',        label: 'Menús'        },
  { id: 'allergens',    label: 'Alérgenos'    },
  { id: 'protocol',     label: 'Protocolo'    },
  { id: 'mesas',        label: 'Mesas'        },
  { id: 'planos',       label: 'Planos'       },
  { id: 'invoice',      label: 'Facturación'  },
  { id: 'reminders',    label: 'Recordatorios'},
];

const STATUS_OPTIONS = ['BORRADOR','PENDIENTE_INFO','EN_CURSO','CONFIRMADO','COMPLETADO','CANCELADO'];
const STATUS_LABELS = { BORRADOR:'Borrador', PENDIENTE_INFO:'Pendiente info', EN_CURSO:'En curso', CONFIRMADO:'Confirmado', COMPLETADO:'Completado', CANCELADO:'Cancelado' };

export default function EventDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [tab, setTab] = useState('info');
  const [event, setEvent] = useState(null);
  const [menus, setMenus] = useState([]);
  const [allergens, setAllergens] = useState([]);
  const [protocol, setProtocol] = useState([]);
  const [invoice, setInvoice] = useState(null);
  const [assignments, setAssignments] = useState([]);
  const [staff, setStaff] = useState([]);
  const [tables, setTables] = useState([]);

  const loadEvent       = () => api.get(`/events/${id}`).then(r => setEvent(r.data));
  const loadMenus       = () => api.get(`/events/${id}/menus`).then(r => setMenus(r.data));
  const loadAllergens   = () => api.get(`/events/${id}/allergens`).then(r => setAllergens(r.data));
  const loadProtocol    = () => api.get(`/events/${id}/protocol`).then(r => setProtocol(r.data));
  const loadInvoice     = () => api.get(`/events/${id}/invoice`).then(r => setInvoice(r.data)).catch(() => setInvoice(null));
  const loadAssignments = () => api.get(`/events/${id}/assignments`).then(r => setAssignments(r.data));
  const loadStaff       = () => api.get('/users/staff').then(r => setStaff(r.data)).catch(() => {});
  const loadTables      = () => api.get(`/events/${id}/tables`).then(r => setTables(r.data)).catch(() => {});

  useEffect(() => {
    loadEvent(); loadMenus(); loadAllergens(); loadProtocol();
    loadInvoice(); loadAssignments(); loadStaff(); loadTables();
  }, [id]);

  if (!event) return <Layout><div className="animate-pulse text-center p-20 text-stone-400">Cargando...</div></Layout>;

  const handleStatusChange = async (status) => {
    try {
      await api.patch(`/events/${id}/status`, { status });
      setEvent(ev => ({ ...ev, status, statusLabel: STATUS_LABELS[status] }));
      toast.success('Estado actualizado');
    } catch { toast.error('Error al actualizar estado'); }
  };

  const sendReminder = async (channel) => {
    const message = `Hola ${event.clientName}, le recordamos que tiene pendiente completar información para su evento. Acceda al portal: http://localhost:5173/login`;
    try {
      await api.post(`/dashboard/send-reminder/${id}`, { message, channel, subject: 'Recordatorio de su evento' });
      toast.success(`Recordatorio enviado por ${channel}`);
    } catch { toast.error('Error enviando recordatorio'); }
  };

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
          <div className="flex items-center gap-3">
            <button onClick={() => navigate('/admin/eventos')}
              className="flex items-center gap-1 text-stone-400 hover:text-stone-600 transition-colors">
              <ArrowLeft size={18} />
            </button>
            <div>
              <h1 className="text-2xl font-bold text-stone-900">{event.clientName}</h1>
              <p className="text-stone-500">
                {event.typeLabel} · {new Date(event.eventDate).toLocaleDateString('es-ES', { weekday:'long', year:'numeric', month:'long', day:'numeric' })}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <select value={event.status} onChange={e => handleStatusChange(e.target.value)} className="input w-auto text-sm">
              {STATUS_OPTIONS.map(s => <option key={s} value={s}>{STATUS_LABELS[s]}</option>)}
            </select>
          </div>
        </div>

        {/* Completitud */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {[
            { ok: event.menuConfirmed,      label: 'Menú confirmado',       icon: '️' },
            { ok: event.allergensCompleted, label: 'Alérgenos registrados', icon: '⚠️' },
            { ok: event.protocolCompleted,  label: 'Protocolo completo',    icon: '' },
            { ok: event.budgetSigned,       label: 'Presupuesto firmado',   icon: '✍️' },
          ].map(item => (
            <div key={item.label} className={`card p-4 text-center ${item.ok ? 'border-emerald-200 bg-emerald-50' : 'border-amber-200 bg-amber-50'}`}>
              <div className="text-2xl mb-1">{item.icon}</div>
              <p className={`text-xs font-medium ${item.ok ? 'text-emerald-700' : 'text-amber-700'}`}>
                {item.ok ? '✅' : '⚠️'} {item.label}
              </p>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div className="border-b border-stone-200">
          <div className="flex gap-1 overflow-x-auto">
            {TABS.map(t => (
              <button key={t.id} onClick={() => setTab(t.id)}
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                  tab === t.id ? 'border-rose-600 text-rose-600' : 'border-transparent text-stone-500 hover:text-stone-700'
                }`}>
                {t.label}
              </button>
            ))}
          </div>
        </div>

        {/* Tab content */}
        {tab === 'info'         && <InfoTab event={event} />}
        {tab === 'asignaciones' && <AsignacionesTab eventId={id} assignments={assignments} staff={staff} reload={loadAssignments} />}
        {tab === 'menus'        && <MenusTab eventId={id} event={event} menus={menus} reload={loadMenus} />}
        {tab === 'allergens'    && <AllergensTab eventId={id} event={event} tables={tables} reload={() => { loadTables(); loadEvent(); }} onGoToMesas={() => setTab('mesas')} />}
        {tab === 'protocol'     && <ProtocolTab eventId={id} event={event} items={protocol} reload={() => { loadProtocol(); loadEvent(); }} />}
        {tab === 'mesas'        && <MesasAdminTab eventId={id} event={event} tables={tables} reload={() => { loadTables(); loadEvent(); }} />}
        {tab === 'planos'       && <PlanosTab eventId={id} event={event} />}
        {tab === 'invoice'      && <InvoiceTab eventId={id} event={event} invoice={invoice} reload={loadInvoice} />}
        {tab === 'reminders'    && <RemindersTab event={event} onSend={sendReminder} />}
      </div>
    </Layout>
  );
}

// -- Tab Components --

// ── Constantes compartidas ─────────────────────────────────────────────────────
const ALLERGEN_LIST = ['GLUTEN','LACTEOS','HUEVOS','FRUTOS_SECOS','CACAHUETES','SOJA','MARISCO','PESCADO','MOSTAZA','APIO','SESAMO','SULFITOS','MOLUSCOS','ALTRAMUZ'];
const ALLERGEN_LABELS_MAP = { GLUTEN:'Gluten/Celíaco', LACTEOS:'Lácteos', HUEVOS:'Huevos', FRUTOS_SECOS:'Frutos secos', CACAHUETES:'Cacahuetes', SOJA:'Soja', MARISCO:'Marisco', PESCADO:'Pescado', MOSTAZA:'Mostaza', APIO:'Apio', SESAMO:'Sésamo', SULFITOS:'Sulfitos', MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuces' };
const ALLERGEN_BADGE_COLORS = ['bg-amber-50 text-amber-700 border border-amber-200','bg-red-50 text-red-700 border border-red-200','bg-orange-50 text-orange-700 border border-orange-200','bg-yellow-50 text-yellow-700 border border-yellow-200'];
const DIET_COLORS = { VEGETARIANO:'bg-green-100 text-green-700', VEGANO:'bg-emerald-100 text-emerald-700', HALAL:'bg-teal-100 text-teal-700', KOSHER:'bg-cyan-100 text-cyan-700', SIN_SAL:'bg-sky-100 text-sky-700', DIABETICO:'bg-blue-100 text-blue-700' };

function InfoTab({ event }) {
  return (
    <div className="card">
      <h3 className="font-semibold text-stone-800 mb-4">Datos del evento</h3>
      <dl className="grid grid-cols-1 sm:grid-cols-2 gap-y-4 gap-x-8 text-sm">
        {[
          { label: 'Cliente',             value: event.clientName        },
          { label: 'Tipo',                value: event.typeLabel         },
          { label: 'Fecha',               value: new Date(event.eventDate).toLocaleDateString('es-ES') },
          { label: 'Invitados estimados', value: event.estimatedGuests   },
          { label: 'Salón',               value: event.venue             },
          { label: 'Contacto',            value: event.contactPerson     },
          { label: 'Teléfono',            value: event.phone             },
          { label: 'Email',               value: event.email             },
          { label: 'Acceso cliente',      value: event.clientUsername    },
        ].map(item => item.value ? (
          <div key={item.label}>
            <dt className="text-stone-500">{item.label}</dt>
            <dd className="font-medium text-stone-900">{item.value}</dd>
          </div>
        ) : null)}
      </dl>
      {event.notes && (
        <div className="mt-4 pt-4 border-t border-stone-100">
          <p className="text-stone-500 text-sm mb-1">Notas internas</p>
          <p className="text-stone-700 text-sm">{event.notes}</p>
        </div>
      )}
    </div>
  );
}

function AsignacionesTab({ eventId, assignments, staff, reload }) {
  const [selectedUser, setSelectedUser] = useState('');

  const ROLE_ICONS  = { DJ: Music2, FLOOR: Layers, KITCHEN: ChefHat };
  const ROLE_COLORS = { DJ:'bg-blue-100 text-blue-700', FLOOR:'bg-emerald-100 text-emerald-700', KITCHEN:'bg-orange-100 text-orange-700', OFFICE:'bg-violet-100 text-violet-700' };
  const ROLE_LABELS = { DJ:'DJ', FLOOR:'Sala/Metres', KITCHEN:'Cocina', OFFICE:'Oficina' };

  const assignedIds = assignments.map(a => a.userId);
  const available   = staff.filter(u => !assignedIds.includes(u.id) && u.role !== 'OFFICE' && u.role !== 'CLIENT');

  const handleAssign = async () => {
    if (!selectedUser) { toast.error('Selecciona un usuario'); return; }
    try {
      await api.post(`/events/${eventId}/assignments`, { userId: parseInt(selectedUser) });
      reload(); setSelectedUser(''); toast.success('Personal asignado ?');
    } catch { toast.error('Error al asignar'); }
  };

  const handleRemove = async (userId, nombre) => {
    if (!confirm(`¿Quitar a "${nombre}" de este evento?`)) return;
    try {
      await api.delete(`/events/${eventId}/assignments/${userId}`);
      reload(); toast.success('Asignación eliminada');
    } catch { toast.error('Error'); }
  };

  return (
    <div className="space-y-5">
      <div className="card">
        <h3 className="font-semibold text-stone-900 mb-4 flex items-center gap-2">
          <UserPlus size={18} className="text-stone-500" />
          Asignar personal a este evento
        </h3>
        {available.length === 0 ? (
          <p className="text-sm text-stone-400">Todo el personal disponible ya está asignado.</p>
        ) : (
          <div className="flex gap-3">
            <select className="input flex-1" value={selectedUser} onChange={e => setSelectedUser(e.target.value)}>
              <option value="">Seleccionar persona...</option>
              {available.map(u => (
                <option key={u.id} value={u.id}>{u.nombre} ({ROLE_LABELS[u.role] || u.role})</option>
              ))}
            </select>
            <button onClick={handleAssign} className="btn-primary flex-none">
              <UserPlus size={16} /> Asignar
            </button>
          </div>
        )}
      </div>

      {assignments.length === 0 ? (
        <div className="card text-center py-12">
          <UserPlus size={36} className="text-stone-300 mx-auto mb-3" />
          <p className="text-stone-500 font-medium">Sin personal asignado</p>
          <p className="text-stone-400 text-sm mt-1">Asigna DJ, metres o cocina para que puedan ver este evento en su panel.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {assignments.map(a => {
            const Icon = ROLE_ICONS[a.role] || UserPlus;
            return (
              <div key={a.id} className="card p-4 flex items-center gap-3 group">
                <div className={`w-10 h-10 rounded-xl ${ROLE_COLORS[a.role]} flex items-center justify-center flex-none`}>
                  <Icon size={16} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-stone-900 text-sm">{a.nombre}</p>
                  <p className="text-xs text-stone-400">@{a.username}</p>
                  <span className={`badge ${ROLE_COLORS[a.role]} text-xs mt-0.5`}>{ROLE_LABELS[a.role] || a.role}</span>
                </div>
                <button onClick={() => handleRemove(a.userId, a.nombre)}
                  className="opacity-0 group-hover:opacity-100 transition-opacity btn-ghost p-1.5 hover:text-red-600 hover:bg-red-50 rounded-lg">
                  <Trash2 size={14} className="text-stone-400" />
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function MenusTab({ eventId, event, menus, reload }) {
  const [form, setForm] = useState({ name:'', description:'', starters:'', firstCourse:'', secondCourse:'', dessert:'', drinks:'', extras:'' });
  const [showForm, setShowForm] = useState(false);

  const handleCreate = async () => {
    try {
      await api.post(`/events/${eventId}/menus`, form);
      reload(); setShowForm(false);
      setForm({ name:'', description:'', starters:'', firstCourse:'', secondCourse:'', dessert:'', drinks:'', extras:'' });
      toast.success('Menú creado');
    } catch { toast.error('Error al crear menú'); }
  };
  const handleSelect = async (menuId) => {
try { await api.post(`/events/${eventId}/menus/${menuId}/select`); reload(); toast.success('Menú seleccionado'); }
    catch { toast.error('Error'); }
  };
  const handleDelete = async (menuId) => {
    if (!confirm('¿Eliminar menú?')) return;
    try { await api.delete(`/events/${eventId}/menus/${menuId}`); reload(); toast.success('Menú eliminado'); }
    catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/menus`);
    return { event, menus: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800">Menús del evento</h3>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="MENUS_VIEW"
            label="PDF menús"
            fileName={`menus-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={MenusPdfDoc}
          />
          <button onClick={() => setShowForm(!showForm)} className="btn-primary text-sm">+ Añadir menú</button>
        </div>
      </div>
      {showForm && (
        <div className="card border-rose-100">
          <h4 className="font-medium mb-3">Nuevo menú</h4>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {[['name','Nombre *'],['starters','Entrantes'],['firstCourse','Primer plato'],['secondCourse','Segundo plato'],['dessert','Postre'],['drinks','Bebidas'],['extras','Extras']].map(([k,l]) => (
              <div key={k}>
                <label className="label">{l}</label>
                <textarea className="input" rows={2} value={form[k]||''} onChange={e => setForm(f=>({...f,[k]:e.target.value}))} />
              </div>
            ))}
          </div>
          <div className="flex gap-3 mt-4">
            <button onClick={() => setShowForm(false)} className="btn-secondary">Cancelar</button>
            <button onClick={handleCreate} className="btn-primary">Guardar menú</button>
          </div>
        </div>
      )}
      {menus.length === 0 && !showForm && <p className="text-stone-500 text-sm">No hay menús. Añade uno para que el cliente pueda seleccionar.</p>}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {menus.map(m => (
          <div key={m.id} className={`card ${m.selected ? 'border-emerald-400 bg-emerald-50' : ''}`}>
            <div className="flex justify-between items-start mb-3">
              <h4 className="font-semibold">{m.name}</h4>
              {m.selected && <span className="badge bg-emerald-100 text-emerald-700">✅ Seleccionado</span>}
            </div>
            {[['Entrantes',m.starters],['1er plato',m.firstCourse],['2do plato',m.secondCourse],['Postre',m.dessert],['Bebidas',m.drinks],['Extras',m.extras]].filter(([,v])=>v).map(([l,v])=>(
              <p key={l} className="text-sm text-stone-600 mb-1"><span className="font-medium">{l}:</span> {v}</p>
            ))}
            <div className="flex gap-2 mt-4">
              {!m.selected && <button onClick={() => handleSelect(m.id)} className="btn-success text-sm flex-1">Seleccionar</button>}
              <button onClick={() => handleDelete(m.id)} className="btn-danger text-sm">Eliminar</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function AllergensTab({ eventId, event, tables, reload, onGoToMesas }) {
  // ── Estado del formulario "Añadir alérgeno" ──────────────────────────────
  const [showForm,         setShowForm]        = useState(false);
  const [formMesaId,       setFormMesaId]      = useState('');
  const [formGuestId,      setFormGuestId]     = useState('');
  const [newAllergies,     setNewAllergies]    = useState([]);
  const [newDiet,          setNewDiet]         = useState('');
  const [newObs,           setNewObs]          = useState('');

  // ── Estado de edición inline ──────────────────────────────────────────────
  const [editingId,  setEditingId]  = useState(null);
  const [editForm,   setEditForm]   = useState({ allergies: [], diet: '', observations: '' });
  const [saving,     setSaving]     = useState(false);

  // ── Datos derivados ───────────────────────────────────────────────────────
  const allGuests = tables.flatMap(t =>
    (t.guests || []).map(g => ({ ...g, tableName: t.name, tableId: t.id }))
  );
  // Solo mesas con al menos un invitado con restricción
  const tablesWithRestrictions = tables.filter(t =>
    (t.guests || []).some(g => g.allergies || g.diet)
  );
  const withRestrictionsCount = allGuests.filter(g => g.allergies || g.diet).length;

  // Invitados de la mesa seleccionada en el formulario (para el step 2)
  const guestsInFormMesa = formMesaId
    ? (tables.find(t => t.id === parseInt(formMesaId))?.guests || [])
    : [];

  // ── Formulario "Añadir" ───────────────────────────────────────────────────
  const openForm = () => {
    setShowForm(true); setFormMesaId(''); setFormGuestId('');
    setNewAllergies([]); setNewDiet(''); setNewObs('');
  };
  const toggleNew = a =>
    setNewAllergies(p => p.includes(a) ? p.filter(x => x !== a) : [...p, a]);

  const handleAdd = async () => {
    if (!formGuestId) { toast.error('Selecciona un invitado'); return; }
    const mesa  = tables.find(t => t.id === parseInt(formMesaId));
    const guest = (mesa?.guests || []).find(g => g.id === parseInt(formGuestId));
    if (!guest) return;
    if (!newAllergies.length && !newDiet) { toast.error('Selecciona al menos un alérgeno o dieta'); return; }
    setSaving(true);
    try {
      await api.put(`/events/${eventId}/tables/${mesa.id}/guests/${guest.id}`, {
        guestName: guest.guestName,
        allergies: newAllergies.join(','),
        diet: newDiet,
        observations: newObs,
      });
      toast.success('Alérgenos asignados');
      setShowForm(false);
      reload();
    } catch { toast.error('Error al guardar'); }
    finally { setSaving(false); }
  };

  // ── Edición inline ────────────────────────────────────────────────────────
  const startEdit = g => {
    setEditingId(g.id);
    setEditForm({
      allergies:    g.allergies ? g.allergies.split(',').filter(Boolean) : [],
      diet:         g.diet || '',
      observations: g.observations || '',
    });
  };
  const toggleEdit = a =>
    setEditForm(f => ({
      ...f,
      allergies: f.allergies.includes(a) ? f.allergies.filter(x => x !== a) : [...f.allergies, a],
    }));

  const handleSave = async g => {
    setSaving(true);
    try {
      await api.put(`/events/${eventId}/tables/${g.tableId}/guests/${g.id}`, {
        guestName: g.guestName,
        allergies: editForm.allergies.join(','),
        diet:      editForm.diet,
        observations: editForm.observations,
      });
      toast.success('Actualizado');
      setEditingId(null);
      reload();
    } catch { toast.error('Error al guardar'); }
    finally { setSaving(false); }
  };

  const handleClear = async g => {
    if (!confirm(`¿Eliminar las restricciones de ${g.guestName}?`)) return;
    try {
      await api.put(`/events/${eventId}/tables/${g.tableId}/guests/${g.id}`,
        { guestName: g.guestName, allergies: '', diet: '', observations: '' });
      toast.success('Restricciones eliminadas');
      reload();
    } catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/allergens`);
    return { event, allergens: r.data.filter(x => x.allergies || x.diet) };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  // ── Guards ────────────────────────────────────────────────────────────────
  if (tables.length === 0) return (
    <div className="card text-center py-16">
      <AlertTriangle size={40} className="text-stone-300 mx-auto mb-4" />
      <h3 className="font-semibold text-stone-700 mb-2">Sin mesas creadas</h3>
      <p className="text-stone-500 text-sm mb-5">Primero debes crear mesas e invitados antes de gestionar alérgenos.</p>
      <button onClick={onGoToMesas} className="btn-primary text-sm inline-flex items-center gap-2 mx-auto">
        <Table2 size={14} /> Ir a Mesas
      </button>
    </div>
  );

  if (allGuests.length === 0) return (
    <div className="card text-center py-16">
      <AlertTriangle size={40} className="text-stone-300 mx-auto mb-4" />
      <h3 className="font-semibold text-stone-700 mb-2">Sin invitados</h3>
      <p className="text-stone-500 text-sm mb-5">Añade invitados en la pestaña Mesas para gestionar sus alérgenos.</p>
      <button onClick={onGoToMesas} className="btn-primary text-sm inline-flex items-center gap-2 mx-auto">
        <Table2 size={14} /> Ir a Mesas
      </button>
    </div>
  );

  // ── Render principal ──────────────────────────────────────────────────────
  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex justify-between items-center flex-wrap gap-2">
        <div>
          <h3 className="font-semibold text-stone-800">Alérgenos y dietas especiales</h3>
          <p className="text-xs text-stone-500 mt-0.5">
            {withRestrictionsCount > 0
              ? `${withRestrictionsCount} de ${allGuests.length} invitados con restricciones`
              : 'Ningún invitado tiene restricciones todavía'}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="ALLERGENS_VIEW"
            label="PDF alérgenos"
            fileName={`alergenos-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={AllergensPdfDoc}
          />
          <button onClick={openForm}
            className="btn-primary text-sm inline-flex items-center gap-1.5">
            + Añadir alérgeno
          </button>
        </div>
      </div>

      {/* ── Formulario 3 pasos ── */}
      {showForm && (
        <div className="card border-amber-200 bg-amber-50/30 space-y-4">
          <div className="flex items-center justify-between">
            <h4 className="font-semibold text-stone-800">Asignar alérgenos a un invitado</h4>
            <button onClick={() => setShowForm(false)} className="text-stone-400 hover:text-stone-600"><X size={16} /></button>
          </div>

          {/* Paso 1 — Mesa */}
          <div>
            <label className="label">Paso 1 — Selecciona la mesa</label>
            <select className="input"
              value={formMesaId}
              onChange={e => { setFormMesaId(e.target.value); setFormGuestId(''); }}>
              <option value="">— Seleccionar mesa —</option>
              {tables.map(t => (
                <option key={t.id} value={t.id}>
                  {t.name}{t.guestCount ? ` (${t.guestCount} inv.)` : ''}
                </option>
              ))}
            </select>
          </div>

          {/* Paso 2 — Invitado */}
          {formMesaId && (
            <div>
              <label className="label">Paso 2 — Selecciona el invitado</label>
              {guestsInFormMesa.length === 0
                ? <p className="text-sm text-stone-400 italic">Esta mesa no tiene invitados registrados.</p>
                : (
                  <select className="input" value={formGuestId} onChange={e => setFormGuestId(e.target.value)}>
                    <option value="">— Seleccionar invitado —</option>
                    {guestsInFormMesa.map(g => (
                      <option key={g.id} value={g.id}>
                        {g.guestName}{(g.allergies || g.diet) ? ' ⚠' : ''}
                      </option>
                    ))}
                  </select>
                )}
            </div>
          )}

          {/* Paso 3 — Alérgenos */}
          {formGuestId && (
            <>
              <div>
                <label className="label">Paso 3 — Alérgenos</label>
                <div className="flex flex-wrap gap-1.5 mt-1">
                  {ALLERGEN_LIST.map(a => (
                    <button key={a} type="button" onClick={() => toggleNew(a)}
                      className={`px-2 py-1 rounded-lg text-xs font-medium border transition-colors ${
                        newAllergies.includes(a)
                          ? 'bg-amber-500 text-white border-amber-500'
                          : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'
                      }`}>
                      {ALLERGEN_LABELS_MAP[a]}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label className="label">Dieta especial</label>
                <select className="input" value={newDiet} onChange={e => setNewDiet(e.target.value)}>
                  <option value="">Ninguna</option>
                  {['VEGETARIANO','VEGANO','HALAL','KOSHER','SIN_SAL','DIABETICO'].map(d => (
                    <option key={d} value={d}>{d.replace('_', ' ')}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="label">Observaciones</label>
                <input className="input" value={newObs}
                  onChange={e => setNewObs(e.target.value)}
                  placeholder="Alergia muy grave, llevar EpiPen..." />
              </div>
            </>
          )}

          <div className="flex gap-3 pt-1">
            <button onClick={() => setShowForm(false)} className="btn-secondary flex-1">Cancelar</button>
            <button onClick={handleAdd} disabled={!formGuestId || saving}
              className="btn-primary flex-1">
              {saving ? 'Guardando...' : 'Guardar'}
            </button>
          </div>
        </div>
      )}

      {/* Sin restricciones todavía */}
      {tablesWithRestrictions.length === 0 && !showForm && (
        <div className="card text-center py-10">
          <div className="text-3xl mb-3">✅</div>
          <p className="text-stone-500 text-sm">Ningún invitado tiene restricciones registradas.</p>
          <p className="text-stone-400 text-xs mt-1">Usa "+ Añadir alérgeno" para registrar la primera.</p>
        </div>
      )}

      {/* ── Listado: solo mesas con restricciones, solo invitados con restricciones ── */}
      {tablesWithRestrictions.map(table => {
        const restricted = (table.guests || [])
          .filter(g => g.allergies || g.diet)
          .map(g => ({ ...g, tableId: table.id, tableName: table.name }));

        return (
          <div key={table.id} className="card border-amber-100">
            <div className="flex items-center gap-2 mb-3">
              <span className="text-sm font-bold text-stone-800"> {table.name}</span>
              <span className="badge bg-amber-100 text-amber-700 text-[10px]">
                ⚠ {restricted.length} restricción{restricted.length !== 1 ? 'es' : ''}
              </span>
              <span className="ml-auto text-xs text-stone-400">
                {(table.guests || []).length} inv. en total
              </span>
            </div>

            <div className="space-y-2">
              {restricted.map(g => {
                const isEditing = editingId === g.id;
                return (
                  <div key={g.id}
                    className={`rounded-xl border transition-all ${isEditing ? 'border-amber-200 bg-amber-50/40' : 'border-stone-100 bg-stone-50'}`}>

                    {!isEditing && (
                      <div className="flex items-start justify-between p-3 gap-2">
                        <div className="flex-1 min-w-0">
                          <p className="font-semibold text-sm text-stone-900">{g.guestName}</p>
                          <div className="flex flex-wrap gap-1 mt-1">
                            {g.diet && (
                              <span className={`badge text-[10px] ${DIET_COLORS[g.diet] || 'bg-purple-100 text-purple-700'}`}>
                                {g.diet.replace('_', ' ')}
                              </span>
                            )}
                            {g.allergies && g.allergies.split(',').filter(Boolean).map((a, idx) => (
                              <span key={a} className={`badge text-[10px] ${ALLERGEN_BADGE_COLORS[idx % ALLERGEN_BADGE_COLORS.length]}`}>
                                ⚠ {ALLERGEN_LABELS_MAP[a] || a}
                              </span>
                            ))}
                          </div>
                          {g.observations && <p className="text-[10px] text-stone-400 italic mt-1">{g.observations}</p>}
                        </div>
                        <div className="flex items-center gap-1 flex-none">
                          <button onClick={() => startEdit(g)}
                            className="p-1.5 rounded-lg text-stone-400 hover:text-blue-600 hover:bg-blue-50 transition-colors" title="Editar">
                            <Edit2 size={13} />
                          </button>
                          <button onClick={() => handleClear(g)}
                            className="p-1.5 rounded-lg text-stone-400 hover:text-red-600 hover:bg-red-50 transition-colors" title="Eliminar restricciones">
                            <X size={13} />
                          </button>
                        </div>
                      </div>
                    )}

                    {isEditing && (
                      <div className="p-4 space-y-3">
                        <div className="flex items-center justify-between">
                          <p className="font-semibold text-sm text-stone-900">✏️ {g.guestName}</p>
                          <button onClick={() => setEditingId(null)} className="text-stone-400 hover:text-stone-600"><X size={15} /></button>
                        </div>
                        <div>
                          <label className="label text-xs mb-1.5 block">Alérgenos</label>
                          <div className="flex flex-wrap gap-1.5">
                            {ALLERGEN_LIST.map(a => (
                              <button key={a} type="button" onClick={() => toggleEdit(a)}
                                className={`px-2 py-1 rounded-lg text-[11px] font-medium border transition-colors ${
                                  editForm.allergies.includes(a)
                                    ? 'bg-amber-500 text-white border-amber-500'
                                    : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'
                                }`}>
                                {ALLERGEN_LABELS_MAP[a]}
                              </button>
                            ))}
                          </div>
                        </div>
                        <div>
                          <label className="label text-xs mb-1 block">Dieta especial</label>
                          <select className="input text-sm" value={editForm.diet}
                            onChange={e => setEditForm(f => ({ ...f, diet: e.target.value }))}>
                            <option value="">Ninguna</option>
                            {['VEGETARIANO','VEGANO','HALAL','KOSHER','SIN_SAL','DIABETICO'].map(d => (
                              <option key={d} value={d}>{d.replace('_', ' ')}</option>
                            ))}
                          </select>
                        </div>
                        <div>
                          <label className="label text-xs mb-1 block">Observaciones</label>
                          <input className="input text-sm" value={editForm.observations}
                            onChange={e => setEditForm(f => ({ ...f, observations: e.target.value }))}
                            placeholder="Alergia muy grave, llevar EpiPen..." />
                        </div>
                        <div className="flex gap-2 pt-1">
                          <button onClick={() => setEditingId(null)} className="btn-secondary flex-1 text-sm">Cancelar</button>
                          <button onClick={() => handleSave(g)} disabled={saving} className="btn-primary flex-1 text-sm">
                            {saving ? 'Guardando...' : 'Guardar'}
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function ProtocolTab({ eventId, event, items, reload }) {
  const [form, setForm] = useState({ eventTime:'', description:'', involvedPerson:'', youtubeLink:'', observations:'' });
  const [showForm, setShowForm] = useState(false);

  const handleCreate = async () => {
    try {
      await api.post(`/events/${eventId}/protocol`, { ...form, position: items.length + 1 });
      reload(); setShowForm(false);
      setForm({ eventTime:'', description:'', involvedPerson:'', youtubeLink:'', observations:'' });
      toast.success('Momento añadido');
    } catch { toast.error('Error'); }
  };
  const handleDelete = async (itemId) => {
    try { await api.delete(`/events/${eventId}/protocol/${itemId}`); reload(); }
    catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/protocol`);
    return { event, protocol: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800">Protocolo del evento</h3>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="PROTOCOL_VIEW"
            label="PDF protocolo"
            fileName={`protocolo-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={ProtocolPdfDoc}
          />
          <button onClick={() => setShowForm(!showForm)} className="btn-primary text-sm">+ Añadir momento</button>
        </div>
      </div>
      {showForm && (
        <div className="card border-blue-100">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <div><label className="label">Hora</label><input className="input" type="time" value={form.eventTime} onChange={e=>setForm(f=>({...f,eventTime:e.target.value}))} /></div>
            <div><label className="label">Descripción *</label><input className="input" value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))} placeholder="Entrada de los novios" /></div>
            <div><label className="label">Persona implicada</label><input className="input" value={form.involvedPerson} onChange={e=>setForm(f=>({...f,involvedPerson:e.target.value}))} /></div>
            <div><label className="label">Enlace YouTube / Canción</label><input className="input" value={form.youtubeLink} onChange={e=>setForm(f=>({...f,youtubeLink:e.target.value}))} placeholder="https://youtube.com/..." /></div>
            <div className="sm:col-span-2"><label className="label">Observaciones</label><input className="input" value={form.observations} onChange={e=>setForm(f=>({...f,observations:e.target.value}))} /></div>
          </div>
          <div className="flex gap-3 mt-4">
            <button onClick={() => setShowForm(false)} className="btn-secondary">Cancelar</button>
            <button onClick={handleCreate} className="btn-primary">Guardar</button>
          </div>
        </div>
      )}
      {items.length === 0 && !showForm && <p className="text-stone-500 text-sm">No hay protocolo definido.</p>}
      <div className="relative">
        {items.map((item, i) => (
          <div key={item.id} className="flex gap-4 mb-4">
            <div className="flex flex-col items-center">
              <div className="w-8 h-8 rounded-full bg-rose-600 text-white flex items-center justify-center text-xs font-bold">{i+1}</div>
              {i < items.length - 1 && <div className="w-0.5 h-full bg-stone-200 my-1" />}
            </div>
            <div className="card flex-1 p-4">
              <div className="flex justify-between items-start">
                <div>
                  {item.eventTime && <span className="text-sm font-semibold text-rose-600">{item.eventTime} · </span>}
                  <span className="font-medium">{item.description}</span>
                  {item.involvedPerson && <p className="text-sm text-stone-500 mt-1"> {item.involvedPerson}</p>}
                  {item.youtubeLink && <a href={item.youtubeLink} target="_blank" rel="noopener noreferrer" className="text-sm text-blue-600 hover:underline mt-1 block"> {item.youtubeLink}</a>}
                  {item.observations && <p className="text-sm text-stone-500 mt-1 italic">{item.observations}</p>}
                </div>
                <button onClick={() => handleDelete(item.id)} className="text-red-400 hover:text-red-600 text-sm ml-2">✕</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function InvoiceTab({ eventId, event, invoice, reload }) {
  const [form, setForm] = useState({ totalAmount: invoice?.totalAmount || '', description: invoice?.description || '', breakdown: invoice?.breakdown || '' });
  const [payForm, setPayForm] = useState({ amount:'', description:'', paymentDate:'', status:'PAGADO', method:'TRANSFERENCIA' });

  const handleSave = async () => {
    try {
      await api.post(`/events/${eventId}/invoice`, { ...form, totalAmount: parseFloat(form.totalAmount) });
      reload(); toast.success('Presupuesto guardado');
    } catch { toast.error('Error'); }
  };
  const handleAddPayment = async () => {
    if (!invoice) { toast.error('Guarda el presupuesto primero'); return; }
    try {
      await api.post(`/events/${eventId}/invoice/${invoice.id}/payments`, { ...payForm, amount: parseFloat(payForm.amount) });
      reload(); setPayForm({ amount:'', description:'', paymentDate:'', status:'PAGADO', method:'TRANSFERENCIA' });
      toast.success('Pago registrado');
    } catch { toast.error('Error'); }
  };
  const handleDeletePayment = async (paymentId) => {
    try { await api.delete(`/events/${eventId}/invoice/${invoice.id}/payments/${paymentId}`); reload(); }
    catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/invoice`).catch(() => ({ data: null }));
    return { event, invoice: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800 text-lg">Facturación</h3>
        <PdfDownloadButton
          permissionCode="INVOICES_VIEW"
            label="PDF facturación"
          fileName={`facturacion-${safeName}.pdf`}
          fetchData={fetchPdfData}
          DocumentComponent={InvoicePdfDoc}
        />
      </div>
      <div className="card">
        <h3 className="font-semibold mb-4">Presupuesto</h3>
        {invoice && <p className="text-xs text-stone-400 mb-3">Ref: {invoice.invoiceNumber}</p>}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4">
          <div><label className="label">Importe total (€) *</label><input className="input" type="number" value={form.totalAmount} onChange={e=>setForm(f=>({...f,totalAmount:e.target.value}))} placeholder="5000" /></div>
          <div><label className="label">Descripción</label><input className="input" value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))} placeholder="Boda completa" /></div>
          <div className="sm:col-span-2"><label className="label">Desglose de conceptos</label><textarea className="input" rows={3} value={form.breakdown} onChange={e=>setForm(f=>({...f,breakdown:e.target.value}))} placeholder="Salón: 2000€&#10;Catering: 3000€" /></div>
        </div>
        <button onClick={handleSave} className="btn-primary">Guardar presupuesto</button>
        {invoice?.signed && <span className="ml-3 badge bg-emerald-100 text-emerald-700">✅ Firmado el {new Date(invoice.signedAt).toLocaleDateString('es-ES')}</span>}
      </div>

      {invoice && (
        <>
          <div className="grid grid-cols-3 gap-4">
            <div className="card p-4 text-center"><p className="text-2xl font-bold text-stone-900">{invoice.totalAmount?.toLocaleString('es-ES')}€</p><p className="text-sm text-stone-500">Total</p></div>
            <div className="card p-4 text-center"><p className="text-2xl font-bold text-emerald-600">{invoice.paidAmount?.toLocaleString('es-ES')}€</p><p className="text-sm text-stone-500">Pagado</p></div>
            <div className="card p-4 text-center"><p className="text-2xl font-bold text-amber-600">{invoice.pendingAmount?.toLocaleString('es-ES')}€</p><p className="text-sm text-stone-500">Pendiente</p></div>
          </div>
          <div className="card">
            <h3 className="font-semibold mb-4">Registrar pago</h3>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 mb-4">
              <div><label className="label">Importe (€)</label><input className="input" type="number" value={payForm.amount} onChange={e=>setPayForm(f=>({...f,amount:e.target.value}))} /></div>
              <div><label className="label">Fecha</label><input className="input" type="date" value={payForm.paymentDate} onChange={e=>setPayForm(f=>({...f,paymentDate:e.target.value}))} /></div>
              <div><label className="label">Descripción</label><input className="input" value={payForm.description} onChange={e=>setPayForm(f=>({...f,description:e.target.value}))} placeholder="Señal, pago final..." /></div>
              <div><label className="label">Método</label>
                <select className="input" value={payForm.method} onChange={e=>setPayForm(f=>({...f,method:e.target.value}))}>
                  {['TRANSFERENCIA','EFECTIVO','TARJETA','BIZUM'].map(m=><option key={m}>{m}</option>)}
                </select>
              </div>
            </div>
            <button onClick={handleAddPayment} className="btn-success text-sm">+ Registrar pago</button>
            <div className="mt-4 space-y-2">
              {invoice.payments?.map(p => (
                <div key={p.id} className="flex items-center justify-between p-3 bg-stone-50 rounded-xl text-sm">
                  <div>
                    <span className="font-medium">{p.amount?.toLocaleString('es-ES')}€</span>
                    <span className="text-stone-500 ml-2">{p.description}</span>
                    {p.paymentDate && <span className="text-stone-400 ml-2">{new Date(p.paymentDate).toLocaleDateString('es-ES')}</span>}
                    {p.method && <span className="badge bg-stone-100 text-stone-600 ml-2">{p.method}</span>}
                  </div>
                  <button onClick={() => handleDeletePayment(p.id)} className="text-red-400 hover:text-red-600">✕</button>
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function RemindersTab({ event, onSend }) {
  const pending = [];
  if (!event.menuConfirmed)      pending.push('El menú aún no ha sido confirmado.');
  if (!event.allergensCompleted) pending.push('No hay alérgenos registrados.');
  if (!event.protocolCompleted)  pending.push('El protocolo del evento no está completo.');
  if (!event.budgetSigned)       pending.push('El presupuesto no ha sido firmado.');

  return (
    <div className="space-y-4">
      <div className="card">
        <h3 className="font-semibold mb-3">Estado de tareas pendientes</h3>
        {pending.length === 0 ? (
          <p className="text-emerald-600">✅ Todo completado</p>
        ) : (
          <ul className="space-y-2">
            {pending.map(p => <li key={p} className="flex items-center gap-2 text-amber-700"><span>⚠️</span>{p}</li>)}
          </ul>
        )}
      </div>
      <div className="card">
        <h3 className="font-semibold mb-3">Enviar recordatorio manual</h3>
        <p className="text-sm text-stone-500 mb-4">Se enviará un recordatorio al cliente para que complete la información pendiente.</p>
        <div className="flex flex-wrap gap-3">
          <button onClick={() => onSend('EMAIL')}    className="btn-secondary text-sm"> Enviar por Email</button>
          <button onClick={() => onSend('SMS')}      className="btn-secondary text-sm"> Enviar por SMS</button>
          <button onClick={() => onSend('WHATSAPP')} className="btn-secondary text-sm"> Enviar por WhatsApp</button>
        </div>
      </div>
    </div>
  );
}

// -- Mesas Admin ----------------------------------------------------------------
const DIET_OPTS = ['VEGETARIANO','VEGANO','HALAL','KOSHER','SIN_SAL','DIABETICO'];

function MesasAdminTab({ eventId, event, tables, reload }) {
  const [showNewTable, setShowNewTable]       = useState(false);
  const [newTable, setNewTable]               = useState({ name: '', capacity: '', notes: '' });
  const [showAddGuest, setShowAddGuest]       = useState(null); // tableId
  const [guestForm, setGuestForm]             = useState({ guestName: '', diet: '', observations: '' });
  const [selAllergens, setSelAllergens]       = useState([]);
  const [editingGuest, setEditingGuest]       = useState(null); // { guest, tableId }
  const [editGuestForm, setEditGuestForm]     = useState({ guestName: '', diet: '', observations: '' });
  const [editSelAllergens, setEditSelAllergens] = useState([]);

  const totalGuests   = tables.reduce((s, t) => s + (t.guestCount || 0), 0);
  const totalAlergias = tables.reduce((s, t) => s + (t.allergiesCount || 0), 0);

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/tables`);
    return { event, tables: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  const handleCreateTable = async () => {
    if (!newTable.name.trim()) { toast.error('El nombre es obligatorio'); return; }
    try {
      await api.post(`/events/${eventId}/tables`, { ...newTable, capacity: newTable.capacity ? parseInt(newTable.capacity) : null });
      toast.success('Mesa creada');
      setShowNewTable(false); setNewTable({ name: '', capacity: '', notes: '' }); reload();
    } catch { toast.error('Error al crear mesa'); }
  };

  const handleDeleteTable = async (tableId, name) => {
    if (!confirm(`¿Eliminar la mesa "${name}" y todos sus invitados?`)) return;
    try { await api.delete(`/events/${eventId}/tables/${tableId}`); toast.success('Mesa eliminada'); reload(); }
    catch { toast.error('Error'); }
  };

  const handleAddGuest = async (tableId) => {
    if (!guestForm.guestName.trim()) { toast.error('El nombre es obligatorio'); return; }
    try {
      await api.post(`/events/${eventId}/tables/${tableId}/guests`, { ...guestForm, allergies: selAllergens.join(',') });
      toast.success('Invitado añadido');
      setShowAddGuest(null); setGuestForm({ guestName:'', diet:'', observations:'' }); setSelAllergens([]); reload();
    } catch { toast.error('Error'); }
  };

  const handleDeleteGuest = async (tableId, guestId) => {
    try { await api.delete(`/events/${eventId}/tables/${tableId}/guests/${guestId}`); reload(); }
    catch { toast.error('Error'); }
  };

  const handleMoveGuest = async (tableId, guestId, targetTableId) => {
    try {
      await api.patch(`/events/${eventId}/tables/${tableId}/guests/${guestId}/move`, { targetTableId });
      toast.success('Invitado movido'); reload();
    } catch { toast.error('Error al mover'); }
  };

  const startEditGuest = (g, tableId) => {
    setEditingGuest({ guestId: g.id, tableId });
    setEditGuestForm({ guestName: g.guestName, diet: g.diet || '', observations: g.observations || '' });
    setEditSelAllergens(g.allergies ? g.allergies.split(',').filter(Boolean) : []);
    setShowAddGuest(null);
  };

  const handleUpdateGuest = async () => {
    if (!editGuestForm.guestName.trim()) { toast.error('El nombre es obligatorio'); return; }
    try {
      await api.put(`/events/${eventId}/tables/${editingGuest.tableId}/guests/${editingGuest.guestId}`, {
        ...editGuestForm, allergies: editSelAllergens.join(','),
      });
      toast.success('Invitado actualizado');
      setEditingGuest(null);
      reload();
    } catch { toast.error('Error al actualizar'); }
  };

  return (
    <div className="space-y-4">
      {tables.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: 'Mesas',     value: tables.length,  color: 'text-stone-900' },
            { label: 'Invitados', value: totalGuests,     color: 'text-stone-900' },
            { label: 'Con alergias', value: totalAlergias, color: totalAlergias > 0 ? 'text-amber-600' : 'text-emerald-600' },
          ].map(i => (
            <div key={i.label} className="card p-4 text-center">
              <p className={`text-2xl font-bold ${i.color}`}>{i.value}</p>
              <p className="text-sm text-stone-500">{i.label}</p>
            </div>
          ))}
        </div>
      )}

      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800">
          Distribución de mesas
          <span className="text-stone-400 font-normal text-sm ml-2">(introducidas por el cliente)</span>
        </h3>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="TABLES_VIEW"
            label="PDF mesas"
            fileName={`mesas-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={TablesPdfDoc}
          />
          <button onClick={() => setShowNewTable(true)} className="btn-primary text-sm">+ Nueva mesa</button>
        </div>
      </div>

      {showNewTable && (
        <div className="card border-blue-100 bg-blue-50/30">
          <h4 className="font-medium mb-3">Nueva mesa</h4>
          <div className="grid grid-cols-2 gap-3 mb-3">
            <div><label className="label">Nombre *</label><input className="input" value={newTable.name} onChange={e => setNewTable(f => ({ ...f, name: e.target.value }))} placeholder="Mesa 1 / Presidencial" /></div>
            <div><label className="label">Capacidad</label><input className="input" type="number" min="1" value={newTable.capacity} onChange={e => setNewTable(f => ({ ...f, capacity: e.target.value }))} placeholder="10" /></div>
            <div className="col-span-2"><label className="label">Observaciones</label><input className="input" value={newTable.notes} onChange={e => setNewTable(f => ({ ...f, notes: e.target.value }))} placeholder="Junto a la pista..." /></div>
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowNewTable(false)} className="btn-secondary">Cancelar</button>
            <button onClick={handleCreateTable} className="btn-primary">Crear mesa</button>
          </div>
        </div>
      )}

      {tables.length === 0 && !showNewTable && (
        <div className="card text-center py-12 text-stone-500">
          El cliente aún no ha configurado mesas, o puedes crearlas tú desde aquí.
        </div>
      )}

      <div className="space-y-4">
        {tables.map(table => {
          const occupancy = table.capacity ? Math.round((table.guestCount / table.capacity) * 100) : null;
          return (
            <div key={table.id} className={`card ${table.allergiesCount > 0 ? 'border-amber-200' : ''}`}>
              <div className="flex items-center justify-between mb-3">
                <div>
                  <div className="flex items-center gap-2 flex-wrap">
                    <h4 className="font-semibold text-stone-900">{table.name}</h4>
                    {table.allergiesCount > 0 && (
                      <span className="badge bg-amber-100 text-amber-700">⚠ {table.allergiesCount} alergia{table.allergiesCount !== 1 ? 's' : ''}</span>
                    )}
                    {table.notes && <span className="text-xs text-stone-400 italic">{table.notes}</span>}
                  </div>
                  <div className="flex items-center gap-3 mt-1">
                    <span className="text-xs text-stone-500">
                      {table.guestCount}{table.capacity ? `/${table.capacity}` : ''} invitado{table.guestCount !== 1 ? 's' : ''}
                    </span>
                    {occupancy !== null && (
                      <div className="w-20 h-1.5 bg-stone-100 rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${occupancy >= 100 ? 'bg-red-500' : occupancy >= 80 ? 'bg-amber-500' : 'bg-emerald-500'}`}
                          style={{ width: `${Math.min(occupancy, 100)}%` }} />
                      </div>
                    )}
                  </div>
                </div>
                <button onClick={() => handleDeleteTable(table.id, table.name)}
                  className="text-stone-300 hover:text-red-500 transition-colors p-1.5 rounded-lg hover:bg-red-50">
                  <Trash2 size={15} />
                </button>
              </div>

              <div className="space-y-1.5">
                {(table.guests || []).map(g => {
                  const isEditingThis = editingGuest?.guestId === g.id;
                  return (
                    <div key={g.id}>
                      {/* Vista normal */}
                      {!isEditingThis && (
                        <div className="flex items-start justify-between p-2.5 bg-stone-50 rounded-xl">
                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-semibold text-stone-900">{g.guestName}</p>
                            <div className="flex flex-wrap gap-1 mt-0.5">
                              {g.diet && <span className="badge bg-violet-100 text-violet-700 text-[10px]">{g.diet.replace('_',' ')}</span>}
                              {g.allergies && g.allergies.split(',').filter(Boolean).map((a, idx) => (
                                <span key={a} className={`badge text-[10px] ${ALLERGEN_BADGE_COLORS[idx % ALLERGEN_BADGE_COLORS.length]}`}>⚠ {ALLERGEN_LABELS_MAP[a] || a}</span>
                              ))}
                              {g.observations && <span className="text-[10px] text-stone-400 italic ml-1">{g.observations}</span>}
                            </div>
                          </div>
                          <div className="flex items-center gap-1 flex-none ml-2">
                            <button onClick={() => startEditGuest(g, table.id)}
                              className="p-1 rounded-lg text-stone-300 hover:text-blue-500 hover:bg-blue-50 transition-colors" title="Editar invitado">
                              <Edit2 size={12} />
                            </button>
                            {tables.filter(t => t.id !== table.id).length > 0 && (
                              <select
                                className="text-xs border border-stone-200 rounded-lg px-1.5 py-1 text-stone-500 bg-white cursor-pointer"
                                defaultValue=""
                                onChange={e => { if (e.target.value) handleMoveGuest(table.id, g.id, parseInt(e.target.value)); e.target.value = ''; }}
                              >
                                <option value="" disabled>Mover ↗</option>
                                {tables.filter(t => t.id !== table.id).map(t => (
                                  <option key={t.id} value={t.id}>{t.name}</option>
                                ))}
                              </select>
                            )}
                            <button onClick={() => handleDeleteGuest(table.id, g.id)}
                              className="text-stone-300 hover:text-red-500 transition-colors p-1 rounded-lg hover:bg-red-50">
                              <Trash2 size={13} />
                            </button>
                          </div>
                        </div>
                      )}

                      {/* Vista edición inline */}
                      {isEditingThis && (
                        <div className="p-3 bg-amber-50 border border-amber-200 rounded-xl space-y-2.5">
                          <div className="flex items-center justify-between">
                            <p className="text-xs font-semibold text-amber-800">✏️ Editando invitado</p>
                            <button onClick={() => setEditingGuest(null)} className="text-stone-400 hover:text-stone-600"><X size={14} /></button>
                          </div>
                          <input className="input text-sm" placeholder="Nombre *" value={editGuestForm.guestName}
                            onChange={e => setEditGuestForm(f => ({ ...f, guestName: e.target.value }))} />
                          <select className="input text-sm" value={editGuestForm.diet}
                            onChange={e => setEditGuestForm(f => ({ ...f, diet: e.target.value }))}>
                            <option value="">Sin dieta especial</option>
                            {DIET_OPTS.map(d => <option key={d} value={d}>{d.replace('_',' ')}</option>)}
                          </select>
                          <div>
                            <label className="label text-[10px] mb-1 block">Alérgenos</label>
                            <div className="flex flex-wrap gap-1">
                              {ALLERGEN_LIST.map(a => (
                                <button key={a} type="button"
                                  onClick={() => setEditSelAllergens(p => p.includes(a) ? p.filter(x => x !== a) : [...p, a])}
                                  className={`px-2 py-0.5 rounded-md text-[10px] font-medium border transition-colors ${editSelAllergens.includes(a) ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'}`}>
                                  {ALLERGEN_LABELS_MAP[a]}
                                </button>
                              ))}
                            </div>
                          </div>
                          <input className="input text-sm" placeholder="Observaciones" value={editGuestForm.observations}
                            onChange={e => setEditGuestForm(f => ({ ...f, observations: e.target.value }))} />
                          <div className="flex gap-2">
                            <button onClick={() => setEditingGuest(null)} className="btn-secondary flex-1 text-xs py-1.5">Cancelar</button>
                            <button onClick={handleUpdateGuest} className="btn-primary flex-1 text-xs py-1.5">Guardar</button>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
                {(!table.guests || table.guests.length === 0) && (
                  <p className="text-xs text-stone-400 italic text-center py-2">Sin invitados asignados</p>
                )}
              </div>

              {showAddGuest !== table.id ? (
                <button
                  onClick={() => { setShowAddGuest(table.id); setSelAllergens([]); setGuestForm({ guestName:'', diet:'', observations:'' }); }}
                  className="mt-3 w-full flex items-center justify-center gap-1.5 py-2 border-2 border-dashed border-stone-200 rounded-xl text-sm text-stone-500 hover:border-rose-300 hover:text-rose-600 transition-all">
                  + Añadir invitado
                </button>
              ) : (
                <div className="mt-3 p-4 bg-stone-50 rounded-2xl space-y-3">
                  <h5 className="font-semibold text-sm text-stone-900">Nuevo invitado en {table.name}</h5>
                  <input className="input" placeholder="Nombre *" value={guestForm.guestName} onChange={e => setGuestForm(f => ({ ...f, guestName: e.target.value }))} />
                  <select className="input" value={guestForm.diet} onChange={e => setGuestForm(f => ({ ...f, diet: e.target.value }))}>
                    <option value="">Sin dieta especial</option>
                    {DIET_OPTS.map(d => <option key={d} value={d}>{d.replace('_',' ')}</option>)}
                  </select>
                  <div>
                    <label className="label text-xs mb-1 block">Alérgenos</label>
                    <div className="flex flex-wrap gap-1.5">
                      {ALLERGEN_LIST.map(a => (
                        <button key={a} type="button"
                          onClick={() => setSelAllergens(p => p.includes(a) ? p.filter(x => x !== a) : [...p, a])}
                          className={`px-2 py-1 rounded-lg text-xs font-medium border transition-colors ${selAllergens.includes(a) ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'}`}>
                          {ALLERGEN_LABELS_MAP[a]}
                        </button>
                      ))}
                    </div>
                  </div>
                  <input className="input" placeholder="Observaciones" value={guestForm.observations} onChange={e => setGuestForm(f => ({ ...f, observations: e.target.value }))} />
                  <div className="flex gap-2">
                    <button onClick={() => setShowAddGuest(null)} className="btn-secondary flex-1 text-sm">Cancelar</button>
                    <button onClick={() => handleAddGuest(table.id)} className="btn-primary flex-1 text-sm">Guardar</button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Planos del Salón ────────────────────────────────────────────────────────
function PlanosTab({ eventId, event }) {
  const [plan,      setPlan]      = useState(null);
  const [planUrl,   setPlanUrl]   = useState(null);
  const [loading,   setLoading]   = useState(true);
  const [uploading, setUploading] = useState(false);
  const [zoom,      setZoom]      = useState(1);
  const fileRef                   = useRef();

  useEffect(() => { loadPlan(); }, []);
  useEffect(() => { return () => { if (planUrl) URL.revokeObjectURL(planUrl); }; }, [planUrl]);

  const loadPlan = async () => {
    setLoading(true);
    try {
      const meta = await api.get(`/events/${eventId}/floorplan/meta`);
      // 204 No Content → sin plano
      if (!meta.data || !meta.data.id) {
        setPlan(null); setPlanUrl(null);
        return;
      }
      setPlan(meta.data);
      const res = await api.get(`/events/${eventId}/floorplan`, { responseType: 'blob' });
      setPlanUrl(URL.createObjectURL(res.data));
    } catch {
      setPlan(null); setPlanUrl(null);
    } finally { setLoading(false); }
  };

  const handleUpload = async (file) => {
    if (!file) return;
    const allowed = ['image/jpeg','image/png','image/webp','application/pdf'];
    if (!allowed.includes(file.type)) { toast.error('Formato no permitido (JPG, PNG, WEBP o PDF)'); return; }
    setUploading(true);
    const fd = new FormData();
    fd.append('file', file);
    try {
      // NO fijar Content-Type: el navegador añade el boundary multipart automáticamente
      await api.post(`/events/${eventId}/floorplan`, fd);
      toast.success('Plano subido correctamente');
      loadPlan();
    } catch (e) {
      const msg = e?.response?.data?.message || e?.response?.data || 'Error al subir el plano';
      toast.error(typeof msg === 'string' ? msg : 'Error al subir el plano');
    } finally { setUploading(false); }
  };

  const handleDelete = async () => {
    if (!confirm('¿Eliminar el plano del salón?')) return;
    try {
      await api.delete(`/events/${eventId}/floorplan`);
      if (planUrl) URL.revokeObjectURL(planUrl);
      setPlan(null); setPlanUrl(null);
      toast.success('Plano eliminado');
    } catch { toast.error('Error al eliminar'); }
  };

  const isImage = plan?.contentType?.startsWith('image/');
  const isPdf   = plan?.contentType === 'application/pdf';
  const fmtSize = b => b < 1024*1024 ? `${(b/1024).toFixed(0)} KB` : `${(b/1024/1024).toFixed(1)} MB`;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <div>
          <h3 className="font-semibold text-stone-800 flex items-center gap-2"><Map size={18} className="text-stone-500" /> Plano del salón</h3>
          <p className="text-xs text-stone-500 mt-0.5">Sube el plano para consulta del equipo de sala</p>
        </div>
        {plan && (
          <div className="flex items-center gap-2">
            <button onClick={() => fileRef.current?.click()}
              className="btn-secondary text-sm inline-flex items-center gap-1.5"><RotateCcw size={14} /> Reemplazar</button>
            <button onClick={handleDelete}
              className="inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium text-red-600 bg-red-50 hover:bg-red-100 border border-red-200 rounded-xl transition-colors">
              <Trash2 size={14} /> Eliminar
            </button>
          </div>
        )}
      </div>

      <input ref={fileRef} type="file" accept=".jpg,.jpeg,.png,.webp,.pdf"
        className="hidden" onChange={e => handleUpload(e.target.files?.[0])} />

      {loading && (
        <div className="card flex items-center justify-center py-20">
          <div className="w-8 h-8 border-2 border-rose-200 border-t-rose-600 rounded-full animate-spin" />
        </div>
      )}

      {!loading && !plan && (
        <div
          onClick={() => fileRef.current?.click()}
          onDragOver={e => e.preventDefault()}
          onDrop={e => { e.preventDefault(); handleUpload(e.dataTransfer.files?.[0]); }}
          className="card border-2 border-dashed border-stone-300 hover:border-rose-400 cursor-pointer transition-all py-20 text-center">
          {uploading
            ? <p className="text-stone-500 text-sm animate-pulse">Subiendo plano...</p>
            : <>
                <Upload size={36} className="text-stone-300 mx-auto mb-3" />
                <p className="font-semibold text-stone-600 mb-1">Arrastra el plano aquí o haz clic</p>
                <p className="text-sm text-stone-400">JPG · PNG · WEBP · PDF · máx 20 MB</p>
              </>}
        </div>
      )}

      {!loading && plan && planUrl && (
        <>
          <div className="flex items-center gap-3 p-3 bg-stone-50 border border-stone-200 rounded-xl text-sm text-stone-600 flex-wrap">
            <span className="font-medium truncate max-w-xs">{plan.filename}</span>
            <span className="text-stone-400">·</span>
            <span className="text-stone-400">{plan.contentType}</span>
            {plan.fileSize && <><span className="text-stone-400">·</span><span>{fmtSize(plan.fileSize)}</span></>}
          </div>

          {isImage && (
            <div className="flex items-center gap-2">
              <button onClick={() => setZoom(z => Math.max(0.25, z - 0.25))} className="p-2 rounded-lg border border-stone-200 hover:bg-stone-100 transition-colors"><ZoomOut size={16} className="text-stone-600" /></button>
              <span className="text-sm text-stone-500 w-14 text-center">{Math.round(zoom * 100)}%</span>
              <button onClick={() => setZoom(z => Math.min(4, z + 0.25))} className="p-2 rounded-lg border border-stone-200 hover:bg-stone-100 transition-colors"><ZoomIn size={16} className="text-stone-600" /></button>
              <button onClick={() => setZoom(1)} className="px-3 py-2 rounded-lg border border-stone-200 hover:bg-stone-100 transition-colors text-xs text-stone-500">Restablecer</button>
            </div>
          )}

          {isImage && (
            <div className="overflow-auto rounded-2xl border border-stone-200 bg-stone-100 max-h-[70vh]">
              <div style={{ width: `${Math.max(100, zoom * 100)}%` }} className="flex items-start justify-center p-4">
                <img src={planUrl} alt="Plano del salón" style={{ transform: `scale(${zoom})`, transformOrigin: 'top left', transition: 'transform 0.2s', maxWidth: '100%' }} className="rounded-lg shadow-sm" />
              </div>
            </div>
          )}

          {isPdf && (
            <div className="rounded-2xl border border-stone-200 overflow-hidden" style={{ height: '70vh' }}>
              <iframe src={planUrl} title="Plano PDF" className="w-full h-full" style={{ border: 'none' }} />
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { ArrowLeft, Music2, Layers, ChefHat, UserPlus, Trash2, Edit2, X, AlertTriangle, Table2, Map, ZoomIn, ZoomOut, Upload, RotateCcw, Download } from 'lucide-react';
import PdfDownloadButton from '../../components/PdfDownloadButton';
import ProtocolPdfDoc  from '../../components/pdf/ProtocolPdfDoc';
import TablesPdfDoc    from '../../components/pdf/TablesPdfDoc';
import AllergensPdfDoc from '../../components/pdf/AllergensPdfDoc';
import MenusPdfDoc     from '../../components/pdf/MenusPdfDoc';
import InvoicePdfDoc   from '../../components/pdf/InvoicePdfDoc';
import { useAuth } from '../../context/AuthContext';

const TABS = [
  { id: 'info',         label: 'Información' },
  { id: 'asignaciones', label: 'Personal'     },
  { id: 'menus',        label: 'Menús'        },
  { id: 'allergens',    label: 'Alérgenos'    },
  { id: 'protocol',     label: 'Protocolo'    },
  { id: 'mesas',        label: 'Mesas'        },
  { id: 'planos',       label: 'Planos'       },
  { id: 'invoice',      label: 'Facturación'  },
  { id: 'reminders',    label: 'Recordatorios'},
];

const STATUS_OPTIONS = ['BORRADOR','PENDIENTE_INFO','EN_CURSO','CONFIRMADO','COMPLETADO','CANCELADO'];
const STATUS_LABELS = { BORRADOR:'Borrador', PENDIENTE_INFO:'Pendiente info', EN_CURSO:'En curso', CONFIRMADO:'Confirmado', COMPLETADO:'Completado', CANCELADO:'Cancelado' };

export default function EventDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { hasPermission } = useAuth();
  const [tab, setTab] = useState('info');
  const [event, setEvent] = useState(null);
  const [menus, setMenus] = useState([]);
  const [allergens, setAllergens] = useState([]);
  const [protocol, setProtocol] = useState([]);
  const [invoice, setInvoice] = useState(null);
  const [assignments, setAssignments] = useState([]);
  const [staff, setStaff] = useState([]);
  const [tables, setTables] = useState([]);

  const loadEvent       = () => api.get(`/events/${id}`).then(r => setEvent(r.data));
  const loadMenus       = () => api.get(`/events/${id}/menus`).then(r => setMenus(r.data));
  const loadAllergens   = () => api.get(`/events/${id}/allergens`).then(r => setAllergens(r.data));
  const loadProtocol    = () => api.get(`/events/${id}/protocol`).then(r => setProtocol(r.data));
  const loadInvoice     = () => api.get(`/events/${id}/invoice`).then(r => setInvoice(r.data)).catch(() => setInvoice(null));
  const loadAssignments = () => api.get(`/events/${id}/assignments`).then(r => setAssignments(r.data));
  const loadStaff       = () => api.get('/users/staff').then(r => setStaff(r.data)).catch(() => {});
  const loadTables      = () => api.get(`/events/${id}/tables`).then(r => setTables(r.data)).catch(() => {});

  useEffect(() => {
    loadEvent(); loadMenus(); loadAllergens(); loadProtocol();
    loadInvoice(); loadAssignments(); loadStaff(); loadTables();
  }, [id]);

  if (!event) return <Layout><div className="animate-pulse text-center p-20 text-stone-400">Cargando...</div></Layout>;

  const handleStatusChange = async (status) => {
    try {
      await api.patch(`/events/${id}/status`, { status });
      setEvent(ev => ({ ...ev, status, statusLabel: STATUS_LABELS[status] }));
      toast.success('Estado actualizado');
    } catch { toast.error('Error al actualizar estado'); }
  };

  const sendReminder = async (channel) => {
    const message = `Hola ${event.clientName}, le recordamos que tiene pendiente completar información para su evento. Acceda al portal: http://localhost:5173/login`;
    try {
      await api.post(`/dashboard/send-reminder/${id}`, { message, channel, subject: 'Recordatorio de su evento' });
      toast.success(`Recordatorio enviado por ${channel}`);
    } catch { toast.error('Error enviando recordatorio'); }
  };

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
          <div className="flex items-center gap-3">
            <button onClick={() => navigate('/admin/eventos')}
              className="flex items-center gap-1 text-stone-400 hover:text-stone-600 transition-colors">
              <ArrowLeft size={18} />
            </button>
            <div>
              <h1 className="text-2xl font-bold text-stone-900">{event.clientName}</h1>
              <p className="text-stone-500">
                {event.typeLabel} · {new Date(event.eventDate).toLocaleDateString('es-ES', { weekday:'long', year:'numeric', month:'long', day:'numeric' })}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <select value={event.status} onChange={e => handleStatusChange(e.target.value)} className="input w-auto text-sm">
              {STATUS_OPTIONS.map(s => <option key={s} value={s}>{STATUS_LABELS[s]}</option>)}
            </select>
          </div>
        </div>

        {/* Completitud */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {[
            { ok: event.menuConfirmed,      label: 'Menú confirmado',       icon: '️' },
            { ok: event.allergensCompleted, label: 'Alérgenos registrados', icon: '⚠️' },
            { ok: event.protocolCompleted,  label: 'Protocolo completo',    icon: '' },
            { ok: event.budgetSigned,       label: 'Presupuesto firmado',   icon: '✍️' },
          ].map(item => (
            <div key={item.label} className={`card p-4 text-center ${item.ok ? 'border-emerald-200 bg-emerald-50' : 'border-amber-200 bg-amber-50'}`}>
              <div className="text-2xl mb-1">{item.icon}</div>
              <p className={`text-xs font-medium ${item.ok ? 'text-emerald-700' : 'text-amber-700'}`}>
                {item.ok ? '✅' : '⚠️'} {item.label}
              </p>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div className="border-b border-stone-200">
          <div className="flex gap-1 overflow-x-auto">
            {TABS.map(t => (
              <button key={t.id} onClick={() => setTab(t.id)}
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                  tab === t.id ? 'border-rose-600 text-rose-600' : 'border-transparent text-stone-500 hover:text-stone-700'
                }`}>
                {t.label}
              </button>
            ))}
          </div>
        </div>

        {/* Tab content */}
        {tab === 'info'         && <InfoTab event={event} />}
        {tab === 'asignaciones' && <AsignacionesTab eventId={id} assignments={assignments} staff={staff} reload={loadAssignments} />}
        {tab === 'menus'        && <MenusTab eventId={id} event={event} menus={menus} reload={loadMenus} />}
        {tab === 'allergens'    && <AllergensTab eventId={id} event={event} tables={tables} reload={() => { loadTables(); loadEvent(); }} onGoToMesas={() => setTab('mesas')} />}
        {tab === 'protocol'     && <ProtocolTab eventId={id} event={event} items={protocol} reload={() => { loadProtocol(); loadEvent(); }} />}
        {tab === 'mesas'        && <MesasAdminTab eventId={id} event={event} tables={tables} reload={() => { loadTables(); loadEvent(); }} />}
        {tab === 'planos'       && <PlanosTab eventId={id} event={event} hasPermission={hasPermission} />}
        {tab === 'invoice'      && <InvoiceTab eventId={id} event={event} invoice={invoice} reload={loadInvoice} />}
        {tab === 'reminders'    && <RemindersTab event={event} onSend={sendReminder} />}
      </div>
    </Layout>
  );
}

// -- Tab Components --

// ── Constantes compartidas ─────────────────────────────────────────────────────
const ALLERGEN_LIST = ['GLUTEN','LACTEOS','HUEVOS','FRUTOS_SECOS','CACAHUETES','SOJA','MARISCO','PESCADO','MOSTAZA','APIO','SESAMO','SULFITOS','MOLUSCOS','ALTRAMUZ'];
const ALLERGEN_LABELS_MAP = { GLUTEN:'Gluten/Celíaco', LACTEOS:'Lácteos', HUEVOS:'Huevos', FRUTOS_SECOS:'Frutos secos', CACAHUETES:'Cacahuetes', SOJA:'Soja', MARISCO:'Marisco', PESCADO:'Pescado', MOSTAZA:'Mostaza', APIO:'Apio', SESAMO:'Sésamo', SULFITOS:'Sulfitos', MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuces' };
const ALLERGEN_BADGE_COLORS = ['bg-amber-50 text-amber-700 border border-amber-200','bg-red-50 text-red-700 border border-red-200','bg-orange-50 text-orange-700 border border-orange-200','bg-yellow-50 text-yellow-700 border border-yellow-200'];
const DIET_COLORS = { VEGETARIANO:'bg-green-100 text-green-700', VEGANO:'bg-emerald-100 text-emerald-700', HALAL:'bg-teal-100 text-teal-700', KOSHER:'bg-cyan-100 text-cyan-700', SIN_SAL:'bg-sky-100 text-sky-700', DIABETICO:'bg-blue-100 text-blue-700' };

function InfoTab({ event }) {
  return (
    <div className="card">
      <h3 className="font-semibold text-stone-800 mb-4">Datos del evento</h3>
      <dl className="grid grid-cols-1 sm:grid-cols-2 gap-y-4 gap-x-8 text-sm">
        {[
          { label: 'Cliente',             value: event.clientName        },
          { label: 'Tipo',                value: event.typeLabel         },
          { label: 'Fecha',               value: new Date(event.eventDate).toLocaleDateString('es-ES') },
          { label: 'Invitados estimados', value: event.estimatedGuests   },
          { label: 'Salón',               value: event.venue             },
          { label: 'Contacto',            value: event.contactPerson     },
          { label: 'Teléfono',            value: event.phone             },
          { label: 'Email',               value: event.email             },
          { label: 'Acceso cliente',      value: event.clientUsername    },
        ].map(item => item.value ? (
          <div key={item.label}>
            <dt className="text-stone-500">{item.label}</dt>
            <dd className="font-medium text-stone-900">{item.value}</dd>
          </div>
        ) : null)}
      </dl>
      {event.notes && (
        <div className="mt-4 pt-4 border-t border-stone-100">
          <p className="text-stone-500 text-sm mb-1">Notas internas</p>
          <p className="text-stone-700 text-sm">{event.notes}</p>
        </div>
      )}
    </div>
  );
}

function AsignacionesTab({ eventId, assignments, staff, reload }) {
  const [selectedUser, setSelectedUser] = useState('');

  const ROLE_ICONS  = { DJ: Music2, FLOOR: Layers, KITCHEN: ChefHat };
  const ROLE_COLORS = { DJ:'bg-blue-100 text-blue-700', FLOOR:'bg-emerald-100 text-emerald-700', KITCHEN:'bg-orange-100 text-orange-700', OFFICE:'bg-violet-100 text-violet-700' };
  const ROLE_LABELS = { DJ:'DJ', FLOOR:'Sala/Metres', KITCHEN:'Cocina', OFFICE:'Oficina' };

  const assignedIds = assignments.map(a => a.userId);
  const available   = staff.filter(u => !assignedIds.includes(u.id) && u.role !== 'OFFICE' && u.role !== 'CLIENT');

  const handleAssign = async () => {
    if (!selectedUser) { toast.error('Selecciona un usuario'); return; }
    try {
      await api.post(`/events/${eventId}/assignments`, { userId: parseInt(selectedUser) });
      reload(); setSelectedUser(''); toast.success('Personal asignado ?');
    } catch { toast.error('Error al asignar'); }
  };

  const handleRemove = async (userId, nombre) => {
    if (!confirm(`¿Quitar a "${nombre}" de este evento?`)) return;
    try {
      await api.delete(`/events/${eventId}/assignments/${userId}`);
      reload(); toast.success('Asignación eliminada');
    } catch { toast.error('Error'); }
  };

  return (
    <div className="space-y-5">
      <div className="card">
        <h3 className="font-semibold text-stone-900 mb-4 flex items-center gap-2">
          <UserPlus size={18} className="text-stone-500" />
          Asignar personal a este evento
        </h3>
        {available.length === 0 ? (
          <p className="text-sm text-stone-400">Todo el personal disponible ya está asignado.</p>
        ) : (
          <div className="flex gap-3">
            <select className="input flex-1" value={selectedUser} onChange={e => setSelectedUser(e.target.value)}>
              <option value="">Seleccionar persona...</option>
              {available.map(u => (
                <option key={u.id} value={u.id}>{u.nombre} ({ROLE_LABELS[u.role] || u.role})</option>
              ))}
            </select>
            <button onClick={handleAssign} className="btn-primary flex-none">
              <UserPlus size={16} /> Asignar
            </button>
          </div>
        )}
      </div>

      {assignments.length === 0 ? (
        <div className="card text-center py-12">
          <UserPlus size={36} className="text-stone-300 mx-auto mb-3" />
          <p className="text-stone-500 font-medium">Sin personal asignado</p>
          <p className="text-stone-400 text-sm mt-1">Asigna DJ, metres o cocina para que puedan ver este evento en su panel.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {assignments.map(a => {
            const Icon = ROLE_ICONS[a.role] || UserPlus;
            return (
              <div key={a.id} className="card p-4 flex items-center gap-3 group">
                <div className={`w-10 h-10 rounded-xl ${ROLE_COLORS[a.role]} flex items-center justify-center flex-none`}>
                  <Icon size={16} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-stone-900 text-sm">{a.nombre}</p>
                  <p className="text-xs text-stone-400">@{a.username}</p>
                  <span className={`badge ${ROLE_COLORS[a.role]} text-xs mt-0.5`}>{ROLE_LABELS[a.role] || a.role}</span>
                </div>
                <button onClick={() => handleRemove(a.userId, a.nombre)}
                  className="opacity-0 group-hover:opacity-100 transition-opacity btn-ghost p-1.5 hover:text-red-600 hover:bg-red-50 rounded-lg">
                  <Trash2 size={14} className="text-stone-400" />
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function MenusTab({ eventId, event, menus, reload }) {
  const [form, setForm] = useState({ name:'', description:'', starters:'', firstCourse:'', secondCourse:'', dessert:'', drinks:'', extras:'' });
  const [showForm, setShowForm] = useState(false);

  const handleCreate = async () => {
    try {
      await api.post(`/events/${eventId}/menus`, form);
      reload(); setShowForm(false);
      setForm({ name:'', description:'', starters:'', firstCourse:'', secondCourse:'', dessert:'', drinks:'', extras:'' });
      toast.success('Menú creado');
    } catch { toast.error('Error al crear menú'); }
  };
  const handleSelect = async (menuId) => {
try { await api.post(`/events/${eventId}/menus/${menuId}/select`); reload(); toast.success('Menú seleccionado'); }
    catch { toast.error('Error'); }
  };
  const handleDelete = async (menuId) => {
    if (!confirm('¿Eliminar menú?')) return;
    try { await api.delete(`/events/${eventId}/menus/${menuId}`); reload(); toast.success('Menú eliminado'); }
    catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/menus`);
    return { event, menus: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800">Menús del evento</h3>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="PDF_MENUS"
            label="PDF menús"
            fileName={`menus-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={MenusPdfDoc}
          />
          <button onClick={() => setShowForm(!showForm)} className="btn-primary text-sm">+ Añadir menú</button>
        </div>
      </div>
      {showForm && (
        <div className="card border-rose-100">
          <h4 className="font-medium mb-3">Nuevo menú</h4>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {[['name','Nombre *'],['starters','Entrantes'],['firstCourse','Primer plato'],['secondCourse','Segundo plato'],['dessert','Postre'],['drinks','Bebidas'],['extras','Extras']].map(([k,l]) => (
              <div key={k}>
                <label className="label">{l}</label>
                <textarea className="input" rows={2} value={form[k]||''} onChange={e => setForm(f=>({...f,[k]:e.target.value}))} />
              </div>
            ))}
          </div>
          <div className="flex gap-3 mt-4">
            <button onClick={() => setShowForm(false)} className="btn-secondary">Cancelar</button>
            <button onClick={handleCreate} className="btn-primary">Guardar menú</button>
          </div>
        </div>
      )}
      {menus.length === 0 && !showForm && <p className="text-stone-500 text-sm">No hay menús. Añade uno para que el cliente pueda seleccionar.</p>}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {menus.map(m => (
          <div key={m.id} className={`card ${m.selected ? 'border-emerald-400 bg-emerald-50' : ''}`}>
            <div className="flex justify-between items-start mb-3">
              <h4 className="font-semibold">{m.name}</h4>
              {m.selected && <span className="badge bg-emerald-100 text-emerald-700">✅ Seleccionado</span>}
            </div>
            {[['Entrantes',m.starters],['1er plato',m.firstCourse],['2do plato',m.secondCourse],['Postre',m.dessert],['Bebidas',m.drinks],['Extras',m.extras]].filter(([,v])=>v).map(([l,v])=>(
              <p key={l} className="text-sm text-stone-600 mb-1"><span className="font-medium">{l}:</span> {v}</p>
            ))}
            <div className="flex gap-2 mt-4">
              {!m.selected && <button onClick={() => handleSelect(m.id)} className="btn-success text-sm flex-1">Seleccionar</button>}
              <button onClick={() => handleDelete(m.id)} className="btn-danger text-sm">Eliminar</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function AllergensTab({ eventId, event, tables, reload, onGoToMesas }) {
  // ── Estado del formulario "Añadir alérgeno" ──────────────────────────────
  const [showForm,         setShowForm]        = useState(false);
  const [formMesaId,       setFormMesaId]      = useState('');
  const [formGuestId,      setFormGuestId]     = useState('');
  const [newAllergies,     setNewAllergies]    = useState([]);
  const [newDiet,          setNewDiet]         = useState('');
  const [newObs,           setNewObs]          = useState('');

  // ── Estado de edición inline ──────────────────────────────────────────────
  const [editingId,  setEditingId]  = useState(null);
  const [editForm,   setEditForm]   = useState({ allergies: [], diet: '', observations: '' });
  const [saving,     setSaving]     = useState(false);

  // ── Datos derivados ───────────────────────────────────────────────────────
  const allGuests = tables.flatMap(t =>
    (t.guests || []).map(g => ({ ...g, tableName: t.name, tableId: t.id }))
  );
  // Solo mesas con al menos un invitado con restricción
  const tablesWithRestrictions = tables.filter(t =>
    (t.guests || []).some(g => g.allergies || g.diet)
  );
  const withRestrictionsCount = allGuests.filter(g => g.allergies || g.diet).length;

  // Invitados de la mesa seleccionada en el formulario (para el step 2)
  const guestsInFormMesa = formMesaId
    ? (tables.find(t => t.id === parseInt(formMesaId))?.guests || [])
    : [];

  // ── Formulario "Añadir" ───────────────────────────────────────────────────
  const openForm = () => {
    setShowForm(true); setFormMesaId(''); setFormGuestId('');
    setNewAllergies([]); setNewDiet(''); setNewObs('');
  };
  const toggleNew = a =>
    setNewAllergies(p => p.includes(a) ? p.filter(x => x !== a) : [...p, a]);

  const handleAdd = async () => {
    if (!formGuestId) { toast.error('Selecciona un invitado'); return; }
    const mesa  = tables.find(t => t.id === parseInt(formMesaId));
    const guest = (mesa?.guests || []).find(g => g.id === parseInt(formGuestId));
    if (!guest) return;
    if (!newAllergies.length && !newDiet) { toast.error('Selecciona al menos un alérgeno o dieta'); return; }
    setSaving(true);
    try {
      await api.put(`/events/${eventId}/tables/${mesa.id}/guests/${guest.id}`, {
        guestName: guest.guestName,
        allergies: newAllergies.join(','),
        diet: newDiet,
        observations: newObs,
      });
      toast.success('Alérgenos asignados');
      setShowForm(false);
      reload();
    } catch { toast.error('Error al guardar'); }
    finally { setSaving(false); }
  };

  // ── Edición inline ────────────────────────────────────────────────────────
  const startEdit = g => {
    setEditingId(g.id);
    setEditForm({
      allergies:    g.allergies ? g.allergies.split(',').filter(Boolean) : [],
      diet:         g.diet || '',
      observations: g.observations || '',
    });
  };
  const toggleEdit = a =>
    setEditForm(f => ({
      ...f,
      allergies: f.allergies.includes(a) ? f.allergies.filter(x => x !== a) : [...f.allergies, a],
    }));

  const handleSave = async g => {
    setSaving(true);
    try {
      await api.put(`/events/${eventId}/tables/${g.tableId}/guests/${g.id}`, {
        guestName: g.guestName,
        allergies: editForm.allergies.join(','),
        diet:      editForm.diet,
        observations: editForm.observations,
      });
      toast.success('Actualizado');
      setEditingId(null);
      reload();
    } catch { toast.error('Error al guardar'); }
    finally { setSaving(false); }
  };

  const handleClear = async g => {
    if (!confirm(`¿Eliminar las restricciones de ${g.guestName}?`)) return;
    try {
      await api.put(`/events/${eventId}/tables/${g.tableId}/guests/${g.id}`,
        { guestName: g.guestName, allergies: '', diet: '', observations: '' });
      toast.success('Restricciones eliminadas');
      reload();
    } catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/allergens`);
    return { event, allergens: r.data.filter(x => x.allergies || x.diet) };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  // ── Guards ────────────────────────────────────────────────────────────────
  if (tables.length === 0) return (
    <div className="card text-center py-16">
      <AlertTriangle size={40} className="text-stone-300 mx-auto mb-4" />
      <h3 className="font-semibold text-stone-700 mb-2">Sin mesas creadas</h3>
      <p className="text-stone-500 text-sm mb-5">Primero debes crear mesas e invitados antes de gestionar alérgenos.</p>
      <button onClick={onGoToMesas} className="btn-primary text-sm inline-flex items-center gap-2 mx-auto">
        <Table2 size={14} /> Ir a Mesas
      </button>
    </div>
  );

  if (allGuests.length === 0) return (
    <div className="card text-center py-16">
      <AlertTriangle size={40} className="text-stone-300 mx-auto mb-4" />
      <h3 className="font-semibold text-stone-700 mb-2">Sin invitados</h3>
      <p className="text-stone-500 text-sm mb-5">Añade invitados en la pestaña Mesas para gestionar sus alérgenos.</p>
      <button onClick={onGoToMesas} className="btn-primary text-sm inline-flex items-center gap-2 mx-auto">
        <Table2 size={14} /> Ir a Mesas
      </button>
    </div>
  );

  // ── Render principal ──────────────────────────────────────────────────────
  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex justify-between items-center flex-wrap gap-2">
        <div>
          <h3 className="font-semibold text-stone-800">Alérgenos y dietas especiales</h3>
          <p className="text-xs text-stone-500 mt-0.5">
            {withRestrictionsCount > 0
              ? `${withRestrictionsCount} de ${allGuests.length} invitados con restricciones`
              : 'Ningún invitado tiene restricciones todavía'}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="PDF_ALLERGENS"
            label="PDF alérgenos"
            fileName={`alergenos-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={AllergensPdfDoc}
          />
          <button onClick={openForm}
            className="btn-primary text-sm inline-flex items-center gap-1.5">
            + Añadir alérgeno
          </button>
        </div>
      </div>

      {/* ── Formulario 3 pasos ── */}
      {showForm && (
        <div className="card border-amber-200 bg-amber-50/30 space-y-4">
          <div className="flex items-center justify-between">
            <h4 className="font-semibold text-stone-800">Asignar alérgenos a un invitado</h4>
            <button onClick={() => setShowForm(false)} className="text-stone-400 hover:text-stone-600"><X size={16} /></button>
          </div>

          {/* Paso 1 — Mesa */}
          <div>
            <label className="label">Paso 1 — Selecciona la mesa</label>
            <select className="input"
              value={formMesaId}
              onChange={e => { setFormMesaId(e.target.value); setFormGuestId(''); }}>
              <option value="">— Seleccionar mesa —</option>
              {tables.map(t => (
                <option key={t.id} value={t.id}>
                  {t.name}{t.guestCount ? ` (${t.guestCount} inv.)` : ''}
                </option>
              ))}
            </select>
          </div>

          {/* Paso 2 — Invitado */}
          {formMesaId && (
            <div>
              <label className="label">Paso 2 — Selecciona el invitado</label>
              {guestsInFormMesa.length === 0
                ? <p className="text-sm text-stone-400 italic">Esta mesa no tiene invitados registrados.</p>
                : (
                  <select className="input" value={formGuestId} onChange={e => setFormGuestId(e.target.value)}>
                    <option value="">— Seleccionar invitado —</option>
                    {guestsInFormMesa.map(g => (
                      <option key={g.id} value={g.id}>
                        {g.guestName}{(g.allergies || g.diet) ? ' ⚠' : ''}
                      </option>
                    ))}
                  </select>
                )}
            </div>
          )}

          {/* Paso 3 — Alérgenos */}
          {formGuestId && (
            <>
              <div>
                <label className="label">Paso 3 — Alérgenos</label>
                <div className="flex flex-wrap gap-1.5 mt-1">
                  {ALLERGEN_LIST.map(a => (
                    <button key={a} type="button" onClick={() => toggleNew(a)}
                      className={`px-2 py-1 rounded-lg text-xs font-medium border transition-colors ${
                        newAllergies.includes(a)
                          ? 'bg-amber-500 text-white border-amber-500'
                          : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'
                      }`}>
                      {ALLERGEN_LABELS_MAP[a]}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label className="label">Dieta especial</label>
                <select className="input" value={newDiet} onChange={e => setNewDiet(e.target.value)}>
                  <option value="">Ninguna</option>
                  {['VEGETARIANO','VEGANO','HALAL','KOSHER','SIN_SAL','DIABETICO'].map(d => (
                    <option key={d} value={d}>{d.replace('_', ' ')}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="label">Observaciones</label>
                <input className="input" value={newObs}
                  onChange={e => setNewObs(e.target.value)}
                  placeholder="Alergia muy grave, llevar EpiPen..." />
              </div>
            </>
          )}

          <div className="flex gap-3 pt-1">
            <button onClick={() => setShowForm(false)} className="btn-secondary flex-1">Cancelar</button>
            <button onClick={handleAdd} disabled={!formGuestId || saving}
              className="btn-primary flex-1">
              {saving ? 'Guardando...' : 'Guardar'}
            </button>
          </div>
        </div>
      )}

      {/* Sin restricciones todavía */}
      {tablesWithRestrictions.length === 0 && !showForm && (
        <div className="card text-center py-10">
          <div className="text-3xl mb-3">✅</div>
          <p className="text-stone-500 text-sm">Ningún invitado tiene restricciones registradas.</p>
          <p className="text-stone-400 text-xs mt-1">Usa "+ Añadir alérgeno" para registrar la primera.</p>
        </div>
      )}

      {/* ── Listado: solo mesas con restricciones, solo invitados con restricciones ── */}
      {tablesWithRestrictions.map(table => {
        const restricted = (table.guests || [])
          .filter(g => g.allergies || g.diet)
          .map(g => ({ ...g, tableId: table.id, tableName: table.name }));

        return (
          <div key={table.id} className="card border-amber-100">
            <div className="flex items-center gap-2 mb-3">
              <span className="text-sm font-bold text-stone-800"> {table.name}</span>
              <span className="badge bg-amber-100 text-amber-700 text-[10px]">
                ⚠ {restricted.length} restricción{restricted.length !== 1 ? 'es' : ''}
              </span>
              <span className="ml-auto text-xs text-stone-400">
                {(table.guests || []).length} inv. en total
              </span>
            </div>

            <div className="space-y-2">
              {restricted.map(g => {
                const isEditing = editingId === g.id;
                return (
                  <div key={g.id}
                    className={`rounded-xl border transition-all ${isEditing ? 'border-amber-200 bg-amber-50/40' : 'border-stone-100 bg-stone-50'}`}>

                    {!isEditing && (
                      <div className="flex items-start justify-between p-3 gap-2">
                        <div className="flex-1 min-w-0">
                          <p className="font-semibold text-sm text-stone-900">{g.guestName}</p>
                          <div className="flex flex-wrap gap-1 mt-1">
                            {g.diet && (
                              <span className={`badge text-[10px] ${DIET_COLORS[g.diet] || 'bg-purple-100 text-purple-700'}`}>
                                {g.diet.replace('_', ' ')}
                              </span>
                            )}
                            {g.allergies && g.allergies.split(',').filter(Boolean).map((a, idx) => (
                              <span key={a} className={`badge text-[10px] ${ALLERGEN_BADGE_COLORS[idx % ALLERGEN_BADGE_COLORS.length]}`}>
                                ⚠ {ALLERGEN_LABELS_MAP[a] || a}
                              </span>
                            ))}
                          </div>
                          {g.observations && <p className="text-[10px] text-stone-400 italic mt-1">{g.observations}</p>}
                        </div>
                        <div className="flex items-center gap-1 flex-none">
                          <button onClick={() => startEdit(g)}
                            className="p-1.5 rounded-lg text-stone-400 hover:text-blue-600 hover:bg-blue-50 transition-colors" title="Editar">
                            <Edit2 size={13} />
                          </button>
                          <button onClick={() => handleClear(g)}
                            className="p-1.5 rounded-lg text-stone-400 hover:text-red-600 hover:bg-red-50 transition-colors" title="Eliminar restricciones">
                            <X size={13} />
                          </button>
                        </div>
                      </div>
                    )}

                    {isEditing && (
                      <div className="p-4 space-y-3">
                        <div className="flex items-center justify-between">
                          <p className="font-semibold text-sm text-stone-900">✏️ {g.guestName}</p>
                          <button onClick={() => setEditingId(null)} className="text-stone-400 hover:text-stone-600"><X size={15} /></button>
                        </div>
                        <div>
                          <label className="label text-xs mb-1.5 block">Alérgenos</label>
                          <div className="flex flex-wrap gap-1.5">
                            {ALLERGEN_LIST.map(a => (
                              <button key={a} type="button" onClick={() => toggleEdit(a)}
                                className={`px-2 py-1 rounded-lg text-[11px] font-medium border transition-colors ${
                                  editForm.allergies.includes(a)
                                    ? 'bg-amber-500 text-white border-amber-500'
                                    : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'
                                }`}>
                                {ALLERGEN_LABELS_MAP[a]}
                              </button>
                            ))}
                          </div>
                        </div>
                        <div>
                          <label className="label text-xs mb-1 block">Dieta especial</label>
                          <select className="input text-sm" value={editForm.diet}
                            onChange={e => setEditForm(f => ({ ...f, diet: e.target.value }))}>
                            <option value="">Ninguna</option>
                            {['VEGETARIANO','VEGANO','HALAL','KOSHER','SIN_SAL','DIABETICO'].map(d => (
                              <option key={d} value={d}>{d.replace('_', ' ')}</option>
                            ))}
                          </select>
                        </div>
                        <div>
                          <label className="label text-xs mb-1 block">Observaciones</label>
                          <input className="input text-sm" value={editForm.observations}
                            onChange={e => setEditForm(f => ({ ...f, observations: e.target.value }))}
                            placeholder="Alergia muy grave, llevar EpiPen..." />
                        </div>
                        <div className="flex gap-2 pt-1">
                          <button onClick={() => setEditingId(null)} className="btn-secondary flex-1 text-sm">Cancelar</button>
                          <button onClick={() => handleSave(g)} disabled={saving} className="btn-primary flex-1 text-sm">
                            {saving ? 'Guardando...' : 'Guardar'}
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function ProtocolTab({ eventId, event, items, reload }) {
  const [form, setForm] = useState({ eventTime:'', description:'', involvedPerson:'', youtubeLink:'', observations:'' });
  const [showForm, setShowForm] = useState(false);

  const handleCreate = async () => {
    try {
      await api.post(`/events/${eventId}/protocol`, { ...form, position: items.length + 1 });
      reload(); setShowForm(false);
      setForm({ eventTime:'', description:'', involvedPerson:'', youtubeLink:'', observations:'' });
      toast.success('Momento añadido');
    } catch { toast.error('Error'); }
  };
  const handleDelete = async (itemId) => {
    try { await api.delete(`/events/${eventId}/protocol/${itemId}`); reload(); }
    catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/protocol`);
    return { event, protocol: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800">Protocolo del evento</h3>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="PDF_PROTOCOL"
            label="PDF protocolo"
            fileName={`protocolo-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={ProtocolPdfDoc}
          />
          <button onClick={() => setShowForm(!showForm)} className="btn-primary text-sm">+ Añadir momento</button>
        </div>
      </div>
      {showForm && (
        <div className="card border-blue-100">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <div><label className="label">Hora</label><input className="input" type="time" value={form.eventTime} onChange={e=>setForm(f=>({...f,eventTime:e.target.value}))} /></div>
            <div><label className="label">Descripción *</label><input className="input" value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))} placeholder="Entrada de los novios" /></div>
            <div><label className="label">Persona implicada</label><input className="input" value={form.involvedPerson} onChange={e=>setForm(f=>({...f,involvedPerson:e.target.value}))} /></div>
            <div><label className="label">Enlace YouTube / Canción</label><input className="input" value={form.youtubeLink} onChange={e=>setForm(f=>({...f,youtubeLink:e.target.value}))} placeholder="https://youtube.com/..." /></div>
            <div className="sm:col-span-2"><label className="label">Observaciones</label><input className="input" value={form.observations} onChange={e=>setForm(f=>({...f,observations:e.target.value}))} /></div>
          </div>
          <div className="flex gap-3 mt-4">
            <button onClick={() => setShowForm(false)} className="btn-secondary">Cancelar</button>
            <button onClick={handleCreate} className="btn-primary">Guardar</button>
          </div>
        </div>
      )}
      {items.length === 0 && !showForm && <p className="text-stone-500 text-sm">No hay protocolo definido.</p>}
      <div className="relative">
        {items.map((item, i) => (
          <div key={item.id} className="flex gap-4 mb-4">
            <div className="flex flex-col items-center">
              <div className="w-8 h-8 rounded-full bg-rose-600 text-white flex items-center justify-center text-xs font-bold">{i+1}</div>
              {i < items.length - 1 && <div className="w-0.5 h-full bg-stone-200 my-1" />}
            </div>
            <div className="card flex-1 p-4">
              <div className="flex justify-between items-start">
                <div>
                  {item.eventTime && <span className="text-sm font-semibold text-rose-600">{item.eventTime} · </span>}
                  <span className="font-medium">{item.description}</span>
                  {item.involvedPerson && <p className="text-sm text-stone-500 mt-1"> {item.involvedPerson}</p>}
                  {item.youtubeLink && <a href={item.youtubeLink} target="_blank" rel="noopener noreferrer" className="text-sm text-blue-600 hover:underline mt-1 block"> {item.youtubeLink}</a>}
                  {item.observations && <p className="text-sm text-stone-500 mt-1 italic">{item.observations}</p>}
                </div>
                <button onClick={() => handleDelete(item.id)} className="text-red-400 hover:text-red-600 text-sm ml-2">✕</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function InvoiceTab({ eventId, event, invoice, reload }) {
  const [form, setForm] = useState({ totalAmount: invoice?.totalAmount || '', description: invoice?.description || '', breakdown: invoice?.breakdown || '' });
  const [payForm, setPayForm] = useState({ amount:'', description:'', paymentDate:'', status:'PAGADO', method:'TRANSFERENCIA' });

  const handleSave = async () => {
    try {
      await api.post(`/events/${eventId}/invoice`, { ...form, totalAmount: parseFloat(form.totalAmount) });
      reload(); toast.success('Presupuesto guardado');
    } catch { toast.error('Error'); }
  };
  const handleAddPayment = async () => {
    if (!invoice) { toast.error('Guarda el presupuesto primero'); return; }
    try {
      await api.post(`/events/${eventId}/invoice/${invoice.id}/payments`, { ...payForm, amount: parseFloat(payForm.amount) });
      reload(); setPayForm({ amount:'', description:'', paymentDate:'', status:'PAGADO', method:'TRANSFERENCIA' });
      toast.success('Pago registrado');
    } catch { toast.error('Error'); }
  };
  const handleDeletePayment = async (paymentId) => {
    try { await api.delete(`/events/${eventId}/invoice/${invoice.id}/payments/${paymentId}`); reload(); }
    catch { toast.error('Error'); }
  };

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/invoice`).catch(() => ({ data: null }));
    return { event, invoice: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800 text-lg">Facturación</h3>
        <PdfDownloadButton
          permissionCode="PDF_INVOICES"
            label="PDF facturación"
          fileName={`facturacion-${safeName}.pdf`}
          fetchData={fetchPdfData}
          DocumentComponent={InvoicePdfDoc}
        />
      </div>
      <div className="card">
        <h3 className="font-semibold mb-4">Presupuesto</h3>
        {invoice && <p className="text-xs text-stone-400 mb-3">Ref: {invoice.invoiceNumber}</p>}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4">
          <div><label className="label">Importe total (€) *</label><input className="input" type="number" value={form.totalAmount} onChange={e=>setForm(f=>({...f,totalAmount:e.target.value}))} placeholder="5000" /></div>
          <div><label className="label">Descripción</label><input className="input" value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))} placeholder="Boda completa" /></div>
          <div className="sm:col-span-2"><label className="label">Desglose de conceptos</label><textarea className="input" rows={3} value={form.breakdown} onChange={e=>setForm(f=>({...f,breakdown:e.target.value}))} placeholder="Salón: 2000€&#10;Catering: 3000€" /></div>
        </div>
        <button onClick={handleSave} className="btn-primary">Guardar presupuesto</button>
        {invoice?.signed && <span className="ml-3 badge bg-emerald-100 text-emerald-700">✅ Firmado el {new Date(invoice.signedAt).toLocaleDateString('es-ES')}</span>}
      </div>

      {invoice && (
        <>
          <div className="grid grid-cols-3 gap-4">
            <div className="card p-4 text-center"><p className="text-2xl font-bold text-stone-900">{invoice.totalAmount?.toLocaleString('es-ES')}€</p><p className="text-sm text-stone-500">Total</p></div>
            <div className="card p-4 text-center"><p className="text-2xl font-bold text-emerald-600">{invoice.paidAmount?.toLocaleString('es-ES')}€</p><p className="text-sm text-stone-500">Pagado</p></div>
            <div className="card p-4 text-center"><p className="text-2xl font-bold text-amber-600">{invoice.pendingAmount?.toLocaleString('es-ES')}€</p><p className="text-sm text-stone-500">Pendiente</p></div>
          </div>
          <div className="card">
            <h3 className="font-semibold mb-4">Registrar pago</h3>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 mb-4">
              <div><label className="label">Importe (€)</label><input className="input" type="number" value={payForm.amount} onChange={e=>setPayForm(f=>({...f,amount:e.target.value}))} /></div>
              <div><label className="label">Fecha</label><input className="input" type="date" value={payForm.paymentDate} onChange={e=>setPayForm(f=>({...f,paymentDate:e.target.value}))} /></div>
              <div><label className="label">Descripción</label><input className="input" value={payForm.description} onChange={e=>setPayForm(f=>({...f,description:e.target.value}))} placeholder="Señal, pago final..." /></div>
              <div><label className="label">Método</label>
                <select className="input" value={payForm.method} onChange={e=>setPayForm(f=>({...f,method:e.target.value}))}>
                  {['TRANSFERENCIA','EFECTIVO','TARJETA','BIZUM'].map(m=><option key={m}>{m}</option>)}
                </select>
              </div>
            </div>
            <button onClick={handleAddPayment} className="btn-success text-sm">+ Registrar pago</button>
            <div className="mt-4 space-y-2">
              {invoice.payments?.map(p => (
                <div key={p.id} className="flex items-center justify-between p-3 bg-stone-50 rounded-xl text-sm">
                  <div>
                    <span className="font-medium">{p.amount?.toLocaleString('es-ES')}€</span>
                    <span className="text-stone-500 ml-2">{p.description}</span>
                    {p.paymentDate && <span className="text-stone-400 ml-2">{new Date(p.paymentDate).toLocaleDateString('es-ES')}</span>}
                    {p.method && <span className="badge bg-stone-100 text-stone-600 ml-2">{p.method}</span>}
                  </div>
                  <button onClick={() => handleDeletePayment(p.id)} className="text-red-400 hover:text-red-600">✕</button>
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function RemindersTab({ event, onSend }) {
  const pending = [];
  if (!event.menuConfirmed)      pending.push('El menú aún no ha sido confirmado.');
  if (!event.allergensCompleted) pending.push('No hay alérgenos registrados.');
  if (!event.protocolCompleted)  pending.push('El protocolo del evento no está completo.');
  if (!event.budgetSigned)       pending.push('El presupuesto no ha sido firmado.');

  return (
    <div className="space-y-4">
      <div className="card">
        <h3 className="font-semibold mb-3">Estado de tareas pendientes</h3>
        {pending.length === 0 ? (
          <p className="text-emerald-600">✅ Todo completado</p>
        ) : (
          <ul className="space-y-2">
            {pending.map(p => <li key={p} className="flex items-center gap-2 text-amber-700"><span>⚠️</span>{p}</li>)}
          </ul>
        )}
      </div>
      <div className="card">
        <h3 className="font-semibold mb-3">Enviar recordatorio manual</h3>
        <p className="text-sm text-stone-500 mb-4">Se enviará un recordatorio al cliente para que complete la información pendiente.</p>
        <div className="flex flex-wrap gap-3">
          <button onClick={() => onSend('EMAIL')}    className="btn-secondary text-sm"> Enviar por Email</button>
          <button onClick={() => onSend('SMS')}      className="btn-secondary text-sm"> Enviar por SMS</button>
          <button onClick={() => onSend('WHATSAPP')} className="btn-secondary text-sm"> Enviar por WhatsApp</button>
        </div>
      </div>
    </div>
  );
}

// -- Mesas Admin ----------------------------------------------------------------
const DIET_OPTS = ['VEGETARIANO','VEGANO','HALAL','KOSHER','SIN_SAL','DIABETICO'];

function MesasAdminTab({ eventId, event, tables, reload }) {
  const [showNewTable, setShowNewTable]       = useState(false);
  const [newTable, setNewTable]               = useState({ name: '', capacity: '', notes: '' });
  const [showAddGuest, setShowAddGuest]       = useState(null); // tableId
  const [guestForm, setGuestForm]             = useState({ guestName: '', diet: '', observations: '' });
  const [selAllergens, setSelAllergens]       = useState([]);
  const [editingGuest, setEditingGuest]       = useState(null); // { guest, tableId }
  const [editGuestForm, setEditGuestForm]     = useState({ guestName: '', diet: '', observations: '' });
  const [editSelAllergens, setEditSelAllergens] = useState([]);

  const totalGuests   = tables.reduce((s, t) => s + (t.guestCount || 0), 0);
  const totalAlergias = tables.reduce((s, t) => s + (t.allergiesCount || 0), 0);

  const fetchPdfData = async () => {
    const r = await api.get(`/events/${eventId}/tables`);
    return { event, tables: r.data };
  };
  const safeName = (event?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase();

  const handleCreateTable = async () => {
    if (!newTable.name.trim()) { toast.error('El nombre es obligatorio'); return; }
    try {
      await api.post(`/events/${eventId}/tables`, { ...newTable, capacity: newTable.capacity ? parseInt(newTable.capacity) : null });
      toast.success('Mesa creada');
      setShowNewTable(false); setNewTable({ name: '', capacity: '', notes: '' }); reload();
    } catch { toast.error('Error al crear mesa'); }
  };

  const handleDeleteTable = async (tableId, name) => {
    if (!confirm(`¿Eliminar la mesa "${name}" y todos sus invitados?`)) return;
    try { await api.delete(`/events/${eventId}/tables/${tableId}`); toast.success('Mesa eliminada'); reload(); }
    catch { toast.error('Error'); }
  };

  const handleAddGuest = async (tableId) => {
    if (!guestForm.guestName.trim()) { toast.error('El nombre es obligatorio'); return; }
    try {
      await api.post(`/events/${eventId}/tables/${tableId}/guests`, { ...guestForm, allergies: selAllergens.join(',') });
      toast.success('Invitado añadido');
      setShowAddGuest(null); setGuestForm({ guestName:'', diet:'', observations:'' }); setSelAllergens([]); reload();
    } catch { toast.error('Error'); }
  };

  const handleDeleteGuest = async (tableId, guestId) => {
    try { await api.delete(`/events/${eventId}/tables/${tableId}/guests/${guestId}`); reload(); }
    catch { toast.error('Error'); }
  };

  const handleMoveGuest = async (tableId, guestId, targetTableId) => {
    try {
      await api.patch(`/events/${eventId}/tables/${tableId}/guests/${guestId}/move`, { targetTableId });
      toast.success('Invitado movido'); reload();
    } catch { toast.error('Error al mover'); }
  };

  const startEditGuest = (g, tableId) => {
    setEditingGuest({ guestId: g.id, tableId });
    setEditGuestForm({ guestName: g.guestName, diet: g.diet || '', observations: g.observations || '' });
    setEditSelAllergens(g.allergies ? g.allergies.split(',').filter(Boolean) : []);
    setShowAddGuest(null);
  };

  const handleUpdateGuest = async () => {
    if (!editGuestForm.guestName.trim()) { toast.error('El nombre es obligatorio'); return; }
    try {
      await api.put(`/events/${eventId}/tables/${editingGuest.tableId}/guests/${editingGuest.guestId}`, {
        ...editGuestForm, allergies: editSelAllergens.join(','),
      });
      toast.success('Invitado actualizado');
      setEditingGuest(null);
      reload();
    } catch { toast.error('Error al actualizar'); }
  };

  return (
    <div className="space-y-4">
      {tables.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: 'Mesas',     value: tables.length,  color: 'text-stone-900' },
            { label: 'Invitados', value: totalGuests,     color: 'text-stone-900' },
            { label: 'Con alergias', value: totalAlergias, color: totalAlergias > 0 ? 'text-amber-600' : 'text-emerald-600' },
          ].map(i => (
            <div key={i.label} className="card p-4 text-center">
              <p className={`text-2xl font-bold ${i.color}`}>{i.value}</p>
              <p className="text-sm text-stone-500">{i.label}</p>
            </div>
          ))}
        </div>
      )}

      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-stone-800">
          Distribución de mesas
          <span className="text-stone-400 font-normal text-sm ml-2">(introducidas por el cliente)</span>
        </h3>
        <div className="flex items-center gap-2">
          <PdfDownloadButton
            permissionCode="PDF_TABLES"
            label="PDF mesas"
            fileName={`mesas-${safeName}.pdf`}
            fetchData={fetchPdfData}
            DocumentComponent={TablesPdfDoc}
          />
          <button onClick={() => setShowNewTable(true)} className="btn-primary text-sm">+ Nueva mesa</button>
        </div>
      </div>

      {showNewTable && (
        <div className="card border-blue-100 bg-blue-50/30">
          <h4 className="font-medium mb-3">Nueva mesa</h4>
          <div className="grid grid-cols-2 gap-3 mb-3">
            <div><label className="label">Nombre *</label><input className="input" value={newTable.name} onChange={e => setNewTable(f => ({ ...f, name: e.target.value }))} placeholder="Mesa 1 / Presidencial" /></div>
            <div><label className="label">Capacidad</label><input className="input" type="number" min="1" value={newTable.capacity} onChange={e => setNewTable(f => ({ ...f, capacity: e.target.value }))} placeholder="10" /></div>
            <div className="col-span-2"><label className="label">Observaciones</label><input className="input" value={newTable.notes} onChange={e => setNewTable(f => ({ ...f, notes: e.target.value }))} placeholder="Junto a la pista..." /></div>
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowNewTable(false)} className="btn-secondary">Cancelar</button>
            <button onClick={handleCreateTable} className="btn-primary">Crear mesa</button>
          </div>
        </div>
      )}

      {tables.length === 0 && !showNewTable && (
        <div className="card text-center py-12 text-stone-500">
          El cliente aún no ha configurado mesas, o puedes crearlas tú desde aquí.
        </div>
      )}

      <div className="space-y-4">
        {tables.map(table => {
          const occupancy = table.capacity ? Math.round((table.guestCount / table.capacity) * 100) : null;
          return (
            <div key={table.id} className={`card ${table.allergiesCount > 0 ? 'border-amber-200' : ''}`}>
              <div className="flex items-center justify-between mb-3">
                <div>
                  <div className="flex items-center gap-2 flex-wrap">
                    <h4 className="font-semibold text-stone-900">{table.name}</h4>
                    {table.allergiesCount > 0 && (
                      <span className="badge bg-amber-100 text-amber-700">⚠ {table.allergiesCount} alergia{table.allergiesCount !== 1 ? 's' : ''}</span>
                    )}
                    {table.notes && <span className="text-xs text-stone-400 italic">{table.notes}</span>}
                  </div>
                  <div className="flex items-center gap-3 mt-1">
                    <span className="text-xs text-stone-500">
                      {table.guestCount}{table.capacity ? `/${table.capacity}` : ''} invitado{table.guestCount !== 1 ? 's' : ''}
                    </span>
                    {occupancy !== null && (
                      <div className="w-20 h-1.5 bg-stone-100 rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${occupancy >= 100 ? 'bg-red-500' : occupancy >= 80 ? 'bg-amber-500' : 'bg-emerald-500'}`}
                          style={{ width: `${Math.min(occupancy, 100)}%` }} />
                      </div>
                    )}
                  </div>
                </div>
                <button onClick={() => handleDeleteTable(table.id, table.name)}
                  className="text-stone-300 hover:text-red-500 transition-colors p-1.5 rounded-lg hover:bg-red-50">
                  <Trash2 size={15} />
                </button>
              </div>

              <div className="space-y-1.5">
                {(table.guests || []).map(g => {
                  const isEditingThis = editingGuest?.guestId === g.id;
                  return (
                    <div key={g.id}>
                      {/* Vista normal */}
                      {!isEditingThis && (
                        <div className="flex items-start justify-between p-2.5 bg-stone-50 rounded-xl">
                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-semibold text-stone-900">{g.guestName}</p>
                            <div className="flex flex-wrap gap-1 mt-0.5">
                              {g.diet && <span className="badge bg-violet-100 text-violet-700 text-[10px]">{g.diet.replace('_',' ')}</span>}
                              {g.allergies && g.allergies.split(',').filter(Boolean).map((a, idx) => (
                                <span key={a} className={`badge text-[10px] ${ALLERGEN_BADGE_COLORS[idx % ALLERGEN_BADGE_COLORS.length]}`}>⚠ {ALLERGEN_LABELS_MAP[a] || a}</span>
                              ))}
                              {g.observations && <span className="text-[10px] text-stone-400 italic ml-1">{g.observations}</span>}
                            </div>
                          </div>
                          <div className="flex items-center gap-1 flex-none ml-2">
                            <button onClick={() => startEditGuest(g, table.id)}
                              className="p-1 rounded-lg text-stone-300 hover:text-blue-500 hover:bg-blue-50 transition-colors" title="Editar invitado">
                              <Edit2 size={12} />
                            </button>
                            {tables.filter(t => t.id !== table.id).length > 0 && (
                              <select
                                className="text-xs border border-stone-200 rounded-lg px-1.5 py-1 text-stone-500 bg-white cursor-pointer"
                                defaultValue=""
                                onChange={e => { if (e.target.value) handleMoveGuest(table.id, g.id, parseInt(e.target.value)); e.target.value = ''; }}
                              >
                                <option value="" disabled>Mover ↗</option>
                                {tables.filter(t => t.id !== table.id).map(t => (
                                  <option key={t.id} value={t.id}>{t.name}</option>
                                ))}
                              </select>
                            )}
                            <button onClick={() => handleDeleteGuest(table.id, g.id)}
                              className="text-stone-300 hover:text-red-500 transition-colors p-1 rounded-lg hover:bg-red-50">
                              <Trash2 size={13} />
                            </button>
                          </div>
                        </div>
                      )}

                      {/* Vista edición inline */}
                      {isEditingThis && (
                        <div className="p-3 bg-amber-50 border border-amber-200 rounded-xl space-y-2.5">
                          <div className="flex items-center justify-between">
                            <p className="text-xs font-semibold text-amber-800">✏️ Editando invitado</p>
                            <button onClick={() => setEditingGuest(null)} className="text-stone-400 hover:text-stone-600"><X size={14} /></button>
                          </div>
                          <input className="input text-sm" placeholder="Nombre *" value={editGuestForm.guestName}
                            onChange={e => setEditGuestForm(f => ({ ...f, guestName: e.target.value }))} />
                          <select className="input text-sm" value={editGuestForm.diet}
                            onChange={e => setEditGuestForm(f => ({ ...f, diet: e.target.value }))}>
                            <option value="">Sin dieta especial</option>
                            {DIET_OPTS.map(d => <option key={d} value={d}>{d.replace('_',' ')}</option>)}
                          </select>
                          <div>
                            <label className="label text-[10px] mb-1 block">Alérgenos</label>
                            <div className="flex flex-wrap gap-1">
                              {ALLERGEN_LIST.map(a => (
                                <button key={a} type="button"
                                  onClick={() => setEditSelAllergens(p => p.includes(a) ? p.filter(x => x !== a) : [...p, a])}
                                  className={`px-2 py-0.5 rounded-md text-[10px] font-medium border transition-colors ${editSelAllergens.includes(a) ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'}`}>
                                  {ALLERGEN_LABELS_MAP[a]}
                                </button>
                              ))}
                            </div>
                          </div>
                          <input className="input text-sm" placeholder="Observaciones" value={editGuestForm.observations}
                            onChange={e => setEditGuestForm(f => ({ ...f, observations: e.target.value }))} />
                          <div className="flex gap-2">
                            <button onClick={() => setEditingGuest(null)} className="btn-secondary flex-1 text-xs py-1.5">Cancelar</button>
                            <button onClick={handleUpdateGuest} className="btn-primary flex-1 text-xs py-1.5">Guardar</button>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
                {(!table.guests || table.guests.length === 0) && (
                  <p className="text-xs text-stone-400 italic text-center py-2">Sin invitados asignados</p>
                )}
              </div>

              {showAddGuest !== table.id ? (
                <button
                  onClick={() => { setShowAddGuest(table.id); setSelAllergens([]); setGuestForm({ guestName:'', diet:'', observations:'' }); }}
                  className="mt-3 w-full flex items-center justify-center gap-1.5 py-2 border-2 border-dashed border-stone-200 rounded-xl text-sm text-stone-500 hover:border-rose-300 hover:text-rose-600 transition-all">
                  + Añadir invitado
                </button>
              ) : (
                <div className="mt-3 p-4 bg-stone-50 rounded-2xl space-y-3">
                  <h5 className="font-semibold text-sm text-stone-900">Nuevo invitado en {table.name}</h5>
                  <input className="input" placeholder="Nombre *" value={guestForm.guestName} onChange={e => setGuestForm(f => ({ ...f, guestName: e.target.value }))} />
                  <select className="input" value={guestForm.diet} onChange={e => setGuestForm(f => ({ ...f, diet: e.target.value }))}>
                    <option value="">Sin dieta especial</option>
                    {DIET_OPTS.map(d => <option key={d} value={d}>{d.replace('_',' ')}</option>)}
                  </select>
                  <div>
                    <label className="label text-xs mb-1 block">Alérgenos</label>
                    <div className="flex flex-wrap gap-1.5">
                      {ALLERGEN_LIST.map(a => (
                        <button key={a} type="button"
                          onClick={() => setSelAllergens(p => p.includes(a) ? p.filter(x => x !== a) : [...p, a])}
                          className={`px-2 py-1 rounded-lg text-xs font-medium border transition-colors ${selAllergens.includes(a) ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-stone-600 border-stone-200 hover:border-amber-300'}`}>
                          {ALLERGEN_LABELS_MAP[a]}
                        </button>
                      ))}
                    </div>
                  </div>
                  <input className="input" placeholder="Observaciones" value={guestForm.observations} onChange={e => setGuestForm(f => ({ ...f, observations: e.target.value }))} />
                  <div className="flex gap-2">
                    <button onClick={() => setShowAddGuest(null)} className="btn-secondary flex-1 text-sm">Cancelar</button>
                    <button onClick={() => handleAddGuest(table.id)} className="btn-primary flex-1 text-sm">Guardar</button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Planos del Salón ────────────────────────────────────────────────────────
function PlanosTab({ eventId, event, hasPermission }) {
  const [plan,      setPlan]      = useState(null);
  const [planUrl,   setPlanUrl]   = useState(null);
  const [loading,   setLoading]   = useState(true);
  const [uploading, setUploading] = useState(false);
  const [zoom,      setZoom]      = useState(1);
  const fileRef                   = useRef();

  useEffect(() => { loadPlan(); }, []);
  useEffect(() => { return () => { if (planUrl) URL.revokeObjectURL(planUrl); }; }, [planUrl]);

  const loadPlan = async () => {
    setLoading(true);
    try {
      const meta = await api.get(`/events/${eventId}/floorplan/meta`);
      // 204 No Content → sin plano
      if (!meta.data || !meta.data.id) {
        setPlan(null); setPlanUrl(null);
        return;
      }
      setPlan(meta.data);
      const res = await api.get(`/events/${eventId}/floorplan`, { responseType: 'blob' });
      setPlanUrl(URL.createObjectURL(res.data));
    } catch {
      setPlan(null); setPlanUrl(null);
    } finally { setLoading(false); }
  };

  const handleUpload = async (file) => {
    if (!file) return;
    const allowed = ['image/jpeg','image/png','image/webp','application/pdf'];
    if (!allowed.includes(file.type)) { toast.error('Formato no permitido (JPG, PNG, WEBP o PDF)'); return; }
    setUploading(true);
    const fd = new FormData();
    fd.append('file', file);
    try {
      // NO fijar Content-Type: el navegador añade el boundary multipart automáticamente
      await api.post(`/events/${eventId}/floorplan`, fd);
      toast.success('Plano subido correctamente');
      loadPlan();
    } catch (e) {
      const msg = e?.response?.data?.message || e?.response?.data || 'Error al subir el plano';
      toast.error(typeof msg === 'string' ? msg : 'Error al subir el plano');
    } finally { setUploading(false); }
  };

  const handleDelete = async () => {
    if (!confirm('¿Eliminar el plano del salón?')) return;
    try {
      await api.delete(`/events/${eventId}/floorplan`);
      if (planUrl) URL.revokeObjectURL(planUrl);
      setPlan(null); setPlanUrl(null);
      toast.success('Plano eliminado');
    } catch { toast.error('Error al eliminar'); }
  };

  const isImage = plan?.contentType?.startsWith('image/');
  const isPdf   = plan?.contentType === 'application/pdf';
  const fmtSize = b => b < 1024*1024 ? `${(b/1024).toFixed(0)} KB` : `${(b/1024/1024).toFixed(1)} MB`;

  const canDownloadFloorPlan = hasPermission ? hasPermission('PDF_FLOOR_PLAN') : false;

  const handleDownloadPlan = () => {
    if (!planUrl || !plan) return;
    const a = document.createElement('a');
    a.href = planUrl;
    a.download = plan.filename || 'plano';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <div>
          <h3 className="font-semibold text-stone-800 flex items-center gap-2"><Map size={18} className="text-stone-500" /> Plano del salón</h3>
          <p className="text-xs text-stone-500 mt-0.5">Sube el plano para consulta del equipo de sala</p>
        </div>
        {plan && (
          <div className="flex items-center gap-2">
            {canDownloadFloorPlan && planUrl && (
              <button
                onClick={handleDownloadPlan}
                className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-sm font-medium border border-stone-200 bg-white text-stone-600 hover:border-emerald-300 hover:text-emerald-700 hover:bg-emerald-50 transition-colors"
                title="Descargar plano"
              >
                <Download size={14} /> Descargar plano
              </button>
            )}
            <button onClick={() => fileRef.current?.click()}
              className="btn-secondary text-sm inline-flex items-center gap-1.5"><RotateCcw size={14} /> Reemplazar</button>
            <button onClick={handleDelete}
              className="inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium text-red-600 bg-red-50 hover:bg-red-100 border border-red-200 rounded-xl transition-colors">
              <Trash2 size={14} /> Eliminar
            </button>
          </div>
        )}
      </div>

      <input ref={fileRef} type="file" accept=".jpg,.jpeg,.png,.webp,.pdf"
        className="hidden" onChange={e => handleUpload(e.target.files?.[0])} />

      {loading && (
        <div className="card flex items-center justify-center py-20">
          <div className="w-8 h-8 border-2 border-rose-200 border-t-rose-600 rounded-full animate-spin" />
        </div>
      )}

      {!loading && !plan && (
        <div
          onClick={() => fileRef.current?.click()}
          onDragOver={e => e.preventDefault()}
          onDrop={e => { e.preventDefault(); handleUpload(e.dataTransfer.files?.[0]); }}
          className="card border-2 border-dashed border-stone-300 hover:border-rose-400 cursor-pointer transition-all py-20 text-center">
          {uploading
            ? <p className="text-stone-500 text-sm animate-pulse">Subiendo plano...</p>
            : <>
                <Upload size={36} className="text-stone-300 mx-auto mb-3" />
                <p className="font-semibold text-stone-600 mb-1">Arrastra el plano aquí o haz clic</p>
                <p className="text-sm text-stone-400">JPG · PNG · WEBP · PDF · máx 20 MB</p>
              </>}
        </div>
      )}

      {!loading && plan && planUrl && (
        <>
          <div className="flex items-center gap-3 p-3 bg-stone-50 border border-stone-200 rounded-xl text-sm text-stone-600 flex-wrap">
            <span className="font-medium truncate max-w-xs">{plan.filename}</span>
            <span className="text-stone-400">·</span>
            <span className="text-stone-400">{plan.contentType}</span>
            {plan.fileSize && <><span className="text-stone-400">·</span><span>{fmtSize(plan.fileSize)}</span></>}
          </div>

          {isImage && (
            <div className="flex items-center gap-2">
              <button onClick={() => setZoom(z => Math.max(0.25, z - 0.25))} className="p-2 rounded-lg border border-stone-200 hover:bg-stone-100 transition-colors"><ZoomOut size={16} className="text-stone-600" /></button>
              <span className="text-sm text-stone-500 w-14 text-center">{Math.round(zoom * 100)}%</span>
              <button onClick={() => setZoom(z => Math.min(4, z + 0.25))} className="p-2 rounded-lg border border-stone-200 hover:bg-stone-100 transition-colors"><ZoomIn size={16} className="text-stone-600" /></button>
              <button onClick={() => setZoom(1)} className="px-3 py-2 rounded-lg border border-stone-200 hover:bg-stone-100 transition-colors text-xs text-stone-500">Restablecer</button>
            </div>
          )}

          {isImage && (
            <div className="overflow-auto rounded-2xl border border-stone-200 bg-stone-100 max-h-[70vh]">
              <div style={{ width: `${Math.max(100, zoom * 100)}%` }} className="flex items-start justify-center p-4">
                <img src={planUrl} alt="Plano del salón" style={{ transform: `scale(${zoom})`, transformOrigin: 'top left', transition: 'transform 0.2s', maxWidth: '100%' }} className="rounded-lg shadow-sm" />
              </div>
            </div>
          )}

          {isPdf && (
            <div className="rounded-2xl border border-stone-200 overflow-hidden" style={{ height: '70vh' }}>
              <iframe src={planUrl} title="Plano PDF" className="w-full h-full" style={{ border: 'none' }} />
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Layers, Calendar, Users, MapPin, Clock, AlertTriangle, Table2, Lock, Map, ZoomIn, ZoomOut, Upload, RotateCcw } from 'lucide-react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import PdfDownloadButton      from '../../components/PdfDownloadButton';
import ProtocolPdfDoc         from '../../components/pdf/ProtocolPdfDoc';
import TablesPdfDoc           from '../../components/pdf/TablesPdfDoc';
import AllergensPdfDoc        from '../../components/pdf/AllergensPdfDoc';
import MetreOperativePdfDoc   from '../../components/pdf/MetreOperativePdfDoc';

const ALLERGEN_LABELS = {
  GLUTEN:'Gluten', LACTEOS:'Lácteos', HUEVOS:'Huevos', FRUTOS_SECOS:'Frutos secos',
  CACAHUETES:'Cacahuetes', SOJA:'Soja', MARISCO:'Marisco', PESCADO:'Pescado',
  MOSTAZA:'Mostaza', APIO:'Apio', SESAMO:'Sésamo', SULFITOS:'Sulfitos',
  MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuz'
};

const ALLERGEN_COLORS = [
  'bg-amber-50 text-amber-700 border-amber-200',
  'bg-red-50 text-red-700 border-red-200',
  'bg-orange-50 text-orange-700 border-orange-200',
  'bg-yellow-50 text-yellow-700 border-yellow-200',
];

const DIET_COLORS = {
  VEGETARIANO: 'bg-green-100 text-green-700',
  VEGANO: 'bg-emerald-100 text-emerald-700',
  HALAL: 'bg-teal-100 text-teal-700',
  KOSHER: 'bg-cyan-100 text-cyan-700',
  SIN_SAL: 'bg-sky-100 text-sky-700',
  DIABETICO: 'bg-blue-100 text-blue-700',
};

export default function FloorView() {
  const { hasPermission } = useAuth();
  const [events, setEvents] = useState([]);
  const [selected, setSelected] = useState(null);
  const [protocol, setProtocol] = useState([]);
  const [allergens, setAllergens] = useState([]);
  const [tables, setTables] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('timing');
  // Estado para planos
  const [planMeta, setPlanMeta] = useState(null);
  const [planUrl,  setPlanUrl]  = useState(null);
  const [zoom,     setZoom]     = useState(1);

  const canViewProtocol  = hasPermission('PROTOCOL_VIEW');
  const canViewTables    = hasPermission('TABLES_VIEW');
  const canViewAllergens = hasPermission('ALLERGENS_VIEW');

  useEffect(() => {
    api.get('/events/mis-eventos')
      .then(r => {
        const active = r.data.filter(e => !['COMPLETADO', 'CANCELADO'].includes(e.status));
        setEvents(active);
        if (active.length > 0) loadEvent(active[0].id);
        else setLoading(false);
      })
      .catch(() => { toast.error('Error cargando eventos'); setLoading(false); });
  }, []);

  const loadEvent = async (id) => {
    setSelected(id);
    setProtocol([]); setAllergens([]); setTables([]);
    setPlanMeta(null);
    if (planUrl) { URL.revokeObjectURL(planUrl); setPlanUrl(null); }
    setLoading(true);
    const [p, a, t] = await Promise.all([
      canViewProtocol  ? api.get(`/events/${id}/protocol`).catch(() => ({ data: [] }))  : Promise.resolve({ data: [] }),
      canViewAllergens ? api.get(`/events/${id}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
      canViewTables    ? api.get(`/events/${id}/tables`).catch(() => ({ data: [] }))    : Promise.resolve({ data: [] }),
    ]);
    setProtocol(p.data); setAllergens(a.data); setTables(t.data);
    // Cargar plano si existe
    try {
      const meta = await api.get(`/events/${id}/floorplan/meta`);
      // 204 No Content → sin plano
      if (!meta.data || !meta.data.id) {
        setPlanMeta(null); setPlanUrl(null);
      } else {
        setPlanMeta(meta.data);
        const res = await api.get(`/events/${id}/floorplan`, { responseType: 'blob' });
        setPlanUrl(URL.createObjectURL(res.data));
      }
    } catch { setPlanMeta(null); setPlanUrl(null); }
    setLoading(false);
  };

  const selectedEvent = events.find(e => e.id === selected);
  // El endpoint /allergens ahora devuelve TODOS los invitados; filtramos los que tienen restricciones
  const allergenGuests = allergens.filter(a => a.allergies || a.diet);
  const byTable = allergenGuests.reduce((acc, a) => {
    const t = a.tableNumber || a.tableName || 'Sin mesa asignada';
    (acc[t] = acc[t] || []).push(a);
    return acc;
  }, {});

  if (loading) return (
    <Layout>
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-2 border-emerald-200 border-t-emerald-600 rounded-full animate-spin" />
      </div>
    </Layout>
  );

  if (events.length === 0) return (
    <Layout>
      <div className="card text-center py-20">
        <Layers size={48} className="text-stone-300 mx-auto mb-4" />
        <h2 className="text-xl font-bold text-stone-800 mb-2">Sin eventos asignados</h2>
        <p className="text-stone-500">Cuando te asignen a un evento, aparecerá aquí.</p>
      </div>
    </Layout>
  );

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center gap-3">
          <div className="w-11 h-11 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-2xl flex items-center justify-center shadow-sm">
            <Layers size={22} className="text-white" />
          </div>
          <div className="flex-1">
            <h1 className="text-xl font-bold text-stone-900">Vista Sala / Metres</h1>
            <p className="text-stone-500 text-sm">Timing y distribución de mesas</p>
          </div>
          {selectedEvent && (
            <PdfDownloadButton
              permissionCode="TABLES_VIEW"
              label="Descargar PDF operativo"
              variant="primary"
              fileName={`operativo-metre-${(selectedEvent.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
              fetchData={async () => {
                const [p, a, t, m] = await Promise.all([
                  canViewProtocol  ? api.get(`/events/${selected}/protocol`).catch(() => ({ data: [] }))  : Promise.resolve({ data: [] }),
                  canViewAllergens ? api.get(`/events/${selected}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
                  canViewTables    ? api.get(`/events/${selected}/tables`).catch(() => ({ data: [] }))    : Promise.resolve({ data: [] }),
                  api.get(`/events/${selected}/menus`).catch(() => ({ data: [] })),
                ]);
                return { event: selectedEvent, protocol: p.data, allergens: a.data, tables: t.data, menus: m.data };
              }}
              DocumentComponent={MetreOperativePdfDoc}
            />
          )}
        </div>

        {/* Event selector */}
        {events.length > 1 && (
          <div className="flex gap-2 flex-wrap">
            {events.map(e => (
              <button key={e.id} onClick={() => loadEvent(e.id)}
                className={`px-4 py-2 rounded-xl text-sm font-medium border transition-all ${
                  selected === e.id
                    ? 'bg-emerald-600 text-white border-emerald-600 shadow-sm'
                    : 'bg-white text-stone-600 border-stone-200 hover:border-emerald-200'
                }`}>
                {e.clientName}
                <span className="ml-1.5 opacity-70 text-xs">
                  {new Date(e.eventDate).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                </span>
              </button>
            ))}
          </div>
        )}

        {/* Event info */}
        {selectedEvent && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
            className="bg-gradient-to-r from-emerald-600 to-teal-600 rounded-2xl p-5 text-white shadow-lg shadow-emerald-200">
            <p className="text-emerald-200 text-xs font-semibold uppercase tracking-wide mb-1">{selectedEvent.typeLabel}</p>
            <h2 className="text-xl font-bold mb-2">{selectedEvent.clientName}</h2>
            <div className="flex flex-wrap gap-3 text-sm text-emerald-100">
              <span className="flex items-center gap-1.5"><Calendar size={14} />
                {new Date(selectedEvent.eventDate).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
              </span>
              {selectedEvent.estimatedGuests && (
                <span className="flex items-center gap-1.5"><Users size={14} />{selectedEvent.estimatedGuests} invitados</span>
              )}
              {selectedEvent.venue && (
                <span className="flex items-center gap-1.5"><MapPin size={14} />{selectedEvent.venue}</span>
              )}
            </div>
          </motion.div>
        )}

        {/* Tabs internos: Timing / Mesas / Alérgenos */}
        <div className="flex gap-1 bg-stone-100 rounded-xl p-1 w-fit flex-wrap">
          {[
            ['timing','Timing',Clock, canViewProtocol],
            ['mesas','Mesas',Table2, canViewTables],
            ['alergenos','Alérgenos',AlertTriangle, canViewAllergens],
            ['planos','Planos',Map, true]
          ].map(([id,label,Icon,allowed]) => (
            <button key={id} onClick={() => allowed && setActiveTab(id)}
              disabled={!allowed}
              title={!allowed ? 'Sin permiso' : ''}
              className={`flex items-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                !allowed
                  ? 'text-stone-300 cursor-not-allowed opacity-50'
                  : activeTab === id ? 'bg-white text-emerald-700 shadow-sm' : 'text-stone-500 hover:text-stone-700'
              }`}>
              <Icon size={14} />{label}
              {!allowed && <Lock size={11} />}
            </button>
          ))}
        </div>

        {/* Contenido por tab */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Timeline — siempre visible */}
          {(activeTab === 'timing') && (
            <div className="card lg:col-span-2">
              <div className="flex items-center gap-2 mb-5">
                <Clock size={18} className="text-emerald-600" />
                <h3 className="font-semibold text-stone-900">Timing del servicio</h3>
                <span className="badge bg-emerald-100 text-emerald-700 ml-auto">{protocol.length} momentos</span>
                <PdfDownloadButton
                  permissionCode="PROTOCOL_VIEW"
                  label="PDF protocolo"
                  fileName={`protocolo-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
                    const r = await api.get(`/events/${selected}/protocol`);
                    return { event: selectedEvent, protocol: r.data };
                  }}
                  DocumentComponent={ProtocolPdfDoc}
                />
              </div>
              {protocol.length === 0 ? (
                <div className="text-center py-10"><Clock size={32} className="text-stone-300 mx-auto mb-3" /><p className="text-stone-400 text-sm">No hay protocolo definido</p></div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {protocol.map((item, i) => (
                    <motion.div key={item.id} initial={{ opacity: 0, x: -8 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.03 }}
                      className="flex items-start gap-3 p-3 bg-stone-50 rounded-xl hover:bg-emerald-50 transition-colors">
                      <span className={`text-xs font-bold w-12 flex-none mt-0.5 ${item.eventTime ? 'text-emerald-700' : 'text-stone-400'}`}>{item.eventTime || '—'}</span>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-semibold text-stone-900">{item.description}</p>
                        {item.involvedPerson && <p className="text-xs text-stone-500 mt-0.5"> {item.involvedPerson}</p>}
                        {item.observations && <p className="text-xs text-stone-400 mt-0.5 italic">{item.observations}</p>}
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Mesas con invitados */}
          {activeTab === 'mesas' && (
            <div className="card lg:col-span-2">
              <div className="flex items-center gap-2 mb-5">
                <Table2 size={18} className="text-emerald-600" />
                <h3 className="font-semibold text-stone-900">Distribución de mesas</h3>
                <span className="badge bg-emerald-100 text-emerald-700 ml-auto">{tables.length} mesas · {tables.reduce((s,t) => s + (t.guestCount||0), 0)} invitados</span>
                <PdfDownloadButton
                  permissionCode="TABLES_VIEW"
                  label="PDF mesas"
                  fileName={`mesas-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
                    const r = await api.get(`/events/${selected}/tables`);
                    return { event: selectedEvent, tables: r.data };
                  }}
                  DocumentComponent={TablesPdfDoc}
                />
              </div>
              {tables.length === 0 ? (
                <div className="text-center py-10"><Table2 size={32} className="text-stone-300 mx-auto mb-3" /><p className="text-stone-400 text-sm">No hay mesas configuradas para este evento</p></div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {tables.map(table => (
                    <motion.div key={table.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                      className={`border rounded-2xl overflow-hidden ${table.allergiesCount > 0 ? 'border-amber-200' : 'border-stone-200'}`}>
                      <div className={`px-4 py-2.5 flex items-center gap-2 ${table.allergiesCount > 0 ? 'bg-amber-50' : 'bg-stone-50'}`}>
                        <span className="font-bold text-stone-900 text-sm flex-1">{table.name}</span>
                        <span className="text-xs text-stone-500">{table.guestCount}{table.capacity ? `/${table.capacity}` : ''}</span>
                        {table.allergiesCount > 0 && <span className="badge bg-amber-200 text-amber-800 text-[10px]">⚠ {table.allergiesCount}</span>}
                      </div>
                      <div className="p-3 space-y-1.5">
                        {(table.guests || []).map(g => (
                          <div key={g.id} className="flex items-start gap-2 p-2 bg-white border border-stone-100 rounded-xl">
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-semibold text-stone-900">{g.guestName}</p>
                              <div className="flex flex-wrap gap-1 mt-0.5">
                                {g.diet && <span className={`badge text-[10px] ${DIET_COLORS[g.diet] || 'bg-purple-100 text-purple-700'}`}>{g.diet.replace('_',' ')}</span>}
                                {g.allergies && g.allergies.split(',').filter(Boolean).map((a, idx) => (
                                  <span key={a} className={`badge text-[10px] ${ALLERGEN_COLORS[idx % ALLERGEN_COLORS.length]}`}>⚠ {ALLERGEN_LABELS[a] || a}</span>
                                ))}
                              </div>
                            </div>
                          </div>
                        ))}
                        {(!table.guests || table.guests.length === 0) && <p className="text-xs text-stone-400 text-center py-2 italic">Sin invitados</p>}
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Alérgenos por mesa */}
          {activeTab === 'alergenos' && (
            <div className="card lg:col-span-2">
              <div className="flex items-center justify-between mb-5">
                <div className="flex items-center gap-2"><AlertTriangle size={18} className="text-amber-600" /><h3 className="font-semibold text-stone-900">Necesidades especiales</h3></div>
                <div className="flex items-center gap-2">
                  {allergenGuests.length > 0 && <span className="badge bg-amber-100 text-amber-700">{allergenGuests.length} personas</span>}
                  <PdfDownloadButton
                    permissionCode="PDF_ALLERGENS"
                    label="PDF alérgenos"
                    fileName={`alergenos-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                    fetchData={async () => {
                      const r = await api.get(`/events/${selected}/allergens`);
                      return { event: selectedEvent, allergens: r.data };
                    }}
                    DocumentComponent={AllergensPdfDoc}
                  />
                </div>
              </div>
              {allergenGuests.length === 0 ? (
                <div className="text-center py-10"><div className="text-4xl mb-3">✅</div><p className="text-stone-400 text-sm">{tables.length === 0 ? 'Sin mesas configuradas para este evento' : 'Sin necesidades especiales registradas'}</p></div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {Object.entries(byTable).sort(([a],[b]) => a.localeCompare(b)).map(([table, entries]) => (
                    <div key={table} className="border border-amber-100 rounded-2xl overflow-hidden">
                      <div className="bg-amber-50 px-4 py-2 flex items-center gap-2">
                        <MapPin size={13} className="text-amber-600" /><span className="font-semibold text-amber-800 text-sm">{table}</span>
                        <span className="ml-auto text-xs text-amber-600">{entries.length} pers.</span>
                      </div>
                      <div className="p-3 space-y-2">
                        {entries.map(e => (
                          <div key={e.id} className="bg-white rounded-xl p-3 border border-stone-100">
                            <p className="font-semibold text-sm text-stone-900 mb-1.5">{e.guestName}</p>
                            <div className="flex flex-wrap gap-1">
                              {e.diet && <span className={`badge ${DIET_COLORS[e.diet] || 'bg-purple-100 text-purple-700'}`}>{e.diet.replace('_', ' ')}</span>}
                              {e.allergies && e.allergies.split(',').filter(Boolean).map((a, idx) => (
                                <span key={a} className={`badge ${ALLERGEN_COLORS[idx % ALLERGEN_COLORS.length]}`}>{ALLERGEN_LABELS[a] || a}</span>
                              ))}
                            </div>
                            {e.observations && <p className="text-xs text-stone-400 mt-1.5 italic">{e.observations}</p>}
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Plano del salón — solo lectura */}
          {activeTab === 'planos' && (
            <div className="card lg:col-span-2">
              <div className="flex items-center gap-2 mb-4">
                <Map size={18} className="text-emerald-600" />
                <h3 className="font-semibold text-stone-900">Plano del salón</h3>
              </div>

              {!planMeta && (
                <div className="text-center py-14">
                  <Map size={36} className="text-stone-300 mx-auto mb-3" />
                  <p className="text-stone-400 text-sm">No hay plano disponible para este evento.</p>
                  <p className="text-stone-400 text-xs mt-1">El administrador puede subir el plano desde la gestión del evento.</p>
                </div>
              )}

              {planMeta && planUrl && (
                <>
                  <div className="flex items-center gap-2 mb-3 text-xs text-stone-500">
                    <span className="font-medium">{planMeta.filename}</span>
                    {planMeta.fileSize && <span className="text-stone-400">· {planMeta.fileSize < 1024*1024 ? `${(planMeta.fileSize/1024).toFixed(0)} KB` : `${(planMeta.fileSize/1024/1024).toFixed(1)} MB`}</span>}
                  </div>

                  {planMeta.contentType?.startsWith('image/') && (
                    <>
                      <div className="flex items-center gap-2 mb-3">
                        <button onClick={() => setZoom(z => Math.max(0.25, z - 0.25))} className="p-1.5 rounded-lg border border-stone-200 hover:bg-stone-100"><ZoomOut size={15} className="text-stone-600" /></button>
                        <span className="text-xs text-stone-500 w-12 text-center">{Math.round(zoom * 100)}%</span>
                        <button onClick={() => setZoom(z => Math.min(4, z + 0.25))} className="p-1.5 rounded-lg border border-stone-200 hover:bg-stone-100"><ZoomIn size={15} className="text-stone-600" /></button>
                        <button onClick={() => setZoom(1)} className="px-2 py-1.5 rounded-lg border border-stone-200 hover:bg-stone-100 text-xs text-stone-500">Reset</button>
                      </div>
                      <div className="overflow-auto rounded-2xl border border-stone-200 bg-stone-100 max-h-[65vh]">
                        <div style={{ width: `${Math.max(100, zoom * 100)}%` }} className="flex items-start justify-center p-4">
                          <img src={planUrl} alt="Plano del salón" style={{ transform: `scale(${zoom})`, transformOrigin: 'top left', transition: 'transform 0.2s', maxWidth: '100%' }} className="rounded-lg shadow-sm" />
                        </div>
                      </div>
                    </>
                  )}

                  {planMeta.contentType === 'application/pdf' && (
                    <div className="rounded-2xl border border-stone-200 overflow-hidden" style={{ height: '65vh' }}>
                      <iframe src={planUrl} title="Plano PDF" className="w-full h-full" style={{ border: 'none' }} />
                    </div>
                  )}
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
}

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Layers, Calendar, Users, MapPin, Clock, AlertTriangle, Table2, Lock, Map, ZoomIn, ZoomOut, Download } from 'lucide-react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import PdfDownloadButton      from '../../components/PdfDownloadButton';
import ProtocolPdfDoc         from '../../components/pdf/ProtocolPdfDoc';
import TablesPdfDoc           from '../../components/pdf/TablesPdfDoc';
import AllergensPdfDoc        from '../../components/pdf/AllergensPdfDoc';
import MetreOperativePdfDoc   from '../../components/pdf/MetreOperativePdfDoc';

const ALLERGEN_LABELS = {
  GLUTEN:'Gluten', LACTEOS:'Lácteos', HUEVOS:'Huevos', FRUTOS_SECOS:'Frutos secos',
  CACAHUETES:'Cacahuetes', SOJA:'Soja', MARISCO:'Marisco', PESCADO:'Pescado',
  MOSTAZA:'Mostaza', APIO:'Apio', SESAMO:'Sésamo', SULFITOS:'Sulfitos',
  MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuz'
};

const ALLERGEN_COLORS = [
  'bg-amber-50 text-amber-700 border-amber-200',
  'bg-red-50 text-red-700 border-red-200',
  'bg-orange-50 text-orange-700 border-orange-200',
  'bg-yellow-50 text-yellow-700 border-yellow-200',
];

const DIET_COLORS = {
  VEGETARIANO: 'bg-green-100 text-green-700',
  VEGANO: 'bg-emerald-100 text-emerald-700',
  HALAL: 'bg-teal-100 text-teal-700',
  KOSHER: 'bg-cyan-100 text-cyan-700',
  SIN_SAL: 'bg-sky-100 text-sky-700',
  DIABETICO: 'bg-blue-100 text-blue-700',
};

export default function FloorView() {
  const { hasPermission } = useAuth();
  const [events, setEvents] = useState([]);
  const [selected, setSelected] = useState(null);
  const [protocol, setProtocol] = useState([]);
  const [allergens, setAllergens] = useState([]);
  const [tables, setTables] = useState([]);
  const [loading, setLoading] = useState(true);
  // Estado para planos
  const [planMeta, setPlanMeta] = useState(null);
  const [planUrl,  setPlanUrl]  = useState(null);
  const [zoom,     setZoom]     = useState(1);

  const canViewProtocol  = hasPermission('PROTOCOL_VIEW');
  const canViewTables    = hasPermission('TABLES_VIEW');
  const canViewAllergens = hasPermission('ALLERGENS_VIEW');
  const canViewFloorPlan = hasPermission('FLOOR_PLAN_VIEW');
  const canDownloadFloorPlan = hasPermission('PDF_FLOOR_PLAN');

  // Primera pestaña habilitada (se usa como tab inicial para no aterrizar en una bloqueada)
  const firstAllowedTab =
    canViewProtocol  ? 'timing'    :
    canViewTables    ? 'mesas'     :
    canViewAllergens ? 'alergenos' :
    canViewFloorPlan ? 'planos'    : 'timing';

  const [activeTab, setActiveTab] = useState(firstAllowedTab);

  useEffect(() => {
    api.get('/events/mis-eventos')
      .then(r => {
        const active = r.data.filter(e => !['COMPLETADO', 'CANCELADO'].includes(e.status));
        setEvents(active);
        if (active.length > 0) loadEvent(active[0].id);
        else setLoading(false);
      })
      .catch(() => { toast.error('Error cargando eventos'); setLoading(false); });
  }, []);

  const loadEvent = async (id) => {
    setSelected(id);
    setProtocol([]); setAllergens([]); setTables([]);
    setPlanMeta(null);
    if (planUrl) { URL.revokeObjectURL(planUrl); setPlanUrl(null); }
    setLoading(true);
    const [p, a, t] = await Promise.all([
      canViewProtocol  ? api.get(`/events/${id}/protocol`).catch(() => ({ data: [] }))  : Promise.resolve({ data: [] }),
      canViewAllergens ? api.get(`/events/${id}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
      canViewTables    ? api.get(`/events/${id}/tables`).catch(() => ({ data: [] }))    : Promise.resolve({ data: [] }),
    ]);
    setProtocol(p.data); setAllergens(a.data); setTables(t.data);
    // Cargar plano si existe
    try {
      const meta = await api.get(`/events/${id}/floorplan/meta`);
      // 204 No Content → sin plano
      if (!meta.data || !meta.data.id) {
        setPlanMeta(null); setPlanUrl(null);
      } else {
        setPlanMeta(meta.data);
        const res = await api.get(`/events/${id}/floorplan`, { responseType: 'blob' });
        setPlanUrl(URL.createObjectURL(res.data));
      }
    } catch { setPlanMeta(null); setPlanUrl(null); }
    setLoading(false);
  };

  const selectedEvent = events.find(e => e.id === selected);
  // El endpoint /allergens ahora devuelve TODOS los invitados; filtramos los que tienen restricciones
  const allergenGuests = allergens.filter(a => a.allergies || a.diet);
  const byTable = allergenGuests.reduce((acc, a) => {
    const t = a.tableNumber || a.tableName || 'Sin mesa asignada';
    (acc[t] = acc[t] || []).push(a);
    return acc;
  }, {});

  if (loading) return (
    <Layout>
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-2 border-emerald-200 border-t-emerald-600 rounded-full animate-spin" />
      </div>
    </Layout>
  );

  if (events.length === 0) return (
    <Layout>
      <div className="card text-center py-20">
        <Layers size={48} className="text-stone-300 mx-auto mb-4" />
        <h2 className="text-xl font-bold text-stone-800 mb-2">Sin eventos asignados</h2>
        <p className="text-stone-500">Cuando te asignen a un evento, aparecerá aquí.</p>
      </div>
    </Layout>
  );

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center gap-3">
          <div className="w-11 h-11 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-2xl flex items-center justify-center shadow-sm">
            <Layers size={22} className="text-white" />
          </div>
          <div className="flex-1">
            <h1 className="text-xl font-bold text-stone-900">Vista Sala / Metres</h1>
            <p className="text-stone-500 text-sm">Timing y distribución de mesas</p>
          </div>
          {selectedEvent && (
            <PdfDownloadButton
              permissionCode="PDF_TABLES"
              label="Descargar PDF operativo"
              variant="primary"
              fileName={`operativo-metre-${(selectedEvent.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
              fetchData={async () => {
                const [p, a, t, m] = await Promise.all([
                  canViewProtocol  ? api.get(`/events/${selected}/protocol`).catch(() => ({ data: [] }))  : Promise.resolve({ data: [] }),
                  canViewAllergens ? api.get(`/events/${selected}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
                  canViewTables    ? api.get(`/events/${selected}/tables`).catch(() => ({ data: [] }))    : Promise.resolve({ data: [] }),
                  api.get(`/events/${selected}/menus`).catch(() => ({ data: [] })),
                ]);
                // Intentar incluir el plano como imagen en el PDF operativo
                let floorPlanBase64 = null;
                let floorPlanIsImage = false;
                let floorPlanFilename = null;
                try {
                  const meta = await api.get(`/events/${selected}/floorplan/meta`);
                  if (meta.data?.id && meta.data.contentType?.startsWith('image/')) {
                    const floorRes = await api.get(`/events/${selected}/floorplan`, { responseType: 'blob' });
                    floorPlanBase64 = await new Promise(resolve => {
                      const reader = new FileReader();
                      reader.onloadend = () => resolve(reader.result);
                      reader.readAsDataURL(floorRes.data);
                    });
                    floorPlanIsImage = true;
                    floorPlanFilename = meta.data.filename;
                  }
                } catch { /* sin plano, no es crítico */ }
                return { event: selectedEvent, protocol: p.data, allergens: a.data, tables: t.data, menus: m.data, floorPlanBase64, floorPlanIsImage, floorPlanFilename };
              }}
              DocumentComponent={MetreOperativePdfDoc}
            />
          )}
        </div>

        {/* Event selector */}
        {events.length > 1 && (
          <div className="flex gap-2 flex-wrap">
            {events.map(e => (
              <button key={e.id} onClick={() => loadEvent(e.id)}
                className={`px-4 py-2 rounded-xl text-sm font-medium border transition-all ${
                  selected === e.id
                    ? 'bg-emerald-600 text-white border-emerald-600 shadow-sm'
                    : 'bg-white text-stone-600 border-stone-200 hover:border-emerald-200'
                }`}>
                {e.clientName}
                <span className="ml-1.5 opacity-70 text-xs">
                  {new Date(e.eventDate).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                </span>
              </button>
            ))}
          </div>
        )}

        {/* Event info */}
        {selectedEvent && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
            className="bg-gradient-to-r from-emerald-600 to-teal-600 rounded-2xl p-5 text-white shadow-lg shadow-emerald-200">
            <p className="text-emerald-200 text-xs font-semibold uppercase tracking-wide mb-1">{selectedEvent.typeLabel}</p>
            <h2 className="text-xl font-bold mb-2">{selectedEvent.clientName}</h2>
            <div className="flex flex-wrap gap-3 text-sm text-emerald-100">
              <span className="flex items-center gap-1.5"><Calendar size={14} />
                {new Date(selectedEvent.eventDate).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
              </span>
              {selectedEvent.estimatedGuests && (
                <span className="flex items-center gap-1.5"><Users size={14} />{selectedEvent.estimatedGuests} invitados</span>
              )}
              {selectedEvent.venue && (
                <span className="flex items-center gap-1.5"><MapPin size={14} />{selectedEvent.venue}</span>
              )}
            </div>
          </motion.div>
        )}

        {/* Tabs internos: Timing / Mesas / Alérgenos / Planos */}
        <div className="flex gap-1 bg-stone-100 rounded-xl p-1 w-fit flex-wrap">
          {[
            ['timing',    'Timing',     Clock,         canViewProtocol ],
            ['mesas',     'Mesas',      Table2,        canViewTables   ],
            ['alergenos', 'Alérgenos',  AlertTriangle, canViewAllergens],
            ['planos',    'Planos',     Map,           canViewFloorPlan],
          ].map(([id, label, Icon, allowed]) => (
            <button key={id} onClick={() => allowed && setActiveTab(id)}
              disabled={!allowed}
              title={!allowed ? 'Sin permiso' : ''}
              className={`flex items-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                !allowed
                  ? 'text-stone-300 cursor-not-allowed opacity-50'
                  : activeTab === id ? 'bg-white text-emerald-700 shadow-sm' : 'text-stone-500 hover:text-stone-700'
              }`}>
              <Icon size={14} />{label}
              {!allowed && <Lock size={11} />}
            </button>
          ))}
        </div>

        {/* Contenido por tab */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Timeline — siempre visible */}
          {(activeTab === 'timing') && (
            <div className="card lg:col-span-2">
              <div className="flex items-center gap-2 mb-5">
                <Clock size={18} className="text-emerald-600" />
                <h3 className="font-semibold text-stone-900">Timing del servicio</h3>
                <span className="badge bg-emerald-100 text-emerald-700 ml-auto">{protocol.length} momentos</span>
                <PdfDownloadButton
                  permissionCode="PDF_PROTOCOL"
                  label="PDF protocolo"
                  fileName={`protocolo-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
                    const r = await api.get(`/events/${selected}/protocol`);
                    return { event: selectedEvent, protocol: r.data };
                  }}
                  DocumentComponent={ProtocolPdfDoc}
                />
              </div>
              {protocol.length === 0 ? (
                <div className="text-center py-10"><Clock size={32} className="text-stone-300 mx-auto mb-3" /><p className="text-stone-400 text-sm">No hay protocolo definido</p></div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {protocol.map((item, i) => (
                    <motion.div key={item.id} initial={{ opacity: 0, x: -8 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.03 }}
                      className="flex items-start gap-3 p-3 bg-stone-50 rounded-xl hover:bg-emerald-50 transition-colors">
                      <span className={`text-xs font-bold w-12 flex-none mt-0.5 ${item.eventTime ? 'text-emerald-700' : 'text-stone-400'}`}>{item.eventTime || '—'}</span>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-semibold text-stone-900">{item.description}</p>
                        {item.involvedPerson && <p className="text-xs text-stone-500 mt-0.5"> {item.involvedPerson}</p>}
                        {item.observations && <p className="text-xs text-stone-400 mt-0.5 italic">{item.observations}</p>}
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Mesas con invitados */}
          {activeTab === 'mesas' && (
            <div className="card lg:col-span-2">
              <div className="flex items-center gap-2 mb-5">
                <Table2 size={18} className="text-emerald-600" />
                <h3 className="font-semibold text-stone-900">Distribución de mesas</h3>
                <span className="badge bg-emerald-100 text-emerald-700 ml-auto">{tables.length} mesas · {tables.reduce((s,t) => s + (t.guestCount||0), 0)} invitados</span>
                <PdfDownloadButton
                  permissionCode="PDF_TABLES"
                  label="PDF mesas"
                  fileName={`mesas-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
                    const r = await api.get(`/events/${selected}/tables`);
                    return { event: selectedEvent, tables: r.data };
                  }}
                  DocumentComponent={TablesPdfDoc}
                />
              </div>
              {tables.length === 0 ? (
                <div className="text-center py-10"><Table2 size={32} className="text-stone-300 mx-auto mb-3" /><p className="text-stone-400 text-sm">No hay mesas configuradas para este evento</p></div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {tables.map(table => (
                    <motion.div key={table.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                      className={`border rounded-2xl overflow-hidden ${table.allergiesCount > 0 ? 'border-amber-200' : 'border-stone-200'}`}>
                      <div className={`px-4 py-2.5 flex items-center gap-2 ${table.allergiesCount > 0 ? 'bg-amber-50' : 'bg-stone-50'}`}>
                        <span className="font-bold text-stone-900 text-sm flex-1">{table.name}</span>
                        <span className="text-xs text-stone-500">{table.guestCount}{table.capacity ? `/${table.capacity}` : ''}</span>
                        {table.allergiesCount > 0 && <span className="badge bg-amber-200 text-amber-800 text-[10px]">⚠ {table.allergiesCount}</span>}
                      </div>
                      <div className="p-3 space-y-1.5">
                        {(table.guests || []).map(g => (
                          <div key={g.id} className="flex items-start gap-2 p-2 bg-white border border-stone-100 rounded-xl">
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-semibold text-stone-900">{g.guestName}</p>
                              <div className="flex flex-wrap gap-1 mt-0.5">
                                {g.diet && <span className={`badge text-[10px] ${DIET_COLORS[g.diet] || 'bg-purple-100 text-purple-700'}`}>{g.diet.replace('_', ' ')}</span>}
                                {g.allergies && g.allergies.split(',').filter(Boolean).map((a, idx) => (
                                  <span key={a} className={`badge text-[10px] ${ALLERGEN_COLORS[idx % ALLERGEN_COLORS.length]}`}>⚠ {ALLERGEN_LABELS[a] || a}</span>
                                ))}
                              </div>
                            </div>
                          </div>
                        ))}
                        {(!table.guests || table.guests.length === 0) && <p className="text-xs text-stone-400 text-center py-2 italic">Sin invitados</p>}
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Alérgenos por mesa */}
          {activeTab === 'alergenos' && (
            <div className="card lg:col-span-2">
              <div className="flex items-center justify-between mb-5">
                <div className="flex items-center gap-2"><AlertTriangle size={18} className="text-amber-600" /><h3 className="font-semibold text-stone-900">Necesidades especiales</h3></div>
                <div className="flex items-center gap-2">
                  {allergenGuests.length > 0 && <span className="badge bg-amber-100 text-amber-700">{allergenGuests.length} personas</span>}
                  <PdfDownloadButton
                    permissionCode="PDF_ALLERGENS"
                    label="PDF alérgenos"
                    fileName={`alergenos-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                    fetchData={async () => {
                      const r = await api.get(`/events/${selected}/allergens`);
                      return { event: selectedEvent, allergens: r.data };
                    }}
                    DocumentComponent={AllergensPdfDoc}
                  />
                </div>
              </div>
              {allergenGuests.length === 0 ? (
                <div className="text-center py-10"><div className="text-4xl mb-3">✅</div><p className="text-stone-400 text-sm">{tables.length === 0 ? 'Sin mesas configuradas para este evento' : 'Sin necesidades especiales registradas'}</p></div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {Object.entries(byTable).sort(([a],[b]) => a.localeCompare(b)).map(([table, entries]) => (
                    <div key={table} className="border border-amber-100 rounded-2xl overflow-hidden">
                      <div className="bg-amber-50 px-4 py-2 flex items-center gap-2">
                        <MapPin size={13} className="text-amber-600" /><span className="font-semibold text-amber-800 text-sm">{table}</span>
                        <span className="ml-auto text-xs text-amber-600">{entries.length} pers.</span>
                      </div>
                      <div className="p-3 space-y-2">
                        {entries.map(e => (
                          <div key={e.id} className="bg-white rounded-xl p-3 border border-stone-100">
                            <p className="font-semibold text-sm text-stone-900 mb-1.5">{e.guestName}</p>
                            <div className="flex flex-wrap gap-1">
                              {e.diet && <span className={`badge ${DIET_COLORS[e.diet] || 'bg-purple-100 text-purple-700'}`}>{e.diet.replace('_', ' ')}</span>}
                              {e.allergies && e.allergies.split(',').filter(Boolean).map((a, idx) => (
                                <span key={a} className={`badge ${ALLERGEN_COLORS[idx % ALLERGEN_COLORS.length]}`}>{ALLERGEN_LABELS[a] || a}</span>
                              ))}
                            </div>
                            {e.observations && <p className="text-xs text-stone-400 mt-1.5 italic">{e.observations}</p>}
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Plano del salón — solo lectura */}
          {activeTab === 'planos' && (
            <div className="card lg:col-span-2">
              <div className="flex items-center gap-2 mb-4">
                <Map size={18} className="text-emerald-600" />
                <h3 className="font-semibold text-stone-900">Plano del salón</h3>
                {canDownloadFloorPlan && planUrl && planMeta && (
                  <button
                    onClick={() => {
                      const a = document.createElement('a');
                      a.href = planUrl;
                      a.download = planMeta.filename || 'plano';
                      document.body.appendChild(a);
                      a.click();
                      document.body.removeChild(a);
                    }}
                    className="ml-auto inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-sm font-medium border border-stone-200 bg-white text-stone-600 hover:border-emerald-300 hover:text-emerald-700 hover:bg-emerald-50 transition-colors"
                    title="Descargar plano"
                  >
                    <Download size={14} /> Descargar plano
                  </button>
                )}
              </div>

              {!planMeta && (
                <div className="text-center py-14">
                  <Map size={36} className="text-stone-300 mx-auto mb-3" />
                  <p className="text-stone-400 text-sm">No hay plano disponible para este evento.</p>
                  <p className="text-stone-400 text-xs mt-1">El administrador puede subir el plano desde la gestión del evento.</p>
                </div>
              )}

              {planMeta && planUrl && (
                <>
                  <div className="flex items-center gap-2 mb-3 text-xs text-stone-500">
                    <span className="font-medium">{planMeta.filename}</span>
                    {planMeta.fileSize && <span className="text-stone-400">· {planMeta.fileSize < 1024*1024 ? `${(planMeta.fileSize/1024).toFixed(0)} KB` : `${(planMeta.fileSize/1024/1024).toFixed(1)} MB`}</span>}
                  </div>

                  {planMeta.contentType?.startsWith('image/') && (
                    <>
                      <div className="flex items-center gap-2 mb-3">
                        <button onClick={() => setZoom(z => Math.max(0.25, z - 0.25))} className="p-1.5 rounded-lg border border-stone-200 hover:bg-stone-100"><ZoomOut size={15} className="text-stone-600" /></button>
                        <span className="text-xs text-stone-500 w-12 text-center">{Math.round(zoom * 100)}%</span>
                        <button onClick={() => setZoom(z => Math.min(4, z + 0.25))} className="p-1.5 rounded-lg border border-stone-200 hover:bg-stone-100"><ZoomIn size={15} className="text-stone-600" /></button>
                        <button onClick={() => setZoom(1)} className="px-2 py-1.5 rounded-lg border border-stone-200 hover:bg-stone-100 text-xs text-stone-500">Reset</button>
                      </div>
                      <div className="overflow-auto rounded-2xl border border-stone-200 bg-stone-100 max-h-[65vh]">
                        <div style={{ width: `${Math.max(100, zoom * 100)}%` }} className="flex items-start justify-center p-4">
                          <img src={planUrl} alt="Plano del salón" style={{ transform: `scale(${zoom})`, transformOrigin: 'top left', transition: 'transform 0.2s', maxWidth: '100%' }} className="rounded-lg shadow-sm" />
                        </div>
                      </div>
                    </>
                  )}

                  {planMeta.contentType === 'application/pdf' && (
                    <div className="rounded-2xl border border-stone-200 overflow-hidden" style={{ height: '65vh' }}>
                      <iframe src={planUrl} title="Plano PDF" className="w-full h-full" style={{ border: 'none' }} />
                    </div>
                  )}
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
}

import { useEffect, useState, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Briefcase, ShieldCheck, Layers, ChefHat, Music2, User,
  Camera, Heart, Star, Users, Plus, Trash2, Edit2,
  Check, X, Lock, Save, ChevronRight, AlertCircle, Wand2, RefreshCw
} from 'lucide-react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import PermissionPanel from '../../components/PermissionPanel';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';

// ── Mapa de iconos disponibles ───────────────────────────────────────────────
const ICON_MAP = {
  'shield-check': ShieldCheck,
  'layers':       Layers,
  'chef-hat':     ChefHat,
  'music-2':      Music2,
  'user':         User,
  'briefcase':    Briefcase,
  'camera':       Camera,
  'heart':        Heart,
  'star':         Star,
  'users':        Users,
};

const COLOR_OPTIONS = [
  { value: 'bg-violet-100 text-violet-700 border-violet-200',   preview: 'bg-violet-500',   label: 'Violeta'   },
  { value: 'bg-emerald-100 text-emerald-700 border-emerald-200', preview: 'bg-emerald-500',  label: 'Verde'     },
  { value: 'bg-orange-100 text-orange-700 border-orange-200',   preview: 'bg-orange-500',   label: 'Naranja'   },
  { value: 'bg-blue-100 text-blue-700 border-blue-200',         preview: 'bg-blue-500',     label: 'Azul'      },
  { value: 'bg-stone-100 text-stone-700 border-stone-200',      preview: 'bg-stone-400',    label: 'Gris'      },
  { value: 'bg-rose-100 text-rose-700 border-rose-200',         preview: 'bg-rose-500',     label: 'Rosa'      },
  { value: 'bg-amber-100 text-amber-700 border-amber-200',      preview: 'bg-amber-500',    label: 'Ámbar'     },
  { value: 'bg-cyan-100 text-cyan-700 border-cyan-200',         preview: 'bg-cyan-500',     label: 'Cian'      },
  { value: 'bg-indigo-100 text-indigo-700 border-indigo-200',   preview: 'bg-indigo-500',   label: 'Índigo'    },
  { value: 'bg-pink-100 text-pink-700 border-pink-200',         preview: 'bg-pink-500',     label: 'Rosa claro'},
];

const ICON_OPTIONS = Object.keys(ICON_MAP);

function PositionIcon({ icon, className = '' }) {
  const Icon = ICON_MAP[icon] || Briefcase;
  return <Icon className={className} />;
}

const emptyForm = { code: '', label: '', description: '', icon: 'briefcase', color: COLOR_OPTIONS[4].value };

export default function JobPositions() {
  const { refreshPermissions } = useAuth();
  const [positions, setPositions]       = useState([]);
  const [catalog, setCatalog]           = useState([]);
  const [selected, setSelected]         = useState(null);   // position code
  const [posPerms, setPosPerms]         = useState({});     // { code: boolean }
  const [saving, setSaving]             = useState(false);
  const [loading, setLoading]           = useState(true);
  const [loadingPerms, setLoadingPerms] = useState(false);

  // Modal nuevo puesto
  const [showModal, setShowModal]       = useState(false);
  const [modalMode, setModalMode]       = useState('create'); // 'create' | 'edit'
  const [form, setForm]                 = useState(emptyForm);
  const [savingForm, setSavingForm]     = useState(false);

  const loadPositions = useCallback(() => {
    setLoading(true);
    api.get('/positions')
      .then(r => setPositions(r.data))
      .catch(() => toast.error('Error cargando puestos'))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    loadPositions();
    api.get('/permissions').then(r => setCatalog(r.data)).catch(() => {});
  }, [loadPositions]);

  // Cuando cambia el puesto seleccionado, cargamos sus permisos
  useEffect(() => {
    if (!selected) return;
    setLoadingPerms(true);
    api.get(`/positions/${selected}/permissions`)
      .then(r => {
        const codes = r.data.permissionCodes || [];
        const map = {};
        catalog.forEach(p => { map[p.code] = codes.includes(p.code); });
        setPosPerms(map);
      })
      .catch(() => toast.error('Error cargando permisos del puesto'))
      .finally(() => setLoadingPerms(false));
  }, [selected, catalog]);

  const handleSelectPosition = (code) => {
    if (code === selected) return;
    setSelected(code);
    setPosPerms({});
  };

  const handleTogglePerm = (code, value) => {
    setPosPerms(prev => ({ ...prev, [code]: value }));
  };

  const handleSavePermissions = async () => {
    if (!selected) return;
    setSaving(true);
    try {
      const permissionCodes = Object.entries(posPerms)
        .filter(([, v]) => v)
        .map(([k]) => k);
      await api.put(`/positions/${selected}/permissions`, { permissionCodes });
      // Refrescar el token del admin actual para que sus permisos también se actualicen
      await refreshPermissions();
      toast.success('Permisos guardados. Los usuarios afectados los verán al recargar la página.');
      loadPositions(); // refresca contadores
    } catch {
      toast.error('Error guardando permisos');
    } finally {
      setSaving(false);
    }
  };

  const handleResetPermissions = async () => {
    if (!selected) return;
    if (!window.confirm(`¿Restablecer los permisos de "${positions.find(p=>p.code===selected)?.label}" a los valores predeterminados del sistema?`)) return;
    setSaving(true);
    try {
      const r = await api.post(`/positions/${selected}/permissions/reset`);
      const codes = r.data.permissionCodes || [];
      const map = {};
      catalog.forEach(p => { map[p.code] = codes.includes(p.code); });
      setPosPerms(map);
      await refreshPermissions();
      toast.success('Permisos restablecidos a los valores por defecto.');
      loadPositions();
    } catch {
      toast.error('Error restableciendo permisos');
    } finally {
      setSaving(false);
    }
  };

  // ── Modal crear / editar ─────────────────────────────────────────────────
  const openCreate = () => {
    setForm(emptyForm);
    setModalMode('create');
    setShowModal(true);
  };

  const openEdit = (pos) => {
    setForm({
      code: pos.code,
      label: pos.label,
      description: pos.description || '',
      icon: pos.icon || 'briefcase',
      color: pos.color || COLOR_OPTIONS[4].value,
    });
    setModalMode('edit');
    setShowModal(true);
  };

  const handleSaveForm = async () => {
    if (!form.label.trim()) { toast.error('La etiqueta es obligatoria'); return; }
    if (modalMode === 'create' && !form.code.trim()) { toast.error('El código es obligatorio'); return; }
    setSavingForm(true);
    try {
      if (modalMode === 'create') {
        await api.post('/positions', form);
        toast.success('Puesto creado');
      } else {
        await api.put(`/positions/${form.code}`, form);
        toast.success('Puesto actualizado');
      }
      setShowModal(false);
      loadPositions();
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Error guardando puesto');
    } finally {
      setSavingForm(false);
    }
  };

  const handleDelete = async (pos) => {
    if (!confirm(`¿Eliminar el puesto "${pos.label}"? Se eliminarán también sus permisos configurados.`)) return;
    try {
      await api.delete(`/positions/${pos.code}`);
      toast.success('Puesto eliminado');
      if (selected === pos.code) setSelected(null);
      loadPositions();
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Error al eliminar');
    }
  };

  const selectedPos = positions.find(p => p.code === selected);
  const activeCount = Object.values(posPerms).filter(Boolean).length;

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-2xl font-bold text-stone-900">Puestos de trabajo</h1>
            <p className="text-stone-500 text-sm mt-0.5">
              Define qué puede ver y hacer cada puesto. Los usuarios heredan los permisos automáticamente.
            </p>
          </div>
          <button onClick={openCreate} className="btn-primary flex items-center gap-2">
            <Plus size={16} /> Nuevo puesto
          </button>
        </div>

        {/* Layout split */}
        <div className="flex gap-5 items-start">

          {/* ── Panel izquierdo: lista de puestos ─────────────────────── */}
          <div className="w-64 flex-none space-y-2">
            {loading ? (
              [1,2,3,4,5].map(i => (
                <div key={i} className="h-16 rounded-xl bg-stone-100 animate-pulse" />
              ))
            ) : (
              positions.map(pos => {
                const isSelected = pos.code === selected;
                return (
                  <motion.div
                    key={pos.code}
                    initial={{ opacity: 0, x: -8 }}
                    animate={{ opacity: 1, x: 0 }}
                    className={`group relative rounded-xl border cursor-pointer transition-all select-none
                      ${isSelected
                        ? 'border-rose-300 bg-rose-50 shadow-sm'
                        : 'border-stone-200 bg-white hover:border-stone-300 hover:shadow-sm'
                      }`}
                    onClick={() => handleSelectPosition(pos.code)}
                  >
                    <div className="flex items-center gap-3 p-3">
                      <div className={`w-9 h-9 rounded-lg border flex items-center justify-center flex-none ${pos.color}`}>
                        <PositionIcon icon={pos.icon} className="w-4 h-4" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className={`text-sm font-semibold truncate ${isSelected ? 'text-rose-700' : 'text-stone-800'}`}>
                          {pos.label}
                        </p>
                        <p className="text-xs text-stone-400">{pos.permissionCount} permisos</p>
                      </div>
                      {pos.system && (
                        <Lock size={11} className="text-stone-300 flex-none" title="Puesto del sistema" />
                      )}
                      {isSelected && (
                        <ChevronRight size={14} className="text-rose-400 flex-none" />
                      )}
                    </div>

                    {/* Acciones hover */}
                    <div className={`absolute top-1.5 right-1.5 gap-0.5 hidden group-hover:flex ${isSelected ? '!flex' : ''}`}>
                      <button
                        onClick={e => { e.stopPropagation(); openEdit(pos); }}
                        className="p-1 rounded-lg hover:bg-stone-200 transition-colors"
                        title="Editar etiqueta/icono"
                      >
                        <Edit2 size={11} className="text-stone-400" />
                      </button>
                      {!pos.system && (
                        <button
                          onClick={e => { e.stopPropagation(); handleDelete(pos); }}
                          className="p-1 rounded-lg hover:bg-red-100 transition-colors"
                          title="Eliminar puesto"
                        >
                          <Trash2 size={11} className="text-red-400" />
                        </button>
                      )}
                    </div>
                  </motion.div>
                );
              })
            )}

            <div className="pt-2 border-t border-stone-100">
              <p className="text-xs text-stone-400 text-center leading-relaxed">
                <Lock size={10} className="inline mr-1" />
                Los puestos del sistema no se pueden eliminar pero sí editar sus permisos.
              </p>
            </div>
          </div>

          {/* ── Panel derecho: permisos del puesto seleccionado ──────── */}
          <div className="flex-1 min-w-0">
            {!selected ? (
              <div className="card p-12 text-center border-dashed">
                <Wand2 size={32} className="mx-auto text-stone-300 mb-3" />
                <p className="text-stone-500 font-medium">Selecciona un puesto</p>
                <p className="text-sm text-stone-400 mt-1">
                  Haz clic en un puesto de la izquierda para ver y editar sus permisos.
                </p>
              </div>
            ) : (
              <div className="space-y-4">
                {/* Header panel de permisos */}
                <div className="flex items-center justify-between gap-3">
                  <div className="flex items-center gap-3">
                    {selectedPos && (
                      <div className={`w-10 h-10 rounded-xl border flex items-center justify-center ${selectedPos.color}`}>
                        <PositionIcon icon={selectedPos.icon} className="w-5 h-5" />
                      </div>
                    )}
                    <div>
                      <h2 className="font-bold text-stone-900">
                        {selectedPos?.label}
                      </h2>
                      <p className="text-xs text-stone-400">
                        {loadingPerms ? 'Cargando...' : `${activeCount} / ${catalog.length} permisos activos`}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={handleSavePermissions}
                    disabled={saving || loadingPerms}
                    className="btn-primary flex items-center gap-2"
                  >
                    {saving
                      ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      : <Save size={15} />
                    }
                    Guardar permisos
                  </button>
                  <button
                    onClick={handleResetPermissions}
                    disabled={saving || loadingPerms}
                    title="Restablecer permisos a los valores por defecto del sistema"
                    className="btn-secondary flex items-center gap-2"
                  >
                    <RefreshCw size={15} />
                    Restablecer
                  </button>
                </div>

                {/* Info hint */}
                <div className="rounded-xl bg-amber-50 border border-amber-200 px-4 py-2.5 flex items-start gap-2">
                  <AlertCircle size={15} className="text-amber-500 flex-none mt-0.5" />
                  <p className="text-xs text-amber-700 leading-relaxed">
                    Todos los usuarios con el puesto <strong>{selectedPos?.label}</strong> heredarán automáticamente estos permisos.
                    Los cambios se aplican al momento — los usuarios verán los nuevos permisos en su próxima acción o al recargar la página.
                  </p>
                </div>

                {/* Panel de permisos */}
                {loadingPerms ? (
                  <div className="space-y-3">
                    {[1,2,3].map(i => <div key={i} className="h-24 rounded-xl bg-stone-100 animate-pulse" />)}
                  </div>
                ) : (
                  <PermissionPanel
                    catalog={catalog}
                    permissions={posPerms}
                    rolePerms={[]}
                    overrides={{}}
                    onChange={handleTogglePerm}
                  />
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── Modal crear / editar puesto ────────────────────────────────── */}
      <AnimatePresence>
        {showModal && (
          <>
            <motion.div
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="fixed inset-0 bg-black/40 z-40"
              onClick={() => setShowModal(false)}
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }}
              className="fixed inset-0 flex items-center justify-center z-50 p-4"
            >
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 space-y-5">
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-stone-900 text-lg">
                    {modalMode === 'create' ? 'Nuevo puesto' : `Editar: ${form.label}`}
                  </h3>
                  <button onClick={() => setShowModal(false)} className="btn-ghost p-2 rounded-lg">
                    <X size={18} className="text-stone-400" />
                  </button>
                </div>

                <div className="space-y-4">
                  {modalMode === 'create' && (
                    <div>
                      <label className="label">Código interno *</label>
                      <input
                        className="input uppercase"
                        value={form.code}
                        onChange={e => setForm(f => ({ ...f, code: e.target.value.toUpperCase().replace(/[^A-Z0-9_]/g, '') }))}
                        placeholder="WEDDING_PLANNER"
                        maxLength={50}
                      />
                      <p className="text-xs text-stone-400 mt-1">Solo letras mayúsculas, números y guión bajo. Inmutable.</p>
                    </div>
                  )}

                  <div>
                    <label className="label">Nombre del puesto *</label>
                    <input
                      className="input"
                      value={form.label}
                      onChange={e => setForm(f => ({ ...f, label: e.target.value }))}
                      placeholder="Wedding Planner"
                    />
                  </div>

                  <div>
                    <label className="label">Descripción</label>
                    <input
                      className="input"
                      value={form.description}
                      onChange={e => setForm(f => ({ ...f, description: e.target.value }))}
                      placeholder="Coordinación de bodas y eventos especiales"
                    />
                  </div>

                  {/* Icono */}
                  <div>
                    <label className="label">Icono</label>
                    <div className="flex flex-wrap gap-2 mt-1">
                      {ICON_OPTIONS.map(ic => {
                        const Icon = ICON_MAP[ic];
                        return (
                          <button
                            key={ic} type="button"
                            onClick={() => setForm(f => ({ ...f, icon: ic }))}
                            className={`p-2 rounded-lg border transition-all ${
                              form.icon === ic
                                ? 'border-rose-400 bg-rose-50 text-rose-600'
                                : 'border-stone-200 bg-white text-stone-500 hover:border-stone-300'
                            }`}
                          >
                            <Icon size={16} />
                          </button>
                        );
                      })}
                    </div>
                  </div>

                  {/* Color */}
                  <div>
                    <label className="label">Color</label>
                    <div className="flex flex-wrap gap-2 mt-1">
                      {COLOR_OPTIONS.map(c => (
                        <button
                          key={c.value} type="button"
                          onClick={() => setForm(f => ({ ...f, color: c.value }))}
                          className={`w-7 h-7 rounded-full transition-all ${c.preview} ${
                            form.color === c.value ? 'ring-2 ring-offset-2 ring-rose-400 scale-110' : 'hover:scale-110'
                          }`}
                          title={c.label}
                        />
                      ))}
                    </div>
                  </div>

                  {/* Preview */}
                  <div>
                    <label className="label">Vista previa</label>
                    <div className={`inline-flex items-center gap-2 px-3 py-2 rounded-xl border text-sm font-medium ${form.color}`}>
                      <PositionIcon icon={form.icon} className="w-4 h-4" />
                      {form.label || 'Nombre del puesto'}
                    </div>
                  </div>
                </div>

                <div className="flex gap-2 pt-2">
                  <button onClick={() => setShowModal(false)} className="btn-secondary flex-1">Cancelar</button>
                  <button
                    onClick={handleSaveForm}
                    disabled={savingForm}
                    className="btn-primary flex-1 flex items-center justify-center gap-2"
                  >
                    {savingForm
                      ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      : <Check size={15} />
                    }
                    {modalMode === 'create' ? 'Crear puesto' : 'Guardar cambios'}
                  </button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </Layout>
  );
}

import { useEffect, useState, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Briefcase, ShieldCheck, Layers, ChefHat, Music2, User,
  Camera, Heart, Star, Users, Plus, Trash2, Edit2,
  Check, X, Lock, Save, ChevronRight, AlertCircle, Wand2, RefreshCw
} from 'lucide-react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import PermissionPanel from '../../components/PermissionPanel';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';

// ── Mapa de iconos disponibles ───────────────────────────────────────────────
const ICON_MAP = {
  'shield-check': ShieldCheck,
  'layers':       Layers,
  'chef-hat':     ChefHat,
  'music-2':      Music2,
  'user':         User,
  'briefcase':    Briefcase,
  'camera':       Camera,
  'heart':        Heart,
  'star':         Star,
  'users':        Users,
};

const COLOR_OPTIONS = [
  { value: 'bg-violet-100 text-violet-700 border-violet-200',   preview: 'bg-violet-500',   label: 'Violeta'   },
  { value: 'bg-emerald-100 text-emerald-700 border-emerald-200', preview: 'bg-emerald-500',  label: 'Verde'     },
  { value: 'bg-orange-100 text-orange-700 border-orange-200',   preview: 'bg-orange-500',   label: 'Naranja'   },
  { value: 'bg-blue-100 text-blue-700 border-blue-200',         preview: 'bg-blue-500',     label: 'Azul'      },
  { value: 'bg-stone-100 text-stone-700 border-stone-200',      preview: 'bg-stone-400',    label: 'Gris'      },
  { value: 'bg-rose-100 text-rose-700 border-rose-200',         preview: 'bg-rose-500',     label: 'Rosa'      },
  { value: 'bg-amber-100 text-amber-700 border-amber-200',      preview: 'bg-amber-500',    label: 'Ámbar'     },
  { value: 'bg-cyan-100 text-cyan-700 border-cyan-200',         preview: 'bg-cyan-500',     label: 'Cian'      },
  { value: 'bg-indigo-100 text-indigo-700 border-indigo-200',   preview: 'bg-indigo-500',   label: 'Índigo'    },
  { value: 'bg-pink-100 text-pink-700 border-pink-200',         preview: 'bg-pink-500',     label: 'Rosa claro'},
];

const ICON_OPTIONS = Object.keys(ICON_MAP);

function PositionIcon({ icon, className = '' }) {
  const Icon = ICON_MAP[icon] || Briefcase;
  return <Icon className={className} />;
}

const emptyForm = { code: '', label: '', description: '', icon: 'briefcase', color: COLOR_OPTIONS[4].value };

export default function JobPositions() {
  const { refreshPermissions } = useAuth();
  const [positions, setPositions]       = useState([]);
  const [catalog, setCatalog]           = useState([]);
  const [selected, setSelected]         = useState(null);   // position code
  const [posPerms, setPosPerms]         = useState({});     // { code: boolean }
  const [saving, setSaving]             = useState(false);
  const [loading, setLoading]           = useState(true);
  const [loadingPerms, setLoadingPerms] = useState(false);

  // Modal nuevo puesto
  const [showModal, setShowModal]       = useState(false);
  const [modalMode, setModalMode]       = useState('create'); // 'create' | 'edit'
  const [form, setForm]                 = useState(emptyForm);
  const [savingForm, setSavingForm]     = useState(false);

  const loadPositions = useCallback(() => {
    setLoading(true);
    api.get('/positions')
      .then(r => setPositions(r.data))
      .catch(() => toast.error('Error cargando puestos'))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    loadPositions();
    api.get('/permissions').then(r => setCatalog(r.data)).catch(() => {});
  }, [loadPositions]);

  // Cuando cambia el puesto seleccionado, cargamos sus permisos
  useEffect(() => {
    if (!selected) return;
    setLoadingPerms(true);
    api.get(`/positions/${selected}/permissions`)
      .then(r => {
        const codes = r.data.permissionCodes || [];
        const map = {};
        catalog.forEach(p => { map[p.code] = codes.includes(p.code); });
        setPosPerms(map);
      })
      .catch(() => toast.error('Error cargando permisos del puesto'))
      .finally(() => setLoadingPerms(false));
  }, [selected, catalog]);

  const handleSelectPosition = (code) => {
    if (code === selected) return;
    setSelected(code);
    setPosPerms({});
  };

  const handleTogglePerm = (code, value) => {
    setPosPerms(prev => ({ ...prev, [code]: value }));
  };

  const handleSavePermissions = async () => {
    if (!selected) return;
    setSaving(true);
    try {
      const permissionCodes = Object.entries(posPerms)
        .filter(([, v]) => v)
        .map(([k]) => k);
      await api.put(`/positions/${selected}/permissions`, { permissionCodes });
      // Refrescar el token del admin actual para que sus permisos también se actualicen
      await refreshPermissions();
      // Notificar a otras pestañas abiertas del mismo navegador para que recarguen permisos
      try {
        const bc = new BroadcastChannel('perms_updated');
        bc.postMessage({ role: selected, ts: Date.now() });
        bc.close();
      } catch { /* BroadcastChannel no disponible en algunos entornos */ }
      toast.success('Permisos guardados. Los usuarios afectados los verán al recargar la página.');
      loadPositions(); // refresca contadores
    } catch {
      toast.error('Error guardando permisos');
    } finally {
      setSaving(false);
    }
  };

  const handleResetPermissions = async () => {
    if (!selected) return;
    if (!window.confirm(`¿Restablecer los permisos de "${positions.find(p=>p.code===selected)?.label}" a los valores predeterminados del sistema?`)) return;
    setSaving(true);
    try {
      const r = await api.post(`/positions/${selected}/permissions/reset`);
      const codes = r.data.permissionCodes || [];
      const map = {};
      catalog.forEach(p => { map[p.code] = codes.includes(p.code); });
      setPosPerms(map);
      await refreshPermissions();
      try {
        const bc = new BroadcastChannel('perms_updated');
        bc.postMessage({ role: selected, ts: Date.now() });
        bc.close();
      } catch { /* BroadcastChannel no disponible */ }
      toast.success('Permisos restablecidos a los valores por defecto.');
      loadPositions();
    } catch {
      toast.error('Error restableciendo permisos');
    } finally {
      setSaving(false);
    }
  };

  // ── Modal crear / editar ─────────────────────────────────────────────────
  const openCreate = () => {
    setForm(emptyForm);
    setModalMode('create');
    setShowModal(true);
  };

  const openEdit = (pos) => {
    setForm({
      code: pos.code,
      label: pos.label,
      description: pos.description || '',
      icon: pos.icon || 'briefcase',
      color: pos.color || COLOR_OPTIONS[4].value,
    });
    setModalMode('edit');
    setShowModal(true);
  };

  const handleSaveForm = async () => {
    if (!form.label.trim()) { toast.error('La etiqueta es obligatoria'); return; }
    if (modalMode === 'create' && !form.code.trim()) { toast.error('El código es obligatorio'); return; }
    setSavingForm(true);
    try {
      if (modalMode === 'create') {
        await api.post('/positions', form);
        toast.success('Puesto creado');
      } else {
        await api.put(`/positions/${form.code}`, form);
        toast.success('Puesto actualizado');
      }
      setShowModal(false);
      loadPositions();
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Error guardando puesto');
    } finally {
      setSavingForm(false);
    }
  };

  const handleDelete = async (pos) => {
    if (!confirm(`¿Eliminar el puesto "${pos.label}"? Se eliminarán también sus permisos configurados.`)) return;
    try {
      await api.delete(`/positions/${pos.code}`);
      toast.success('Puesto eliminado');
      if (selected === pos.code) setSelected(null);
      loadPositions();
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Error al eliminar');
    }
  };

  const selectedPos = positions.find(p => p.code === selected);
  const activeCount = Object.values(posPerms).filter(Boolean).length;

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-2xl font-bold text-stone-900">Puestos de trabajo</h1>
            <p className="text-stone-500 text-sm mt-0.5">
              Define qué puede ver y hacer cada puesto. Los usuarios heredan los permisos automáticamente.
            </p>
          </div>
          <button onClick={openCreate} className="btn-primary flex items-center gap-2">
            <Plus size={16} /> Nuevo puesto
          </button>
        </div>

        {/* Layout split */}
        <div className="flex gap-5 items-start">

          {/* ── Panel izquierdo: lista de puestos ─────────────────────── */}
          <div className="w-64 flex-none space-y-2">
            {loading ? (
              [1,2,3,4,5].map(i => (
                <div key={i} className="h-16 rounded-xl bg-stone-100 animate-pulse" />
              ))
            ) : (
              positions.map(pos => {
                const isSelected = pos.code === selected;
                return (
                  <motion.div
                    key={pos.code}
                    initial={{ opacity: 0, x: -8 }}
                    animate={{ opacity: 1, x: 0 }}
                    className={`group relative rounded-xl border cursor-pointer transition-all select-none
                      ${isSelected
                        ? 'border-rose-300 bg-rose-50 shadow-sm'
                        : 'border-stone-200 bg-white hover:border-stone-300 hover:shadow-sm'
                      }`}
                    onClick={() => handleSelectPosition(pos.code)}
                  >
                    <div className="flex items-center gap-3 p-3">
                      <div className={`w-9 h-9 rounded-lg border flex items-center justify-center flex-none ${pos.color}`}>
                        <PositionIcon icon={pos.icon} className="w-4 h-4" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className={`text-sm font-semibold truncate ${isSelected ? 'text-rose-700' : 'text-stone-800'}`}>
                          {pos.label}
                        </p>
                        <p className="text-xs text-stone-400">{pos.permissionCount} permisos</p>
                      </div>
                      {pos.system && (
                        <Lock size={11} className="text-stone-300 flex-none" title="Puesto del sistema" />
                      )}
                      {isSelected && (
                        <ChevronRight size={14} className="text-rose-400 flex-none" />
                      )}
                    </div>

                    {/* Acciones hover */}
                    <div className={`absolute top-1.5 right-1.5 gap-0.5 hidden group-hover:flex ${isSelected ? '!flex' : ''}`}>
                      <button
                        onClick={e => { e.stopPropagation(); openEdit(pos); }}
                        className="p-1 rounded-lg hover:bg-stone-200 transition-colors"
                        title="Editar etiqueta/icono"
                      >
                        <Edit2 size={11} className="text-stone-400" />
                      </button>
                      {!pos.system && (
                        <button
                          onClick={e => { e.stopPropagation(); handleDelete(pos); }}
                          className="p-1 rounded-lg hover:bg-red-100 transition-colors"
                          title="Eliminar puesto"
                        >
                          <Trash2 size={11} className="text-red-400" />
                        </button>
                      )}
                    </div>
                  </motion.div>
                );
              })
            )}

            <div className="pt-2 border-t border-stone-100">
              <p className="text-xs text-stone-400 text-center leading-relaxed">
                <Lock size={10} className="inline mr-1" />
                Los puestos del sistema no se pueden eliminar pero sí editar sus permisos.
              </p>
            </div>
          </div>

          {/* ── Panel derecho: permisos del puesto seleccionado ──────── */}
          <div className="flex-1 min-w-0">
            {!selected ? (
              <div className="card p-12 text-center border-dashed">
                <Wand2 size={32} className="mx-auto text-stone-300 mb-3" />
                <p className="text-stone-500 font-medium">Selecciona un puesto</p>
                <p className="text-sm text-stone-400 mt-1">
                  Haz clic en un puesto de la izquierda para ver y editar sus permisos.
                </p>
              </div>
            ) : (
              <div className="space-y-4">
                {/* Header panel de permisos */}
                <div className="flex items-center justify-between gap-3">
                  <div className="flex items-center gap-3">
                    {selectedPos && (
                      <div className={`w-10 h-10 rounded-xl border flex items-center justify-center ${selectedPos.color}`}>
                        <PositionIcon icon={selectedPos.icon} className="w-5 h-5" />
                      </div>
                    )}
                    <div>
                      <h2 className="font-bold text-stone-900">
                        {selectedPos?.label}
                      </h2>
                      <p className="text-xs text-stone-400">
                        {loadingPerms ? 'Cargando...' : `${activeCount} / ${catalog.length} permisos activos`}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={handleSavePermissions}
                    disabled={saving || loadingPerms}
                    className="btn-primary flex items-center gap-2"
                  >
                    {saving
                      ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      : <Save size={15} />
                    }
                    Guardar permisos
                  </button>
                  <button
                    onClick={handleResetPermissions}
                    disabled={saving || loadingPerms}
                    title="Restablecer permisos a los valores por defecto del sistema"
                    className="btn-secondary flex items-center gap-2"
                  >
                    <RefreshCw size={15} />
                    Restablecer
                  </button>
                </div>

                {/* Info hint */}
                <div className="rounded-xl bg-amber-50 border border-amber-200 px-4 py-2.5 flex items-start gap-2">
                  <AlertCircle size={15} className="text-amber-500 flex-none mt-0.5" />
                  <p className="text-xs text-amber-700 leading-relaxed">
                    Todos los usuarios con el puesto <strong>{selectedPos?.label}</strong> heredarán automáticamente estos permisos.
                    Los cambios se aplican al momento — los usuarios verán los nuevos permisos en su próxima acción o al recargar la página.
                  </p>
                </div>

                {/* Panel de permisos */}
                {loadingPerms ? (
                  <div className="space-y-3">
                    {[1,2,3].map(i => <div key={i} className="h-24 rounded-xl bg-stone-100 animate-pulse" />)}
                  </div>
                ) : (
                  <PermissionPanel
                    catalog={catalog}
                    permissions={posPerms}
                    rolePerms={[]}
                    overrides={{}}
                    onChange={handleTogglePerm}
                  />
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── Modal crear / editar puesto ────────────────────────────────── */}
      <AnimatePresence>
        {showModal && (
          <>
            <motion.div
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="fixed inset-0 bg-black/40 z-40"
              onClick={() => setShowModal(false)}
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }}
              className="fixed inset-0 flex items-center justify-center z-50 p-4"
            >
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 space-y-5">
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-stone-900 text-lg">
                    {modalMode === 'create' ? 'Nuevo puesto' : `Editar: ${form.label}`}
                  </h3>
                  <button onClick={() => setShowModal(false)} className="btn-ghost p-2 rounded-lg">
                    <X size={18} className="text-stone-400" />
                  </button>
                </div>

                <div className="space-y-4">
                  {modalMode === 'create' && (
                    <div>
                      <label className="label">Código interno *</label>
                      <input
                        className="input uppercase"
                        value={form.code}
                        onChange={e => setForm(f => ({ ...f, code: e.target.value.toUpperCase().replace(/[^A-Z0-9_]/g, '') }))}
                        placeholder="WEDDING_PLANNER"
                        maxLength={50}
                      />
                      <p className="text-xs text-stone-400 mt-1">Solo letras mayúsculas, números y guión bajo. Inmutable.</p>
                    </div>
                  )}

                  <div>
                    <label className="label">Nombre del puesto *</label>
                    <input
                      className="input"
                      value={form.label}
                      onChange={e => setForm(f => ({ ...f, label: e.target.value }))}
                      placeholder="Wedding Planner"
                    />
                  </div>

                  <div>
                    <label className="label">Descripción</label>
                    <input
                      className="input"
                      value={form.description}
                      onChange={e => setForm(f => ({ ...f, description: e.target.value }))}
                      placeholder="Coordinación de bodas y eventos especiales"
                    />
                  </div>

                  {/* Icono */}
                  <div>
                    <label className="label">Icono</label>
                    <div className="flex flex-wrap gap-2 mt-1">
                      {ICON_OPTIONS.map(ic => {
                        const Icon = ICON_MAP[ic];
                        return (
                          <button
                            key={ic} type="button"
                            onClick={() => setForm(f => ({ ...f, icon: ic }))}
                            className={`p-2 rounded-lg border transition-all ${
                              form.icon === ic
                                ? 'border-rose-400 bg-rose-50 text-rose-600'
                                : 'border-stone-200 bg-white text-stone-500 hover:border-stone-300'
                            }`}
                          >
                            <Icon size={16} />
                          </button>
                        );
                      })}
                    </div>
                  </div>

                  {/* Color */}
                  <div>
                    <label className="label">Color</label>
                    <div className="flex flex-wrap gap-2 mt-1">
                      {COLOR_OPTIONS.map(c => (
                        <button
                          key={c.value} type="button"
                          onClick={() => setForm(f => ({ ...f, color: c.value }))}
                          className={`w-7 h-7 rounded-full transition-all ${c.preview} ${
                            form.color === c.value ? 'ring-2 ring-offset-2 ring-rose-400 scale-110' : 'hover:scale-110'
                          }`}
                          title={c.label}
                        />
                      ))}
                    </div>
                  </div>

                  {/* Preview */}
                  <div>
                    <label className="label">Vista previa</label>
                    <div className={`inline-flex items-center gap-2 px-3 py-2 rounded-xl border text-sm font-medium ${form.color}`}>
                      <PositionIcon icon={form.icon} className="w-4 h-4" />
                      {form.label || 'Nombre del puesto'}
                    </div>
                  </div>
                </div>

                <div className="flex gap-2 pt-2">
                  <button onClick={() => setShowModal(false)} className="btn-secondary flex-1">Cancelar</button>
                  <button
                    onClick={handleSaveForm}
                    disabled={savingForm}
                    className="btn-primary flex-1 flex items-center justify-center gap-2"
                  >
                    {savingForm
                      ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      : <Check size={15} />
                    }
                    {modalMode === 'create' ? 'Crear puesto' : 'Guardar cambios'}
                  </button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </Layout>
  );
}

import { useEffect, useState } from 'react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { Lock } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import PdfDownloadButton  from '../../components/PdfDownloadButton';
import MenusPdfDoc         from '../../components/pdf/MenusPdfDoc';
import AllergensPdfDoc     from '../../components/pdf/AllergensPdfDoc';
import KitchenPdfDoc       from '../../components/pdf/KitchenPdfDoc';

const ALLERGEN_LABELS = { GLUTEN:'Gluten', LACTEOS:'Lacteos', HUEVOS:'Huevos', FRUTOS_SECOS:'Frutos secos', CACAHUETES:'Cacahuetes', SOJA:'Soja', MARISCO:'Marisco', PESCADO:'Pescado', MOSTAZA:'Mostaza', APIO:'Apio', SESAMO:'Sesamo', SULFITOS:'Sulfitos', MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuz' };

export default function KitchenView() {
  const { hasPermission } = useAuth();
  const [events, setEvents] = useState([]);
  const [selected, setSelected] = useState(null);
  const [menus, setMenus] = useState([]);
  const [allergens, setAllergens] = useState([]);

  const canViewMenus    = hasPermission('MENUS_VIEW');
  const canViewAllergens = hasPermission('ALLERGENS_VIEW');

  useEffect(() => {
    api.get('/events/mis-eventos').then(r => {
      const active = r.data.filter(e => !['COMPLETADO','CANCELADO'].includes(e.status));
      setEvents(active);
      if (active.length > 0) selectEvent(active[0].id);
    }).catch(() => toast.error('Error cargando eventos'));
  }, []);

  const selectEvent = async (id) => {
    setSelected(id);
    const [m, a] = await Promise.all([
      canViewMenus    ? api.get(`/events/${id}/menus`).catch(() => ({ data: [] }))    : Promise.resolve({ data: [] }),
      canViewAllergens ? api.get(`/events/${id}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
    ]);
    setMenus(m.data);
    setAllergens(a.data);
  };

  const selectedEvent = events.find(e => e.id === selected);
  const selectedMenu = menus.find(m => m.selected);
  const byTable = allergens.reduce((acc, a) => { const t = a.tableNumber || 'Sin mesa'; (acc[t]=acc[t]||[]).push(a); return acc; }, {});

  if (events.length === 0) return (
    <Layout>
      <div className="card text-center py-20">
        <span className="text-5xl mb-4 block">️</span>
        <h2 className="text-xl font-bold text-stone-800 mb-2">Sin eventos asignados</h2>
        <p className="text-stone-500">Cuando te asignen a un evento, aparecerá aquí.</p>
      </div>
    </Layout>
  );

  return (
    <Layout>
      <div className="space-y-6">
        <div className="flex items-center gap-3">
          <span className="text-3xl">️</span>
          <div className="flex-1">
            <h1 className="text-2xl font-bold text-gray-900">Vista Cocina</h1>
            <p className="text-gray-500 text-sm">Menús y alérgenos por evento</p>
          </div>
          {selectedEvent && (
            <PdfDownloadButton
              permissionCode="MENUS_VIEW"
              label="Descargar cocina PDF"
              variant="primary"
              fileName={`cocina-${(selectedEvent.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
              fetchData={async () => {
                const [m, a, t] = await Promise.all([
                  canViewMenus     ? api.get(`/events/${selected}/menus`).catch(() => ({ data: [] }))     : Promise.resolve({ data: [] }),
                  canViewAllergens ? api.get(`/events/${selected}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
                  api.get(`/events/${selected}/tables`).catch(() => ({ data: [] })),
                ]);
                return { event: selectedEvent, menus: m.data, allergens: a.data, tables: t.data };
              }}
              DocumentComponent={KitchenPdfDoc}
            />
          )}
        </div>

        {/* Selector de evento */}
        <div className="flex gap-2 flex-wrap">
          {events.map(e => (
            <button key={e.id} onClick={() => selectEvent(e.id)}
              className={`px-4 py-2 rounded-xl text-sm font-medium border transition-colors ${selected === e.id ? 'bg-orange-600 text-white border-orange-600' : 'bg-white text-gray-600 border-gray-300'}`}>
              {e.clientName} ({new Date(e.eventDate).toLocaleDateString('es-ES', {day:'2-digit',month:'short'})})
            </button>
          ))}
        </div>

        {selectedEvent && (
          <>
            <div className="card bg-orange-50 border-orange-200">
              <h2 className="text-lg font-bold text-orange-900">{selectedEvent.clientName} · {selectedEvent.typeLabel}</h2>
              <p className="text-orange-700"> {new Date(selectedEvent.eventDate).toLocaleDateString('es-ES',{weekday:'long',year:'numeric',month:'long',day:'numeric'})} ·  {selectedEvent.estimatedGuests} invitados</p>
            </div>

            {/* Menu seleccionado */}
            <div className="card">
              <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold text-gray-800">️ Menú seleccionado</h3>
                <PdfDownloadButton
                  permissionCode="MENUS_VIEW"
                  label="PDF menús"
                  fileName={`menus-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
                    const r = await api.get(`/events/${selected}/menus`);
                    return { event: selectedEvent, menus: r.data };
                  }}
                  DocumentComponent={MenusPdfDoc}
                />
              </div>
              {!canViewMenus ? (
                <div className="text-center py-8">
                  <Lock size={32} className="text-stone-300 mx-auto mb-2" />
                  <p className="text-stone-400 text-sm">Sin permiso para ver menús</p>
                </div>
              ) : selectedMenu ? (
                <div>
                  <h4 className="font-bold text-lg mb-3">{selectedMenu.name}</h4>
                  <dl className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {[['Entrantes',selectedMenu.starters],['Primer plato',selectedMenu.firstCourse],['Segundo plato',selectedMenu.secondCourse],['Postre',selectedMenu.dessert],['Bebidas',selectedMenu.drinks],['Extras',selectedMenu.extras]].filter(([,v])=>v).map(([l,v])=>(
                      <div key={l} className="bg-gray-50 rounded-lg p-3">
                        <dt className="text-xs text-gray-500 font-medium uppercase">{l}</dt>
                        <dd className="text-gray-900 mt-1">{v}</dd>
                      </div>
                    ))}
                  </dl>
                </div>
              ) : <p className="text-amber-600">⚠️ El cliente aún no ha confirmado el menú</p>}
            </div>

            {/* Alergenos por mesa */}
            <div className="card">
              <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold text-gray-800">
                  ⚠️ Alérgenos y dietas especiales {canViewAllergens && `(${allergens.length} personas)`}
                </h3>
                <PdfDownloadButton
                  permissionCode="ALLERGENS_VIEW"
                  label="PDF alérgenos"
                  fileName={`alergenos-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
                    const r = await api.get(`/events/${selected}/allergens`);
                    return { event: selectedEvent, allergens: r.data };
                  }}
                  DocumentComponent={AllergensPdfDoc}
                />
              </div>
              {!canViewAllergens ? (
                <div className="text-center py-8">
                  <Lock size={32} className="text-stone-300 mx-auto mb-2" />
                  <p className="text-stone-400 text-sm">Sin permiso para ver alérgenos</p>
                </div>
              ) : allergens.length === 0 ? (
                <p className="text-gray-500">No hay alérgenos registrados para este evento.</p>
              ) : (
                <div className="space-y-4">
                  {Object.entries(byTable).sort(([a],[b])=>a.localeCompare(b)).map(([table, entries]) => (
                    <div key={table} className="border rounded-xl overflow-hidden">
                      <div className="bg-orange-100 px-4 py-2 font-semibold text-orange-800"> {table}</div>
                      <table className="w-full text-sm">
                        <thead className="bg-gray-50">
                          <tr>
                            <th className="text-left p-3">Invitado</th>
                            <th className="text-left p-3">Alérgenos</th>
                            <th className="text-left p-3">Dieta</th>
                            <th className="text-left p-3">Observaciones</th>
                          </tr>
                        </thead>
                        <tbody>
                          {entries.map(e => (
                            <tr key={e.id} className="border-t">
                              <td className="p-3 font-medium">{e.guestName}</td>
                              <td className="p-3">
                                {e.allergies ? e.allergies.split(',').filter(Boolean).map(a=>(
                                  <span key={a} className="badge bg-amber-100 text-amber-700 mr-1 mb-1">{ALLERGEN_LABELS[a]||a}</span>
                                )) : <span className="text-gray-400">Ninguno</span>}
                              </td>
                              <td className="p-3">{e.diet ? <span className="badge bg-purple-100 text-purple-700">{e.diet}</span> : ''}</td>
                              <td className="p-3 text-gray-500">{e.observations || ''}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </Layout>
  );
}

import { useEffect, useState } from 'react';
import api from '../../api/axios';
import Layout from '../../components/Layout';
import toast from 'react-hot-toast';
import { Lock } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import PdfDownloadButton  from '../../components/PdfDownloadButton';
import MenusPdfDoc         from '../../components/pdf/MenusPdfDoc';
import AllergensPdfDoc     from '../../components/pdf/AllergensPdfDoc';
import KitchenPdfDoc       from '../../components/pdf/KitchenPdfDoc';

const ALLERGEN_LABELS = { GLUTEN:'Gluten', LACTEOS:'Lacteos', HUEVOS:'Huevos', FRUTOS_SECOS:'Frutos secos', CACAHUETES:'Cacahuetes', SOJA:'Soja', MARISCO:'Marisco', PESCADO:'Pescado', MOSTAZA:'Mostaza', APIO:'Apio', SESAMO:'Sesamo', SULFITOS:'Sulfitos', MOLUSCOS:'Moluscos', ALTRAMUZ:'Altramuz' };

export default function KitchenView() {
  const { hasPermission } = useAuth();
  const [events, setEvents] = useState([]);
  const [selected, setSelected] = useState(null);
  const [menus, setMenus] = useState([]);
  const [allergens, setAllergens] = useState([]);

  const canViewMenus    = hasPermission('MENUS_VIEW');
  const canViewAllergens = hasPermission('ALLERGENS_VIEW');

  useEffect(() => {
    api.get('/events/mis-eventos').then(r => {
      const active = r.data.filter(e => !['COMPLETADO','CANCELADO'].includes(e.status));
      setEvents(active);
      if (active.length > 0) selectEvent(active[0].id);
    }).catch(() => toast.error('Error cargando eventos'));
  }, []);

  const selectEvent = async (id) => {
    setSelected(id);
    const [m, a] = await Promise.all([
      canViewMenus    ? api.get(`/events/${id}/menus`).catch(() => ({ data: [] }))    : Promise.resolve({ data: [] }),
      canViewAllergens ? api.get(`/events/${id}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
    ]);
    setMenus(m.data);
    setAllergens(a.data);
  };

  const selectedEvent = events.find(e => e.id === selected);
  const selectedMenu = menus.find(m => m.selected);
  const byTable = allergens.reduce((acc, a) => { const t = a.tableNumber || 'Sin mesa'; (acc[t]=acc[t]||[]).push(a); return acc; }, {});

  if (events.length === 0) return (
    <Layout>
      <div className="card text-center py-20">
        <span className="text-5xl mb-4 block">️</span>
        <h2 className="text-xl font-bold text-stone-800 mb-2">Sin eventos asignados</h2>
        <p className="text-stone-500">Cuando te asignen a un evento, aparecerá aquí.</p>
      </div>
    </Layout>
  );

  return (
    <Layout>
      <div className="space-y-6">
        <div className="flex items-center gap-3">
          <span className="text-3xl">️</span>
          <div className="flex-1">
            <h1 className="text-2xl font-bold text-gray-900">Vista Cocina</h1>
            <p className="text-gray-500 text-sm">Menús y alérgenos por evento</p>
          </div>
          {selectedEvent && (
            <PdfDownloadButton
              permissionCode="PDF_MENUS"
              label="Descargar cocina PDF"
              variant="primary"
              fileName={`cocina-${(selectedEvent.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
              fetchData={async () => {
                const [m, a, t] = await Promise.all([
                  canViewMenus     ? api.get(`/events/${selected}/menus`).catch(() => ({ data: [] }))     : Promise.resolve({ data: [] }),
                  canViewAllergens ? api.get(`/events/${selected}/allergens`).catch(() => ({ data: [] })) : Promise.resolve({ data: [] }),
                  api.get(`/events/${selected}/tables`).catch(() => ({ data: [] })),
                ]);
                return { event: selectedEvent, menus: m.data, allergens: a.data, tables: t.data };
              }}
              DocumentComponent={KitchenPdfDoc}
            />
          )}
        </div>

        {/* Selector de evento */}
        <div className="flex gap-2 flex-wrap">
          {events.map(e => (
            <button key={e.id} onClick={() => selectEvent(e.id)}
              className={`px-4 py-2 rounded-xl text-sm font-medium border transition-colors ${selected === e.id ? 'bg-orange-600 text-white border-orange-600' : 'bg-white text-gray-600 border-gray-300'}`}>
              {e.clientName} ({new Date(e.eventDate).toLocaleDateString('es-ES', {day:'2-digit',month:'short'})})
            </button>
          ))}
        </div>

        {selectedEvent && (
          <>
            <div className="card bg-orange-50 border-orange-200">
