                <PdfDownloadButton
                  permissionCode="PDF_MENUS"
                  label="PDF menús"
                  fileName={`menus-${(selectedEvent?.clientName || 'evento').replace(/\s+/g, '-').toLowerCase()}.pdf`}
                  fetchData={async () => {
